#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To maximize the binary number, we want as many '1's as possible,
    // followed by '0's.
    // Each "one" uses 'o', 'n', 'e'.
    // Each "zero" uses 'z', 'e', 'r', 'o'.

    // Count how many '1's we can form
    int num_ones = count_n; // 'n' is unique to "one" among 'o', 'n', 'e' for "one" and 'z', 'e', 'r', 'o' for "zero"
                            // More precisely, 'n' only appears in "one".
                            // So, the number of 'n's directly tells us the maximum number of "one"s.

    // Count how many '0's we can form
    int num_zeros = count_z; // 'z' is unique to "zero".
                             // So, the number of 'z's directly tells us the maximum number of "zero"s.

    bool first_output = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 1;
        first_output = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 0;
        first_output = false;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k; // k can be up to 10^4, sum of a_i can exceed int
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i or k
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it as many times as possible
            // without exceeding k.
            // The number of times is floor((k - a[i]) / min_val)
            if (min_val > 0) { // Avoid division by zero, though problem constraints say a_i >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

