    std::string b = a;
    std::string a_rev = a;
    std::reverse(a_rev.begin(), a_rev.end());

    // Construct B by concatenating A and the reverse of A.
    // For example, if A = "ab", A_rev = "ba", then B = "abba".
    // This B is always a palindrome.
    // A is a prefix of B, so A is a subsequence of B.
    // The length of B will be 2 * |A|.
