#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required for k torches:
        // k sticks for crafting + k * y sticks for buying k coal
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using trade offer 1.
        // Each trade offer 1 consumes 1 stick and produces x sticks,
        // resulting in a net gain of (x - 1) sticks.
        long long sticks_to_gain = total_sticks_needed - 1;

        // Number of trades of type 1 needed:
        // ceil(sticks_to_gain / (x - 1))
        long long num_stick_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = num_stick_trades + num_coal_trades
        // num_coal_trades is k (one trade for each coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream> // Required for input/output operations (cin, cout)

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is generally good practice in competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n; // Number of ping commands
    std::cin >> n;

    // Variables to store total packets sent and total successful packets for server 'a'
    long long total_sent_a = 0;
    long long total_successful_a = 0;

    // Variables to store total packets sent and total successful packets for server 'b'
    long long total_sent_b = 0;
    long long total_successful_b = 0;

    // Loop through each of the n commands
    for (int i = 0; i < n; ++i) {
        int type; // Type of server (1 for 'a', 2 for 'b')
        int x, y; // x: successful packets, y: lost packets
        std::cin >> type >> x >> y;

        // Each ping command sends 10 packets (x + y = 10)
        if (type == 1) { // Command for server 'a'
            total_sent_a += 10;
            total_successful_a += x;
        } else { // Command for server 'b'
            total_sent_b += 10;
            total_successful_b += x;
        }
    }

    // Determine if server 'a' is "alive"
    // A server is "alive" if at least half of the packets sent reached it successfully.
    // This can be checked by: successful_packets * 2 >= total_packets_sent
    if (total_successful_a * 2 >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Determine if server 'b' is "alive"
    if (total_successful_b * 2 >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only consider numbers up to 2048
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of this power of two to the current sum
        // We can think of this as having 'count' copies of 'val'.
        // Each 'val' contributes 'val' to the total sum that can be potentially merged.
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

