#include <iostream>
#include <algorithm> // For std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // If r is at least twice l, then 2 will always be the most frequent divisor.
        // This is because 2 divides floor(r/2) - ceil(l/2) + 1 numbers.
        // Any other number k > 2 would divide at most floor(r/k) - ceil(l/k) + 1 numbers.
        // If r >= 2*l, then the count for 2 is at least floor(r/2) - l/2 + 1.
        // For any k > 2, the count is at most r/k.
        // If r >= 2*l, then the count for 2 is at least (r/2) - (l/2) + 1.
        // The number of multiples of 2 in [l, r] is approximately (r-l)/2.
        // The number of multiples of 3 in [l, r] is approximately (r-l)/3.
        // The number of multiples of any k > 2 is less than or equal to the number of multiples of 2.
        // Specifically, if r >= 2*l, then 2 is guaranteed to be the answer.
        // Example: l=19, r=29. r < 2*l (29 < 38). Output 2.
        // Example: l=3, r=6. r == 2*l. Output 3.
        // The condition r >= 2*l is a sufficient condition for 2 to be the answer.
        // If r < 2*l, then the range [l, r] is relatively small.
        // In this case, the number of multiples of 2 might not be the maximum.
        // For example, if l=3, r=6. r=6, l=3. r = 2*l.
        // Multiples of 2: {4, 6} (count 2)
        // Multiples of 3: {3, 6} (count 2)
        // Multiples of 4: {4} (count 1)
        // Multiples of 5: {5} (count 1)
        // Multiples of 6: {6} (count 1)
        // In this case, 2 and 3 both have count 2. The problem says print any.
        // So, if r >= 2*l, 2 is a valid answer.
        // If r < 2*l, then the range [l, r] is small enough that 2 might not be the only or best answer.
        // However, the question asks for *any* integer.
        // The number 2 will always be a divisor for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // For any k > 2, the count of its multiples is floor(r/k) - ceil(l/k) + 1.
        // This count is always less than or equal to the count for 2.
        // The only exception is when l is small and r is small, e.g., l=3, r=6.
        // Count for 2: floor(6/2) - ceil(3/2) + 1 = 3 - 2 + 1 = 2.
        // Count for 3: floor(6/3) - ceil(3/3) + 1 = 2 - 1 + 1 = 2.
        // In this case, 2 and 3 are both valid answers.
        // The simplest answer is 2, as it's the smallest prime and thus has the most multiples.
        // The only case where 2 might not be the answer is if l=r, where l itself is the answer.
        // But we handled l=r separately.
        // For any l < r, 2 will always be a valid answer.
        // Consider the number of multiples of x in [l, r]: floor(r/x) - (l+x-1)/x + 1.
        // For x=2, count is floor(r/2) - (l+1)/2 + 1.
        // For x=3, count is floor(r/3) - (l+2)/3 + 1.
        // If r >= 2*l, then the count for 2 is at least (r/2) - (l/2) + 1.
        // Since r >= 2*l, r/2 >= l. So (r/2) - (l/2) >= l/2.
        // The count for 2 is at least l/2 + 1.
        // For any x > 2, the count is at most r/x.
        // If x=3, count is at most r/3.
        // If r >= 2*l, then r/3 >= 2l/3.
        // Is l/2 + 1 always greater than or equal to r/3? Not necessarily.
        // Example: l=10, r=20. r=2l.
        // Count for 2: floor(20/2) - (10+1)/2 + 1 = 10 - 5 + 1 = 6. (10,12,14,16,18,20)
        // Count for 3: floor(20/3) - (10+2)/3 + 1 = 6 - 4 + 1 = 3. (12,15,18)
        // Count for 4: floor(20/4) - (10+3)/4 + 1 = 5 - 3 + 1 = 3. (12,16,20)
        // Count for 5: floor(20/5) - (10+4)/5 + 1 = 4 - 2 + 1 = 3. (10,15,20)
        // In this case, 2 is clearly the winner.

        // The problem is simpler than it seems.
        // The number 2 is the smallest prime.
        // For any range [l, r] where l < r, the number of multiples of 2 will be
        // floor(r/2) - ceil(l/2) + 1.
        // The number of multiples of any other integer k > 2 will be
        // floor(r/k) - ceil(l/k) + 1.
        // Since k > 2, floor(r/k) <= floor(r/2) and ceil(l/k) >= ceil(l/2).
        // Thus, floor(r/k) - ceil(l/k) + 1 <= floor(r/2) - ceil(l/2) + 1.
        // This means the count for 2 is always greater than or equal to the count for any other integer k > 2.
        // Therefore, 2 is always an answer (if l < r).
        // The only edge case is when l=r, where the only divisor (other than 1) is l itself.
        // But this is handled by the `if (l == r)` condition.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is less than n.
    // If all elements in p are n-1, it means the actual maximum value 'n'
    // was not present in any min(p_i, p_j) for i != j.
    // This happens if p_i = n for some i, and all other p_j < n.
    // In this case, max(min(p_i, p_j) for j != i) = max(p_j for j != i) = n-1.
    // For all other p_k < n, max(min(p_k, p_j) for j != k) will also be n-1
    // if p_i=n is one of the p_j's.
    // So, if all p[i] are n-1, it means one of the p[i] must be n.
    bool all_n_minus_1 = true;
    for (int i = 0; i < n; ++i) {
        if (p[i] != n - 1) {
            all_n_minus_1 = false;
            break;
        }
    }

    if (all_n_minus_1) {
        // If all p[i] are n-1, it means one of them should be n.
        // We can pick any one, for example, p[0], and set it to n.
        // The problem guarantees a solution exists, so this is valid.
        p[0] = n;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is 0 or greater, it means the frog is at cell last_r_pos.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos (0-indexed).
                // The distance between them is (i+1) - (last_r_pos + 1) if last_r_pos >= 0,
                // or (i+1) - 0 if last_r_pos == -1 (meaning from cell 0).
                // This simplifies to (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // If last_r_pos is -1, it's (i+1) - 0 = i+1.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1));
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // The last 'R' was at index last_r_pos (0-indexed), which is cell last_r_pos + 1.
        // The target is cell n+1.
        // The distance is (s.length() + 1) - (last_r_pos + 1) = s.length() - last_r_pos.
        // If no 'R' was found, last_r_pos is -1, meaning the jump is from cell 0 to n+1.
        // Distance is (s.length() + 1) - 0 = s.length() + 1.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
