            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i.
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // This is because larger numbers might be needed later for new maximums.
            // However, the problem asks for *any* possible permutation.
            // A simpler strategy: pick the largest available number that is less than q_i.
            // This leaves smaller numbers for later, which might be needed if q_i remains the same for a long time.
            // Let's try to pick the largest available number that is not used and is less than q_i.
            // The numbers available are 1 to n.
            // We need to find an unused number x such that x < q_i.
            // The largest such number would be q_i - 1, then q_i - 2, etc.
            // Let's iterate downwards from q_i - 1.
            int found_val = -1;
            for (int val = q[i] - 1; val >= 1; --val) {
                if (!used_numbers.count(val)) {
                    found_val = val;
                    break;
                }
            }
            if (found_val == -1) {
                possible = false;
                break;
            }
            p[i] = found_val;
            used_numbers.insert(found_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

