int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Create pairs (A_i, original_index_A) for sorting A
    std::vector<std::pair<long long, int>> a_indexed(m);
    for (int i = 0; i < m; ++i) {
        a_indexed[i] = {a[i], i};
    }

    // Create pairs (B_i, original_index_B) for sorting B
    // We don't need original_index_B for B, just the values
    // But we need to sort B to match with sorted A
    std::vector<long long> b_sorted = b;

    // Sort A in descending order
    std::sort(a_indexed.rbegin(), a_indexed.rend());

    // Sort B in ascending order
    std::sort(b_sorted.begin(), b_sorted.end());

    // The resulting array A'
    std::vector<long long> a_prime(m);

    // Fill a_prime based on the optimal pairing
    // The i-th largest A_i (a_indexed[i].first) should be paired with the i-th smallest B_i (b_sorted[i])
    // The value a_indexed[i].first goes into the position originally occupied by a_indexed[i].second
    for (int i = 0; i < m; ++i) {
        a_prime[a_indexed[i].second] = a_indexed[i].first;
    }

    // Output the rearranged array A'
    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

