// Function to check if a subarray is a permutation
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // This case should not be hit for p1 or p2 due to l1, l2 >= 1.
    }
    if (length > arr.size()) { // Should not happen if start_idx, end_idx are valid
        return false;
    }

    std::vector<bool> seen(length + 1, false); // Use 1-based indexing for values
    int max_val = 0;

    for (int i = start_idx; i < end_idx; ++i) {
        int val = arr[i];
        if (val < 1 || val > length || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // Check if all numbers from 1 to length are present
    // This is implicitly checked by `seen[val]` and `val > length` conditions
    // combined with `max_val == length`.
    // If all numbers from 1 to length are present, then max_val must be length.
    // And if max_val is length, and all numbers are distinct and within [1, length],
    // then all numbers from 1 to length must be present.
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> max_prefix(n + 1, 0); // max_prefix[k] stores max value in a[0...k-1]
    std::vector<bool> seen_prefix(n + 1, false); // seen_prefix[val] is true if val is in a[0...k-1]
    bool is_prefix_perm[n + 1]; // is_prefix_perm[k] is true if a[0...k-1] is a permutation of length k
    std::fill(is_prefix_perm, is_prefix_perm + n + 1, false);
    is_prefix_perm[0] = true; // Empty prefix is a permutation of length 0

    int current_max_prefix = 0;
    bool current_prefix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k - 1];
        if (val < 1 || val > k || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == k) {
                is_prefix_perm[k] = true;
            }
        }
    }

    std::vector<int> max_suffix(n + 2, 0); // max_suffix[k] stores max value in a[k-1...n-1]
    std::vector<bool> seen_suffix(n + 1, false); // seen_suffix[val] is true if val is in a[k-1...n-1]
    bool is_suffix_perm[n + 2]; // is_suffix_perm[k] is true if a[k-1...n-1] is a permutation of length n-k+1
    std::fill(is_suffix_perm, is_suffix_perm + n + 2, false);
    is_suffix_perm[n + 1] = true; // Empty suffix is a permutation of length 0

    int current_max_suffix = 0;
    bool current_suffix_valid = true;
    std::fill(seen_suffix.begin(), seen_suffix.end(), false); // Reset for suffix check
    for (int k = n; k >= 1; --k) {
        int val = a[k - 1];
        int len = n - k + 1; // Length of suffix a[k-1...n-1]
        if (val < 1 || val > len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == len) {
                is_suffix_perm[k] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> solutions;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be >= 1 and l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l1 + 1]) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

