int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the number of cells for a staircase with k stairs
            // This is k * (k + 1) / 2
            // However, k here is 2^p - 1.
            // The actual number of stairs is (2^p - 1).
            // The cost for a staircase with (2^p - 1) stairs is (2^p - 1) * (2^p) / 2.
            // Let m = 2^p - 1. Then the cost is m * (m + 1) / 2.
            // The sequence of costs for nice staircases is:
            // p=1, k=1: cost = 1 * 2 / 2 = 1
            // p=2, k=3: cost = 3 * 4 / 2 = 6
            // p=3, k=7: cost = 7 * 8 / 2 = 28
            // p=4, k=15: cost = 15 * 16 / 2 = 120
            // The cost for the next nice staircase is (2*k + 1) * (2*k + 2) / 2.
            // This is (2k+1)(k+1).
            // Let's use the formula for the cost of a nice staircase with (2^p - 1) stairs.
            // Cost_p = (2^p - 1) * (2^p) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of costs is 1, 6, 28, 120, ...
            // The next k is 2*k + 1.
            // The cost for the staircase with k stairs is k * (k + 1) / 2.
            long long cost_for_k_stairs = k * (k + 1) / 2;

            if (current_cost + cost_for_k_stairs <= x) {
                current_cost += cost_for_k_stairs;
                count++;
                // Calculate the next k.
                // k_next = 2 * k_current + 1.
                // Check for overflow before multiplying.
                // k_current can be up to 2^62 - 1 (approx 4.6e18).
                // 2 * k_current + 1 can exceed long long max if k_current > LLONG_MAX / 2.
                // LLONG_MAX is approx 9e18.
                // If k is around 4.5e18, 2*k+1 will overflow.
                // The maximum x is 10^18.
                // The costs are 1, 6, 28, 120, 496, 2016, 8128, 32640, 130816, 523776, 2096128, 8386560, 33550336, 134209536, 536854528, 2147450880, 8589869056, 34359607296, 137438691328, 549755681280, 2199022800896, 8796091877376, 35184366086144, 140737479009280, 562949949532672, 2251799813685248, 9007199194004480, 36028797018963968, 144115187000000000 (approx 1.44e17).
                // The next cost would be for k = 2 * (3.6e17) + 1, which is approx 7.2e17.
                // The sum of costs can reach x = 10^18.
                // The largest k for which cost_for_k_stairs <= 10^18 is when k * (k+1)/2 <= 10^18.
                // k^2/2 approx 10^18 => k^2 approx 2*10^18 => k approx sqrt(2)*10^9 approx 1.4 * 10^9.
                // The k values are 1, 3, 7, ..., 2^p - 1.
                // If k is 1.4 * 10^9, then 2*k+1 is 2.8 * 10^9, which fits in long long.
                // The cost for k=2^p-1 is (2^p-1)*2^p/2.
                // If 2^p-1 is approx 1.4*10^9, then 2^p is approx 1.4*10^9.
                // p is approx log2(1.4*10^9) approx log2(10^9) + log2(1.4) approx 9*log2(10) + 0.5 approx 9*3.32 + 0.5 approx 29.88 + 0.5 approx 30.38.
                // So p can go up to around 30.
                // 2^30 - 1 is approx 10^9.
                // The next k would be 2*(2^30-1)+1 = 2^31-1. This is fine.
                // The cost for 2^31-1 stairs is (2^31-1)*2^31/2. This is approx (2*10^9)*(2*10^9)/2 = 2*10^18.
                // This cost alone might exceed x.
                // So k will not overflow.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int win_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (i > 0 && s[i-1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (win_count == 0) { // All L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k L's to W's. Maximize by making them consecutive.
                // If k=1, score is 1. If k>1, score is 1 + 2*(k-1).
                std::cout << 1 + 2 * (k - 1) << "\n";
            }
            continue;
        }

        // If there are already W's
        // Strategy:
        // 1. Fill gaps between W's.
        // 2. Extend W streaks at ends.
        // 3. If k still remains, convert isolated L's to W's.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Calculate gaps between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        // Fill gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len; // Each L in gap becomes W, connecting two W streaks, adding 2 points per L
                win_count += gap_len;
            } else {
                // Not enough k to fill this gap, use remaining k here
                current_score += 2 * k;
                win_count += k;
                k = 0;
                break;
            }
        }

        // Extend streaks at ends
        if (k > 0) {
            // L's before first W
            int L_before_first_W = first_W;
            int can_add_before = std::min(k, L_before_first_W);
            current_score += 2 * can_add_before;
            win_count += can_add_before;
            k -= can_add_before;
        }

        if (k > 0) {
            // L's after last W
            int L_after_last_W = n - 1 - last_W;
            int can_add_after = std::min(k, L_after_last_W);
            current_score += 2 * can_add_after;
            win_count += can_add_after;
            k -= can_add_after;
        }

        // If k still remains, it means we can convert more L's to W's.
        // These would be isolated L's or L's that extend existing streaks.
        // Since we've already filled gaps and extended ends, any remaining k
        // will convert an L to a W, adding 2 points (if it connects to an existing W)
        // or 1 point (if it's an isolated W).
        // However, the current_score calculation already accounts for the 1 point for the first W.
        // Each additional W (beyond the first one in a streak) adds 2 points.
        // We've already added 1 point for each initial W.
        // When we convert an L to W, it either:
        // 1. Connects two W streaks (handled by gaps, adds 2 per L)
        // 2. Extends a W streak (handled by ends, adds 2 per L)
        // 3. Creates a new W streak (if it's an L far from any W, adds 1 per L)
        // 4. Converts an L adjacent to a W, but not connecting two Ws (adds 2 per L)
        // The logic for `current_score += 2 * k` for remaining `k` is correct because
        // `win_count` is the total number of W's.
