int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause this 'b' to be duplicated
            // and the 'a' to move past it.
            // The number of steps this 'b' contributes is equal to the
            // current count of 'a's to its left.
            total_steps = (total_steps + count_a) % mod;
            // After this 'b' has been processed by all 'a's to its left,
            // it effectively doubles the number of 'a's that will interact
            // with 'b's further to the left.
            // This is because each 'a' that passes this 'b' creates a new 'b'.
            // So, the 'a's that were to the left of this 'b' now effectively
            // represent '2 * count_a' 'a's for 'b's further left.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means it's an 'a' that will
            // eventually need to move past all 'b's to its right.
            // It adds 1 to the count of 'a's that are "active"
            // and will interact with 'b's to their right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

