        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_consecutive_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Count existing correct consecutive pairs (i -> i+1)
        // These are pairs where doll 'j' is nested in 'j+1' AND j+1 is the next number in sequence.
        // Example: 1 -> 2, 2 -> 3, etc.
        // If we have a chain 1 -> 2 -> 3, then (1,2) is a correct pair, (2,3) is a correct pair.
        // The number of such pairs is the length of the longest prefix of 1, 2, 3, ...
        // that is present in the chain.
        // For example, if chain is 1 -> 2 -> 4, then 1->2 is correct.
        // If chain is 3 -> 4 -> 5, then no correct pairs starting from 1.

        // We are looking for the sequence 1, 2, 3, ...
        // If the current chain starts with 1, and continues with 2, 3, ...
        // then these are "correctly" formed parts of the final chain.
        // We count how many such consecutive elements we find starting from 1.

        // If the first element of a chain is 1, then we check for 2, 3, ...
        if (m > 0 && chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_consecutive_pairs++;
                    current_expected++;
                } else {
                    // The sequence 1, 2, 3, ... is broken in this chain
                    break;
                }
            }
        }
    }

    // Total dolls to be moved out of their current nesting (disassembled)
    // Each doll that is not the outermost in its chain needs to be taken out.
    // For a chain of length m, there are m-1 dolls nested inside others.
    // So, sum of (m_i - 1) over all chains.
    // This is equivalent to (sum of m_i) - k = n - k.
    // These are the operations to "free" all dolls.
    // However, we don't need to free dolls that are part of the 1->2->...->X sequence.
    // The `correct_consecutive_pairs` variable counts how many dolls are part of the
    // 1->2->...->X sequence.
    // For example, if 1->2->3 is a correct sequence, then 1 is in 2, 2 is in 3.
    // This means 2 dolls (1 and 2) are correctly nested.
    // These `correct_consecutive_pairs` dolls do not need to be disassembled from their
    // correct nesting.
    // So, the number of dolls that need to be disassembled from *incorrect* nestings
    // or from *correct* nestings that are not part of the 1->2->...->X sequence.
    // Total dolls that are nested in *some* other doll is n - k (n total dolls, k outermost dolls).
    // Out of these n-k nested dolls, `correct_consecutive_pairs - 1` are correctly nested
    // (e.g., if 1->2->3, then 1 is in 2, 2 is in 3. `correct_consecutive_pairs` is 3.
    // The number of correct nestings is 2. So `correct_consecutive_pairs - 1`).
    // So, (n - k) - (correct_consecutive_pairs - 1) dolls need to be disassembled.
    // This simplifies to n - k - correct_consecutive_pairs + 1.
    // Each disassembly costs 1 second.

    // Number of dolls that are NOT part of the 1->2->...->X sequence and are nested.
    // These need to be taken out.
    // Total dolls that are nested in some other doll: n - k.
    // Number of dolls that are correctly nested in the 1->2->...->X sequence: correct_consecutive_pairs - 1.
    // (e.g., if 1->2->3, then 1 is in 2, 2 is in 3. `correct_consecutive_pairs` is 3.
    // The number of correct nestings is 2. So `correct_consecutive_pairs - 1`).
    // The number of dolls that need to be taken out is (n - k) - (correct_consecutive_pairs - 1).
    // This is `n - k - correct_consecutive_pairs + 1`.
    // Each such operation costs 1 second.
    total_operations += (n - k) - (correct_consecutive_pairs - 1);

    // Number of dolls that need to be put into other dolls to form the final chain.
    // The final chain has n-1 nestings (1 in 2, 2 in 3, ..., n-1 in n).
    // We already have `correct_consecutive_pairs - 1` of these nestings.
    // So, we need to perform (n - 1) - (correct_consecutive_pairs - 1) new nestings.
    // This simplifies to n - correct_consecutive_pairs.
    // Each such operation costs 1 second.
    total_operations += (n - 1) - (correct_consecutive_pairs - 1);

    std::cout << total_operations << std::endl;

    return 0;
}

