}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string coloring(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');
        bool possible_split = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) {
                current_coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > split_digit) {
                current_coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == split_digit
                // Try to assign to color 1 first, then color 2
                // This greedy approach works because we want to maximize digits in S1
                // and then in S2, while maintaining non-decreasing property.
                // If we assign to color 1, it must be >= last S1 digit.
                // If we assign to color 2, it must be >= last S2 digit.
                // The critical point is the transition from S1 to S2.
                // All digits in S1 must be <= all digits in S2.
                // If d[i] == split_digit, it can go to S1 if S1 is empty or d[i] >= last S1.
                // It can go to S2 if S2 is empty or d[i] >= last S2.
                // To ensure S1_max <= S2_min, we assign all split_digit values to S1
                // until we encounter a digit > split_digit. After that, all split_digit
                // values must go to S2.

                // This logic is simplified:
                // All digits < split_digit go to S1.
                // All digits > split_digit go to S2.
                // For digits == split_digit:
                // The first block of split_digit values that appear *before* any digit > split_digit
                // can go to S1.
                // The second block of split_digit values that appear *after* any digit > split_digit
                // must go to S2.
                // This is equivalent to finding the first occurrence of a digit > split_digit.
                // All split_digits before that go to S1. All split_digits after that go to S2.
                // This ensures S1_max <= split_digit <= S2_min.
                // The `first_gt_split_digit_idx` variable handles this.
            }
        }

        int first_gt_split_digit_idx = -1;
        for (int i = 0; i < n; ++i) {
            if (d[i] > split_digit) {
                first_gt_split_digit_idx = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            if (d[i] == split_digit) {
                if (first_gt_split_digit_idx == -1 || i < first_gt_split_digit_idx) {
                    current_coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                } else {
                    current_coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // Check if max(S1) <= min(S2)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_split = false;
            }
        }

        if (possible_split) {
            coloring = current_coloring;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << coloring << "\n";
    } else {
        std::cout << "-\n";
    }
}

