    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, then b-1=0, sum is 0.
    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k = sum_{k=1 to a} (k * b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a

    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // This is sum_{k=1 to a} k

    long long term1 = (b % MOD * sum_k_val) % MOD; // b * sum_{k=1 to a} k
    long long term2 = a % MOD;                     // sum_{k=1 to a} 1

    long long sum_k_term = (term1 + term2) % MOD;

    // Total sum = sum_r_term * sum_k_term
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

