        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = 1;

    for (int i = 0; i < n; i += k) {
        int block_start_val = current_val;
        int block_end_val = std::min(n, current_val + k - 1);

        for (int j = 0; j <= block_end_val - block_start_val; ++j) {
            p[i + j] = block_end_val - j;
        }
        current_val += k;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two "virtual" numbers: 0 and 1023 (all bits set)
    // We track how these two numbers transform after all operations.
    // This allows us to determine the final state of each bit.
    int val0 = 0;    // What 0 becomes after all operations
    int val1023 = 1023; // What 1023 becomes after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position (0 to 9), we know its final state
    // if the input bit was 0 (from val0) or 1 (from val1023).
    // Let's reconstruct the equivalent operations.

    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_result
    // Or, more generally, a sequence of at most 5 operations.
    // A common strategy is to find a sequence of one AND, one OR, one XOR.
    // (x & AND_CONST | OR_CONST) ^ XOR_CONST

    // Let's determine the AND_CONST, OR_CONST, XOR_CONST bit by bit.
    int final_and_const = 1023; // Represents 'A'
    int final_or_const = 0;    // Represents 'B'
    int final_xor_const = 0;   // Represents 'C'

    for (int j = 0; j < 10; ++j) { // Iterate through bits 0 to 9
        int bit_mask = (1 << j);

        int bit_val0 = (val0 & bit_mask) >> j;      // Final state of bit j if input bit j was 0
        int bit_val1023 = (val1023 & bit_mask) >> j; // Final state of bit j if input bit j was 1

        // Case 1: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 0
        // This means the bit is always 0, regardless of input.
        // To achieve this with (x & A | B) ^ C:
        // (0 & A_j | B_j) ^ C_j = 0
        // (1 & A_j | B_j) ^ C_j = 0
        // This implies A_j must be 0, B_j must be 0, C_j must be 0.
        // Or A_j=1, B_j=0, C_j=0.
        // The simplest way to force a bit to 0 is to AND with 0.
        // So, A_j = 0.
        if (bit_val0 == 0 && bit_val1023 == 0) {
            final_and_const &= ~bit_mask; // Set A_j to 0
            // B_j and C_j remain 0 for this bit
        }
        // Case 2: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 1
        // This means the bit is always 1, regardless of input.
        // The simplest way to force a bit to 1 is to OR with 1.
        // So, B_j = 1.
        if (bit_val0 == 1 && bit_val1023 == 1) {
            final_or_const |= bit_mask; // Set B_j to 1
            // A_j remains 1, C_j remains 0 for this bit
        }
        // Case 3: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 1
        // This means the bit passes through unchanged (identity).
        // (x & A_j | B_j) ^ C_j = x_j
        // If A_j=1, B_j=0, C_j=0, then (x_j & 1 | 0) ^ 0 = x_j. This works.
        // So, A_j = 1 (default), B_j = 0 (default), C_j = 0 (default).
        if (bit_val0 == 0 && bit_val1023 == 1) {
            // No change needed for A_j, B_j, C_j for this bit.
            // final_and_const has 1 at this bit by default.
            // final_or_const has 0 at this bit by default.
            // final_xor_const has 0 at this bit by default.
        }
        // Case 4: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 0
        // This means the bit is flipped (NOT operation).
        // (x & A_j | B_j) ^ C_j = ~x_j
        // If A_j=1, B_j=0, C_j=1, then (x_j & 1 | 0) ^ 1 = x_j ^ 1 = ~x_j. This works.
        // So, C_j = 1.
        if (bit_val0 == 1 && bit_val1023 == 0) {
            final_xor_const |= bit_mask; // Set C_j to 1
            // A_j remains 1, B_j remains 0 for this bit
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit of A is 0, we need an AND operation
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit of B is 1, we need an OR operation
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit of C is 1, we need an XOR operation
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operations 2 and 3: Do nothing (add 0)
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make all elements except the last one divisible by n.
        // For each a[i] (0 <= i < n-1), we want a[i] + b[i] to be a multiple of n.
        // b[i] must be a multiple of n.
        // Let b[i] = k * n. Then a[i] + k * n = 0 (mod n).
        // So a[i] = 0 (mod n).
        // We need to add (n - (a[i] % n)) % n to a[i] to make it a multiple of n.
        // Let x = a[i] % n. If x is negative, x = (x % n + n) % n.
        // The amount to add is (n - (a[i] % n + n) % n) % n.
        // Let's simplify: target_remainder = 0.
        // current_remainder = (a[i] % n + n) % n.
        // diff = (target_remainder - current_remainder + n) % n.
        // This diff is the amount we need to add to a[i] to make it a multiple of n.
        // However, we need to add a multiple of n.
        // The value we add is `diff`. This `diff` is in `[0, n-1]`.
        // We need to add `diff` such that `diff` is a multiple of `n`.
        // This is only possible if `diff` is 0.
        // This approach is wrong.

        // Correct approach for Operation 1:
        // Select segment [1, n-1]. Length is n-1.
        // For each a[i] in this segment, we want to add b[i] such that a[i] + b[i] is a multiple of n.
        // b[i] must be a multiple of (n-1).
        // This is tricky. Let's use the standard trick.

        // Operation 1: Make a[0]...a[n-2] divisible by n.
        // Select segment [1, n-1]. Length is n-1.
        // For each a[i] (0 <= i < n-1), we want to add a value `x` such that `a[i] + x` is a multiple of `n`.
        // And `x` must be a multiple of `n-1`.
        // This is equivalent to `a[i] + x = 0 (mod n)` and `x = 0 (mod n-1)`.
        // So `x = -a[i] (mod n)`.
        // Let `rem = (a[i] % n + n) % n`. We need `x = -rem (mod n)`.
        // We also need `x = k * (n-1)` for some integer `k`.
        // So `k * (n-1) = -rem (mod n)`.
        // `k * (-1) = -rem (mod n)`.
        // `-k = -rem (mod n)`.
        // `k = rem (mod n)`.
        // So `k` can be `rem`.
        // Then `x = rem * (n-1)`.
        // This `x` is a multiple of `n-1`.
        // And `a[i] + x = a[i] + rem * (n-1) = a[i] + rem * n - rem`.
        // `a[i] + x = a[i] - rem (mod n)`.
        // Since `rem = a[i] % n`, `a[i] - rem` is a multiple of `n`.
        // So this works!

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = (a[i] % n + n) % n;
            long long val_to_add = rem * (n - 1);
            std::cout << val_to_add << (i == n - 2 ? "" : " ");
            a[i] += val_to_add;
        }
        std::cout << "\n";

        // After Operation 1, a[0]...a[n-2] are all multiples of n.
        // a[n-1] is unchanged.

        // Operation 2: Make a[n-1] divisible by n.
        // Select segment [n, n]. Length is 1.
        // We want to add `x` to `a[n-1]` such that `a[n-1] + x` is a multiple of `n`.
        // `x` must be a multiple of 1.
        // Let `rem = (a[n-1] % n + n) % n`.
        // We need to add `(n - rem) % n` to make it a multiple of `n`.
        // Or simply, we need to add `k * n` such that `a[n-1] + k * n = 0 (mod n)`.
        // We can add `(n - rem) % n * n` to `a[n-1]`.
        // No, this is wrong. We need to add `x` such that `a[n-1] + x` is a multiple of `n`.
        // And `x` must be a multiple of `len=1`.
        // We can add `(n - (a[n-1] % n + n) % n) % n * n` to `a[n-1]`.
        // This is not right. We need to add `x` such that `a[n-1] + x` is a multiple of `n`.
        // And `x` must be a multiple of `len=1`.
        // The simplest `x` is `(n - (a[n-1] % n + n) % n) % n`.
        // Let `rem = (a[n-1] % n + n) % n`.
        // We want to add `x` such that `a[n-1] + x = 0 (mod n)`.
        // So `x = -a[n-1] (mod n)`.
        // We can choose `x = -a[n-1]`. This is a multiple of 1.
        // But we want `a[n-1]` to become a multiple of `n`.
        // Let `val_to_add = (n - (a[n-1] % n + n) % n) % n`.
        // This `val_to_add` is in `[0, n-1]`.
        // `a[n-1]` becomes `a[n-1] + val_to_add`. This is a multiple of `n`.
        // This `val_to_add` is a multiple of 1. So this works.

        std::cout << n << " " << n << "\n";
        long long rem_n_minus_1 = (a[n - 1] % n + n) % n;
        long long val_to_add_n_minus_1 = (n - rem_n_minus_1) % n;
        std::cout << val_to_add_n_minus_1 << "\n";
        a[n - 1] += val_to_add_n_minus_1;

        // After Operation 2, all elements a[0]...a[n-1] are multiples of n.

        // Operation 3: Make all elements zero.
        // Select segment [1, n]. Length is n.
        // For each a[i], we want to add `x` such that `a[i] + x = 0`.
        // `x` must be a multiple of `n`.
        // Since all `a[i]` are already multiples of `n`, we can choose `x = -a[i]`.
        // This `x` is a multiple of `n`.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the right side (from n to 2n-1)
    // Suffix sums for the right side, but calculated as prefix sums from n to 2n-1
    // right_sums[k] = sum of a[n]...a[n+k-1]
    // This means right_sums[0] = 0 (no jars removed from right)
    // right_sums[1] = a[n] (jar n+1 in 1-indexed)
    // right_sums[k] = sum of a[n]...a[n+k-1]
    std::vector<int> right_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_sums[i + 1] = right_sums[i] + a[n + i];
    }

    // Store the first occurrence of each sum value for the right side
    // map: sum_value -> number of jars removed from right (k)
    std::map<int, int> right_sum_to_k;
    for (int k = 0; k <= n; ++k) {
        if (right_sum_to_k.find(right_sums[k]) == right_sum_to_k.end()) {
            right_sum_to_k[right_sums[k]] = k;
        }
    }

    // Calculate prefix sums for the left side (from n-1 down to 0)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    // This means left_sums[0] = 0 (no jars removed from left)
    // left_sums[1] = a[n-1] (jar n in 1-indexed)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    std::vector<int> left_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_sums[i + 1] = left_sums[i] + a[n - 1 - i];
    }

    int min_removed = 2 * n; // Initialize with maximum possible jars removed

    // Iterate through all possible numbers of jars removed from the left (j)
    for (int j = 0; j <= n; ++j) {
        int current_left_sum = left_sums[j];
        // We need the remaining jars to have a sum of -current_left_sum
        // This means the sum of jars from the right side (right_sums[k]) should be -current_left_sum
        int target_right_sum = -current_left_sum;

        if (right_sum_to_k.count(target_right_sum)) {
            int k = right_sum_to_k[target_right_sum];
            min_removed = std::min(min_removed, j + k);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        // We have n - m zeros.
        // We want to distribute these zeros into m + 1 blocks (separated by 1s, and before first 1, after last 1).
        // To minimize the number of all-zero substrings, we want to make these blocks of zeros as equal in size as possible.
        // Let k be the number of zeros.
        long long k = n - m;

        // Number of blocks of zeros is m + 1.
        // If m = 0, k = n, 1 block of n zeros.
        // If m > 0, we have m ones. These m ones can separate the zeros into at most m+1 blocks.
        // For example, 10101 has m=3 ones, k=2 zeros. Blocks are 0, 0.
        // 01010 has m=2 ones, k=3 zeros. Blocks are 0, 0, 0.
        // The optimal strategy is to distribute the k zeros as evenly as possible among m+1 potential slots.
        // However, the problem is about minimizing all-zero substrings.
        // The '1's act as separators. If we have 'm' ones, they divide the string into 'm+1' potential segments for '0's.
        // For example, _1_1_1_ (4 segments for 0s if m=3).
        // To minimize the number of all-zero substrings, we want to make the blocks of zeros as small as possible.
        // This means we want to put the '1's such that they break up long sequences of '0's.
        // The most effective way to do this is to place '1's such that they are surrounded by '0's, or at the ends.
        // The number of '1's is 'm'. The number of '0's is 'n - m'.
        // Consider the 'm' ones. They divide the string into 'm+1' possible segments where '0's can be placed.
        // For example, if s = "0010100", n=7, m=2. Zeros = 5.
        // The '1's are at indices 2 and 4 (0-indexed).
        // The blocks of zeros are: 00 (length 2), 0 (length 1), 00 (length 2).
        // Total zeros = 2+1+2 = 5.
        // Number of blocks of zeros is m+1.
        // We have k = n - m zeros to distribute into m+1 blocks.
        // Let q = k / (m + 1) be the base size of each block.
        // Let r = k % (m + 1) be the number of blocks that get an extra zero.
        // So, r blocks will have size q + 1.
        // And (m + 1 - r) blocks will have size q.

        long long num_zero_blocks = m + 1;
        long long q = k / num_zero_blocks; // base length of zero blocks
        long long r = k % num_zero_blocks; // number of blocks with length q+1

        long long sum_all_zero_substrings = 0;
        // r blocks of length q+1
        sum_all_zero_substrings += r * (q + 1) * (q + 2) / 2;
        // (m+1-r) blocks of length q
        sum_all_zero_substrings += (num_zero_blocks - r) * q * (q + 1) / 2;

        long long max_f_s = total_substrings - sum_all_zero_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n <= abs_m for simpler logic
        if (abs_n > abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Minimum moves required is abs_m (the larger coordinate)
        // If k is less than abs_m, it's impossible.
        if (k < abs_m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the number of diagonal moves needed to cover the smaller coordinate
        // and an equal amount of the larger coordinate.
        long long diagonal_moves_to_match = abs_n;

        // After these diagonal_moves_to_match, we are at (abs_n, abs_n) or (abs_n, -abs_n) etc.
        // The remaining distance in the larger coordinate is abs_m - abs_n.
        // These remaining abs_m - abs_n units must be covered by straight moves.
        long long straight_moves_for_diff = abs_m - abs_n;

        // Total moves used so far:
        // diagonal_moves_to_match + straight_moves_for_diff
        long long moves_used = diagonal_moves_to_match + straight_moves_for_diff;

        // Remaining moves: k - moves_used
        long long remaining_k = k - moves_used;

        // If remaining_k is odd, we need to make an odd number of "wasted" moves.
        // Each wasted move (e.g., (0,0) -> (1,0) -> (0,0)) uses 2 moves and changes parity.
        // If we have an odd number of remaining moves, we can't end up at (N,M)
        // because each move changes the parity of (x+y) by 1.
        // (0,0) has x+y=0 (even). (N,M) has x+y = N+M.
        // If k is even, N+M must be even. If k is odd, N+M must be odd.
        // This is equivalent to (k % 2) == ((abs_n + abs_m) % 2).
        // Or, more simply, (k - (abs_n + abs_m)) % 2 == 0.
        // This is equivalent to (remaining_k - (abs_n + abs_m - moves_used)) % 2 == 0.
        // Since moves_used = abs_n + (abs_m - abs_n) = abs_m,
        // we need (k - abs_m) % 2 == 0.
        // If (k - abs_m) is odd, it's impossible to reach (N,M) in k moves.
        // This is because each move changes the parity of (x+y) by 1.
        // Starting at (0,0) (sum=0, even), after k moves, the sum of coordinates (x+y) will have the same parity as k.
        // So, (N+M) must have the same parity as k.
        // If (abs_n + abs_m) % 2 != k % 2, it's impossible.
        // This is equivalent to (k - abs_m) % 2 != 0 if abs_n and abs_m have the same parity.
        // Or (k - abs_m) % 2 != 0 if abs_n and abs_m have different parity.
        // Let's check (k - abs_m) % 2.
        // If (k - abs_m) is odd, we cannot reach the target.
        // Example: (2,2), k=3. abs_m=2. k-abs_m = 1 (odd). Output 1.
        // My parity check: (abs_n+abs_m)%2 = (2+2)%2 = 0. k%2 = 3%2 = 1. 0 != 1. So impossible.
        // But example output is 1. What's wrong?
        // The parity check (x+y)%2 == k%2 is for Manhattan distance moves (only straight moves).
        // For 8-directional moves, the parity of (x+y) can change by 0 or 2 for diagonal moves,
        // and by 1 for straight moves.
        // (x,y) -> (x+dx, y+dy). (x+dx+y+dy) - (x+y) = dx+dy.
        // For diagonal: dx, dy are +/-1. dx+dy can be 0, +/-2. So parity of (x+y) doesn't change.
        // For straight: one of dx, dy is 0, other is +/-1. dx+dy can be +/-1. So parity of (x+y) changes.
        // This means the parity of (x+y) changes if and only if a straight move is made.
        // Let `s` be the number of straight moves.
        // Then (abs_n + abs_m) % 2 must be equal to `s % 2`.
        // We have `k = d + s`.
        // We want to maximize `d`. This means minimizing `s`.
        // Minimum `s` is `abs_m - abs_n`.
        // So, if (abs_n + abs_m) % 2 != (abs_m - abs_n) % 2, it's impossible.
        // (abs_n + abs_m) % 2 == (abs_m - abs_n) % 2 simplifies to (2*abs_n) % 2 == 0, which is always true.
        // This means the parity of (abs_n + abs_m) is always the same as the parity of (abs_m - abs_n).
        // So, the minimum number of straight moves `abs_m - abs_n` always satisfies the parity condition for (abs_n + abs_m).
        // The issue is with `k`.
        // If `k - moves_used` is odd, we have an odd number of "extra" moves.
        // Each extra move must be paired up to return to the same parity.
        // E.g., (0,0) -> (1,0) -> (0,0) uses 2 moves, 0 net displacement, 2 straight moves.
        // (0,0) -> (1,1) -> (0,0) uses 2 moves, 0 net displacement, 2 diagonal moves.
        // (0,0) -> (1,0) -> (1,1) -> (0,1) -> (0,0) uses 4 moves, 0 net displacement.
        // The key is that each pair of moves (e.g., move and then move back) uses 2 moves.
        // If `k - moves_used` is odd, we cannot make an odd number of "extra" moves and end up at the target.
        // This is because each "extra" move must be cancelled out by another move, effectively using 2 moves.
        // So, `remaining_k` must be even.
        // If `remaining_k` is odd, we need to adjust.
        // We can convert a diagonal move into a straight move and a "wasted" move.
        // E.g., (0,0) -> (1,1) (diagonal)
        // Instead: (0,0) -> (1,0) -> (1,1) -> (0,1) -> (0,0)
        // This is not right.
