// The problem asks for the final y.
// The path taken depends only on x and the step type.
// We can memoize the (delta_x, delta_y) for reaching a terminal state from (x, step_type).

// Let's define a structure to store results for memoization.
struct Result {
    long long delta_x; // Change in x from this state to termination
    long long delta_y; // Change in y from this state to termination
    bool terminates;   // Does it terminate?
};

// Memoization table: memo[x][step_type]
// step_type 0: we are about to execute step 2 from x
// step_type 1: we are about to execute step 3 from x
std::vector<std::vector<Result>> memo;
std::vector<long long> a_values; // a_1, a_2, ..., a_n
int N_val; // Global N for convenience

// Function to solve for a given starting x and step type
// current_x: the current value of x
// step_type: 0 for step 2, 1 for step 3
// This function returns the (delta_x, delta_y, terminates) from this state.
Result solve(long long current_x, int step_type) {
    // Check termination condition
    if (current_x <= 0 || current_x > N_val) {
        return {0, 0, true}; // Already terminated, no further change
    }

    // Check memoization table
    if (memo[current_x][step_type].terminates != false || memo[current_x][step_type].delta_x != 0 || memo[current_x][step_type].delta_y != 0) {
        // If it's already computed, return it.
        // We need a way to distinguish "not computed" from "terminates immediately with 0,0"
        // A common way is to use a special value like -1 for delta_x/delta_y or a boolean flag.
        // Here, `terminates` being true means it's computed.
        // If `terminates` is false, it means it's an infinite loop or not yet computed.
        // Let's use a `visited` flag or initialize with a sentinel.
        // Initialize with {0, 0, false} and mark `terminates` as true only if it actually terminates.
        // If `terminates` is false, it means it's either an infinite loop or not computed.
        // Let's use a `visited` flag.
        if (memo[current_x][step_type].terminates) { // If it's marked as terminating, it's computed.
            return memo[current_x][step_type];
        }
        // If it's not terminating, but we are currently visiting it, it means infinite loop.
        // This check is crucial for detecting cycles.
        if (memo[current_x][step_type].delta_x == -1 && memo[current_x][step_type].delta_y == -1) { // Sentinel for "currently visiting"
            return {0, 0, false}; // Infinite loop detected
        }
    }

    // Mark as currently visiting to detect cycles
    memo[current_x][step_type] = {-1, -1, false}; // Sentinel for "currently visiting"

    long long val_ax = a_values[current_x];
    Result next_res;

    if (step_type == 0) { // About to execute Step 2
        // x = x + val_ax, y = y + val_ax
        // Then immediately execute Step 3
        next_res = solve(current_x + val_ax, 1); // Next state is (x + val_ax, Step 3)
        if (!next_res.terminates) { // If the subsequent path doesn't terminate
            memo[current_x][step_type] = {0, 0, false}; // This path also doesn't terminate
            return {0, 0, false};
        }
        // If it terminates, accumulate changes
        memo[current_x][step_type] = {val_ax + next_res.delta_x, val_ax + next_res.delta_y, true};
    } else { // step_type == 1, About to execute Step 3
        // x = x - val_ax, y = y + val_ax
        // Then immediately execute Step 2
        next_res = solve(current_x - val_ax, 0); // Next state is (x - val_ax, Step 2)
        if (!next_res.terminates) { // If the subsequent path doesn't terminate
            memo[current_x][step_type] = {0, 0, false}; // This path also doesn't terminate
            return {0, 0, false};
        }
        // If it terminates, accumulate changes
        memo[current_x][step_type] = {-val_ax + next_res.delta_x, val_ax + next_res.delta_y, true};
    }

    return memo[current_x][step_type];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_val = n;

    a_values.resize(n + 1); // a_values[0] unused, a_values[1] will be set for each run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize memoization table.
    // Size N+1 for x (1 to N), 2 for step_type (0 or 1).
    // Initialize with a state that indicates "not computed".
    // Using {0, 0, false} as initial state for "not computed" is problematic if a path
    // actually terminates with 0,0.
    // A better sentinel for "not computed" is needed.
    // Let's use a boolean `computed` flag or initialize with a specific value like `delta_x = -2`.
    // Or, simply clear the `terminates` flag and use `delta_x = -1` for "visiting".
    // Let's use `terminates = false` and `delta_x = 0, delta_y = 0` for "not computed".
    // And `delta_x = -1, delta_y = -1` for "currently visiting".
    // And `terminates = true` for "computed and terminates".

    for (int i = 1; i < n; ++i) {
        a_values[1] = i; // Set a_1 for the current run

        // Clear memoization table for each new run of a_1.
        // This is crucial because a_1 changes.
        // The size of memo is (N+1) * 2.
        memo.assign(n + 1, std::vector<Result>(2, {0, 0, false}));

        // Initial state: x=1, y=0. The first operation is Step 2.
        Result final_res = solve(1, 0);

        if (final_res.terminates) {
            // The initial y is 0. The total y accumulated is final_res.delta_y.
            std::cout << final_res.delta_y << "\n";
        } else {
            std::cout << -1 << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // b[i] stores the maximum possible initial value for a[i]
    // based on type 2 operations.
    // Initially, assume a[i] can be very large.
    std::vector<long long> b(n, 2000000000LL); // Max initial value 10^9 + max total d (5000 * 10^4 = 5*10^7)

    // Iterate operations in reverse to determine b[i]
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If we add d to a[j] in the future, then the current b[j]
            // must be reduced by d to maintain the same relative maximum.
            // This is because b[j] represents a_0[j] + sum_of_future_d.
            // If we are at operation i, and it's a type 1 op (l, r, d),
            // then for any j in [l, r], a_0[j] + sum_of_d_after_i_plus_d_at_i
            // must be <= m_k for some k.
            // So, a_0[j] + sum_of_d_after_i <= m_k - d_at_i.
            // This means the upper bound for a_0[j] + sum_of_d_after_i
            // is effectively reduced by d_at_i.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // For a type 2 operation (l, r, m_i), the maximum of a_0[j] + sum_of_d_after_i
            // for j in [l, r] must be m_i.
            // This means that for all j in [l, r], a_0[j] + sum_of_d_after_i <= m_i.
            // So, we update b[j] = min(b[j], m_i).
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // Now, b[i] contains the maximum possible initial value for a[i]
    // that satisfies all type 2 constraints.
    // Let's call this candidate initial array `a_initial`.
    std::vector<long long> a_initial = b;

    // Verify the solution by simulating all operations
    // and checking if type 2 constraints are met.
    std::vector<long long> current_a = a_initial;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v; // Use long long for v, d, p to avoid overflow during calculations
    long long d;
    long long p;
    bool present;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].present = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].present) {
            continue; // This child has already run away
        }

        // Child i goes to the doctor
        cured_children_ids.push_back(children[i].id);
        children[i].present = false; // Child i is now cured and out of the line

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d values from children who run away

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].present) {
                continue; // This child has already run away
            }

            // Apply effects from the child in the doctor's office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--; // v_i, v_i-1, v_i-2, ...
            }

            // Apply effects from children who ran away earlier in this round
            children[j].p -= total_d_effect;

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].present = false;
                total_d_effect += children[j].d; // Add their d value to the total effect for subsequent children
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f values are of the form a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-2].value + a[n-1].value + h.
    // This happens if a[0] and a[1] are in the same group, and a[n-2] and a[n-1] are in different groups.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in the same group.
    // Or if a[0] and a[1] are in different groups, and a[n-2] and a[n-1] are in different groups.
    // The minimum f value will be min(a[0].value + a[1].value, a[0].value + a[1].value + h).
    // The maximum f value will be max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h).
    //
    // The critical observation is that if we have two non-empty subsequences,
    // then there must be at least one pair (a_i, a_j) in the same subsequence,
    // and at least one pair (a_k, a_l) in different subsequences.
    //
    // So, min_f will be at most a[0].value + a[1].value.
    // And max_f will be at least a[n-2].value + a[n-1].value + h.
    //
    // However, we can try to make the minimum f value as large as possible,
    // and the maximum f value as small as possible.
    //
    // Consider a partition where a[0] is in group 1, and all other elements are in group 2.
    // min_f:
    //   - a[0].value + a[1].value + h (a[0] in group 1, a[1] in group 2)
    //   - a[1].value + a[2].value (a[1], a[2] in group 2)
    //   The minimum of these two is a[1].value + a[2].value.
    // max_f:
    //   - a[n-2].value + a[n-1].value (a[n-2], a[n-1] in group 2)
    //   - a[0].value + a[n-1].value + h (a[0] in group 1, a[n-1] in group 2)
    //   The maximum of these two is a[0].value + a[n-1].value + h.
    //
    // Goodness = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Let's simplify.
    // The smallest possible sum is `a[0].value + a[1].value`.
    // The largest possible sum is `a[n-1].value + a[n-2].value`.
    //
    // If we put `a[0]` in group 1 and all others in group 2:
    // Pairs in same group: `(a[i], a[j])` for `i,j >= 1`. Smallest is `a[1].value + a[2].value`. Largest is `a[n-2].value + a[n-1].value`.
    // Pairs in different groups: `(a[0], a[j])` for `j >= 1`. Smallest is `a[0].value + a[1].value + h`. Largest is `a[0].value + a[n-1].value + h`.
    //
    // So, for this partition:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // Goodness = max_f - min_f;
    //
    // This is the goodness for the partition where a[0] is in group 1, and all others are in group 2.
    // Let's call this goodness2.
    long long min_f2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    long long max_f2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
    long long goodness2 = max_f2 - min_f2;

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        std::vector<int> result_partition(n);
        for (int i = 0; i < n; ++i) {
            result_partition[a[i].original_index] = 1;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        std::vector<int> result_partition(n);
        result_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[a[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

