// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1: One cut, two pieces.
    // Try all possible single cuts.
    // A cut at index `i` splits s into s[0...i-1] and s[i...n-1].
    // The pieces are P1 = s.substr(0, i) and P2 = s.substr(i).
    // We can form P1+P2 (original s) or P2+P1.
    // We need P2+P1 to be a palindrome and P2+P1 != s.
    for (int i = 1; i < n; ++i) { // i is the length of the first piece
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string new_s = p2 + p1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // This is always possible unless all characters in s are the same.
    // If s consists of all identical characters (e.g., "aaaa"),
    // then any reordering of its substrings will result in the same string,
    // and it will always be a palindrome.
    // Example: "aaaa" -> "a|a|aa" -> "aa|a|a" = "aaaa".
    // In this case, it's impossible to form a different palindrome.

    // Check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, it's always possible with k=2.
        // Consider the string s. Since it's a palindrome and not all chars are same,
        // it must have at least two distinct characters.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // Example: "otto" -> "ot|t|o" -> "o|t|ot" (k=2)
        // The problem statement guarantees s is a palindrome.
        // If s is a palindrome and not all characters are the same,
        // then s.substr(0, n-1) (s without last char) is not a palindrome.
        // For example, "abacaba". s.substr(0,6) = "abacab". Not a palindrome.
        // Consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
        // If we take s[0...n/2-1] and s[n/2+1...n-1] and s[n/2] (middle char if odd length)
        // and swap the first and last parts.
        // For example, s = "abacaba", n=7.
        // P1 = "aba", P2 = "c", P3 = "aba".
        // New string P3+P2+P1 = "abacaba" (same).
        //
        // A simpler argument for k=2:
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        // Consider the string s.
        // If we cut s into s[0...n-2] and s[n-1].
        // The first piece is s.substr(0, n-1).
        // The second piece is s.substr(n-1, 1).
        // This is k=1. We already checked this.
        //
        // The problem states: "It can be shown that there is no solution with one cut." for "nolon".
        // This implies that if k=1 doesn't work, k=2 is the next possibility.
        // If s is a palindrome and not all characters are the same,
        // then there exists at least one character `c` such that `s[0] != c`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If `s` is not all same characters, then `s` must contain at least two distinct characters.
        // This means `s` is not of the form `aaaaa...`.
        //
        // Consider the string `s`. If `s` is a palindrome and not all characters are the same,
        // then `s` must have at least two distinct characters.
        // For example, `s = "abacaba"`.
        // `s.substr(0, n-1)` is `s` without its last character.
        // `s.substr(0, n-1)` is `abacab`. This is not a palindrome.
        //
        // The key insight for k=2 is that if k=1 doesn't work, and not all characters are the same,
        // then k=2 is always possible.
        // Consider the string `s`. Since it's a palindrome and not all characters are the same,
        // there must be some `i` such that `s[i] != s[0]`.
        // This means `s` is not of the form `aaaa...`.
        //
        // If `s` is a palindrome and not all characters are the same,
        // then `s` has at least two distinct characters.
        // For example, `s = "abacaba"`.
        // Cut `s` into `s[0...n/2-1]`, `s[n/2]`, `s[n/2+1...n-1]`.
        // Let `P1 = s.substr(0, n/2)`, `P2 = s.substr(n/2, 1)`, `P3 = s.substr(n/2+1)`.
        // If `n` is odd, `P2` is the middle character.
        // If `n` is even, `P2` is empty, and `P1` and `P3` are `s.substr(0, n/2)` and `s.substr(n/2)`.
        // This is not the general k=2 strategy.
        //
        // The problem statement for "nolon" says "It can be shown that there is no solution with one cut."
        // This implies that if k=1 fails, and the string is not all identical characters, then k=2 is the answer.
        // This is a common pattern in competitive programming problems where if a simpler solution doesn't work,
        // the next level of complexity is the answer, unless a specific impossible case is met.
        // The "Impossible" case is when all characters are the same.
        // If `s` is a palindrome and not all characters are the same, then `k=2` is always possible.
        // For example, `s = "abacaba"`.
        // Cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
        // `P1 = "a"`, `P2 = "bacab"`, `P3 = "a"`.
        // Reorder to `P2 + P1 + P3` = `bacabaa`. Not a palindrome.
        // Reorder to `P3 + P2 + P1` = `abacaba`. Same.
        //
        // The example `nolon` -> `no|l|on` -> `on|l|no` works.
        // This is `s.substr(0,2)`, `s.substr(2,1)`, `s.substr(3,2)`.
        // `P1 = "no"`, `P2 = "l"`, `P3 = "on"`.
        // `P3 + P2 + P1 = "onlno"`. This is a palindrome and `!= nolon`.
        // This is a specific way to make two cuts.
        //
        // The problem statement implies that if k=1 doesn't work, and the string is not all identical characters,
        // then k=2 is the answer.
        // This is a common trick in such problems.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for 'x', 'y', 'z' counts
    // counts[0][i] = count of 'x' up to index i-1
    // counts[1][i] = count of 'y' up to index i-1
    // counts[2][i] = count of 'z' up to index i-1
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Adjust to 0-based indexing for prefix sums
        // Substring is s[l-1 ... r-1]
        // Length of substring is r - l + 1

        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The algorithm terminates if the counts of 'x', 'y', 'z'
        // in the substring can be rearranged such that all 3-char
        // substrings are "zyx", "xzy", or "yxz".
        // This implies that the counts must be "balanced" enough.
        // Specifically, the difference between the maximum and minimum
        // count among 'x', 'y', 'z' must be at most 1.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // dp[i] stores the maximum 'r' such that the interval [i, r]
    // does not contain any 'bad' triple.
    // Specifically, dp[i] will be the smallest r' such that [i, r']
    // contains a bad triple, or n+1 if no such r' exists.
    // We want to find the smallest r' >= i such that there exists x, k
    // with s[x]=s[x+k]=s[x+2k] and i <= x and x+2k <= r'.
    // Let's define min_r_for_l[l] as the minimum r such that [l, r] contains a bad triple.
    // If no such r exists, min_r_for_l[l] = n+1.
    // The number of valid (l, r) pairs for a given l is (n - min_r_for_l[l] + 1).
    // This is equivalent to counting (l, r) where l <= x and x+2k <= r.
    // Let's find the smallest r_prime for each l such that [l, r_prime] contains a bad triple.
    // This is equivalent to finding the smallest r_prime such that there exists
    // x, k with s[x]=s[x+k]=s[x+2k] and l <= x and x+2k <= r_prime.
    // Let's denote min_r_prime[l] as this value.
    // If no such triple exists for any x >= l, then min_r_prime[l] = n+1.

    // We iterate l from n-1 down to 0.
    // min_r_prime[l] = min(min_r_prime[l+1], smallest_r_prime_for_x_eq_l)
    // where smallest_r_prime_for_x_eq_l is the minimum x+2k for x=l.

    std::vector<int> min_r_prime(n + 1, n + 1); // min_r_prime[l] stores the smallest r (0-indexed)
                                                // such that [l, r] contains a bad triple.
                                                // Initialize with n+1 (meaning no bad triple found yet).

    // Iterate l from n-1 down to 0
    for (int l = n - 1; l >= 0; --l) {
        // Inherit from l+1: if [l+1, r] has a bad triple, then [l, r] also has one.
        min_r_prime[l] = min_r_prime[l + 1];

        // Check for bad triples starting at x = l
        // k can range from 1 up to (n - 1 - l) / 2
        // x+2k must be <= n-1
        // l+2k <= n-1 => 2k <= n-1-l => k <= (n-1-l)/2
        for (int k = 1; l + 2 * k < n; ++k) {
            if (s[l] == s[l + k] && s[l + k] == s[l + 2 * k]) {
                // Found a bad triple (l, l+k, l+2k)
                // The rightmost index is l+2k.
                // So, for this l, the smallest r_prime is l+2k.
                min_r_prime[l] = std::min(min_r_prime[l], l + 2 * k);
                // Since we are looking for the smallest r_prime for a fixed l,
                // and k increases l+2k, we can break early if we find one.
                // However, the problem statement implies k can be any value.
                // The constraint on k is 1 <= k <= n.
                // The constraint on x is 1 <= x <= n.
                // The constraint on l, r is 1 <= l <= r <= n.
                // The condition is l <= x < x+2k <= r.
                // So, for a given l, we are looking for the smallest r such that
                // there exists x, k with l <= x and x+2k <= r and s[x]=s[x+k]=s[x+2k].
                // This means we need to find min(x+2k) over all x >= l and valid k.
                // The current min_r_prime[l] correctly captures this.
                // The loop for k should continue to find the smallest l+2k for current l.
                // But wait, the problem states "at least one pair of integers x, k".
                // So for a given l, we need to find the minimum r such that there exists
                // *any* x, k with l <= x and x+2k <= r.
                // This means min_r_prime[l] = min_{x >= l, valid k} (x+2k).
                // The current logic:
                // min_r_prime[l] = min(min_r_prime[l+1], min_{k} (l+2k if s[l]=s[l+k]=s[l+2k]))
                // This is correct.
            }
        }
    }

    // Now, min_r_prime[l] contains the smallest 0-indexed r such that the interval [l, r]
    // contains at least one bad triple. If no such r exists, it's n+1.
    // For each l (0-indexed), the number of valid r's (0-indexed) is:
    // r must be >= l.
    // If min_r_prime[l] == n+1, then no bad triple starts at or after l.
    // So all r from l to n-1 are valid. Number of such r's is (n-1) - l + 1 = n - l.
    // If min_r_prime[l] < n+1, then any r < min_r_prime[l] is valid.
    // So r can be from l to min_r_prime[l] - 1.
    // Number of such r's is (min_r_prime[l] - 1) - l + 1 = min_r_prime[l] - l.
    // This is the number of (l, r) pairs that are *not* counted.
    // Let's call this `count_invalid_r_for_l`.
    // The problem asks for the number of pairs (l, r) that *do* satisfy the condition.
    // A pair (l, r) satisfies the condition if there exists x, k such that
    // l <= x and x+2k <= r and s[x]=s[x+k]=s[x+2k].
    // This means r must be >= min_r_prime[l].
    // So for a given l, the valid r's are from min_r_prime[l] to n-1.
    // The number of such r's is (n-1) - min_r_prime[l] + 1 = n - min_r_prime[l].
    // If min_r_prime[l] == n+1, then n - (n+1) = -1, which means 0 valid r's. This is correct.

    long long count_valid_pairs = 0;
    for (int l = 0; l < n; ++l) {
        if (min_r_prime[l] <= n - 1) { // If a bad triple exists starting at or after l
            count_valid_pairs += (n - min_r_prime[l]);
        }
    }

    std::cout << count_valid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, k=0 (2^0-1=0, but we need 1 element)
            k = 0;
        } else {
            k = std::floor(std::log2(X + 1));
        }

        // If 2^k - 1 is exactly X, we can use k elements.
        // If 2^k - 1 < X, we use k elements and then process the remainder.
        // If 2^k - 1 > X, it means k was too large. This happens if X+1 is not a power of 2.
        // In this case, we need to find the largest k such that 2^k - 1 <= X.
        // The floor(log2(X+1)) already gives this k.
        // For example, if X=10, X+1=11, log2(11) approx 3.45, floor is 3.
        // 2^3-1 = 7. We use 3 elements. X becomes 10-7=3.
        // Next, X=3, X+1=4, log2(4)=2, floor is 2.
        // 2^2-1 = 3. We use 2 elements. X becomes 3-3=0.
        // Total elements: 3 + 2 = 5.
        // This strategy works.

        long long num_elements_for_k = k + 1; // We add k+1 elements to the array
                                             // The first k elements will be 'current_val'
                                             // The (k+1)-th element will be 'current_val + d'
                                             // This creates 2^k subsequences of 'current_val'
                                             // and 1 subsequence of 'current_val + d'
                                             // Total 2^k subsequences.
                                             // The number of subsequences formed by k identical elements is 2^k-1.
                                             // The number of subsequences formed by k identical elements and one distinct element is 2^k.
                                             // Let's re-evaluate.
                                             // If we add 'k' identical elements, say 'A', we get 2^k-1 subsequences.
                                             // If we add 'k' identical elements 'A' and one element 'B' such that B-A >= d,
                                             // then the subsequences containing both A and B are removed.
                                             // The remaining subsequences are those containing only A's (2^k-1) and those containing only B (1).
                                             // Total 2^k.
                                             // So, if we want to add 2^k subsequences, we can add k identical elements and one element far away.
                                             // The number of elements to add is k+1.
                                             // The number of subsequences contributed is 2^k.

        // The number of subsequences we want to contribute is X.
        // We want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=10, k=floor(log2(10))=3. 2^3=8.
        // We add 3 identical elements (current_val) and one element (current_val + d).
        // This contributes 2^3 = 8 subsequences.
        // X becomes 10-8=2.
        // Next, X=2, k=floor(log2(2))=1. 2^1=2.
        // We add 1 identical element (current_val') and one element (current_val' + d).
        // This contributes 2^1 = 2 subsequences.
        // X becomes 2-2=0.
        // This strategy seems correct.

        // Let's refine k: we want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=1, k=0. 2^0=1.
        // If X=10, k=3. 2^3=8.
        // If X=4, k=2. 2^2=4.

        long long current_k = 0;
        if (X > 0) { // log2(0) is undefined, log2(1) is 0
            current_k = std::floor(std::log2(X));
        }

        // Add current_k identical elements of value `current_val`
        for (int i = 0; i < current_k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the contributed subsequences
        X -= (1LL << current_k);

        // Prepare for the next block of elements
        // The next block of elements must be sufficiently far from the current block
        // to ensure that subsequences mixing elements from different blocks are removed.
        // We add d to current_val, then add 1 to ensure it's strictly greater than current_val + d - 1.
        // This ensures that current_val_next - current_val >= d.
        current_val += d + 1;

        // Check for overflow
        if (current_val >= 1000000000000000000LL) { // 10^18
            // This case should ideally not be reached if X is within limits and d is positive.
            // The maximum number of elements is 10^4.
            // Max current_val would be roughly 1 + (10^4) * (10^9 + 1) which is too large.
            // However, the number of distinct values is at most 60 (log2(10^9)).
            // So current_val will be 1 + 60 * (d+1).
            // 1 + 60 * (10^9 + 1) is approx 6 * 10^10, which is < 10^18.
            // So overflow for current_val is not an issue.
        }
    }

    // The problem states that the number of elements in the output array should not be more than 10^4.
    // The maximum value of X is 10^9.
    // The maximum k is floor(log2(10^9)) = 29.
    // In the worst case, X is a sum of powers of 2.
    // E.g., X = 2^29 + 2^28 + ... + 2^0. This would be 30 blocks.
    // Each block adds at most 29 elements.
    // So, total elements would be at most 30 * 29 = 870.
    // This is well within the 10^4 limit.

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

