#include <iostream>
#include <vector>
#include <numeric> // For std::gcd in C++17, though not strictly needed for this solution

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The problem asks for n distinct integers from 1 to 4n.
        // We need to select n numbers such that no pair (a, b) satisfies:
        // 1. gcd(a, b) = 1
        // 2. a divides b
        // 3. b divides a
        //
        // A simple strategy is to pick n consecutive even numbers, starting from 2n+2.
        // For example, 2n+2, 2n+4, ..., 2n+2n = 4n.
        // Let's check this strategy:
        // Consider two numbers a = 2k and b = 2m from this set.
        // All numbers are even, so gcd(a, b) will always be at least 2.
        // Thus, gcd(a, b) != 1 is satisfied.
        //
        // Now, consider the divisibility condition.
        // The numbers are 2n+2, 2n+4, ..., 4n.
        // Let a = 2i and b = 2j be two distinct numbers from this set.
        // The smallest number is 2n+2. The largest is 4n.
        // If a divides b, then b = k * a for some integer k.
        // Since all numbers are even, k must be an integer.
        // If a and b are from the chosen set, then 2n+2 <= a < b <= 4n.
        // If a divides b, then b >= 2a.
        // But if a >= 2n+2, then 2a >= 2(2n+2) = 4n+4.
        // Since b <= 4n, it's impossible for b >= 2a.
        // Therefore, no number in this set can divide another number in the set.
        //
        // This strategy satisfies all conditions.
        // The numbers are 2n+2, 2n+4, ..., 4n.
        // There are (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n numbers.
        // All numbers are distinct and within the range [1, 4n].

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 + 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    // A set to store available heads that can cover tracks up to their rightmost reach.
    // Stores pairs: {rightmost_reach, head_original_position}
    // We use head_original_position as a tie-breaker, though not strictly necessary here.
    std::set<std::pair<long long, long long>> available_heads;

    while (p_idx < m) {
        // Add all heads whose leftmost reach is <= current target track p[p_idx]
        // to the set of available heads.
        while (h_idx < n && h[h_idx] - T <= p[p_idx]) {
            available_heads.insert({h[h_idx] + T, h[h_idx]});
            h_idx++;
        }

        // Remove heads from the set that cannot reach the current target track p[p_idx].
        // These are heads whose rightmost reach is less than p[p_idx].
        while (!available_heads.empty() && available_heads.begin()->first < p[p_idx]) {
            available_heads.erase(available_heads.begin());
        }

        // If no head can cover p[p_idx], then T is not sufficient.
        if (available_heads.empty()) {
            return false;
        }

        // Greedily pick the head that can cover p[p_idx] and reaches furthest to the right.
        // This is the last element in the set (due to sorting by rightmost_reach).
        auto it = available_heads.rbegin();
        long long current_head_right_reach = it->first;

        // This head covers all tracks from p[p_idx] up to current_head_right_reach.
        // Advance p_idx past all tracks covered by this head.
        while (p_idx < m && p[p_idx] <= current_head_right_reach) {
            p_idx++;
        }

        // The head used to cover these tracks is now "busy" or "used".
        // Remove it from the set of available heads.
        available_heads.erase(std::next(it).base()); // std::next(it).base() converts reverse_iterator to iterator
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between coordinates (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

