        // If we have 'count' tiles of value 'val', they contribute 'val * count' to the total sum
        // that can potentially be merged into larger tiles.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

