int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, the only number is l.
        // We need to find a divisor of l (except 1).
        // The smallest prime factor is always a good candidate.
        // For l=2, output 2. For l=3, output 3. For l=4, output 2.
        // Since l >= 2, l itself is a divisor (and > 1).
        // Or, if l is even, 2 is a divisor.
        // The problem asks for *any* integer.
        // If l is even, 2 is a divisor.
        // If l is odd, l itself is a divisor.
        // However, the problem asks for the one that appears maximum number of times.
        // If l=r, any divisor of l (except 1) appears exactly once.
        // So, any divisor of l (except 1) is a valid answer.
        // The simplest is to just output 2 if l is even, otherwise l itself.
        // But the problem statement implies we should find the one that appears max times.
        // If l=r, all divisors (except 1) appear once. So any divisor is fine.
        // The simplest is to output 2 if l is even, otherwise l.
        // But the example 3 6 -> 3. If l=r=3, output 3. If l=r=4, output 2.
        // The most robust answer for l=r is to just output l itself, as it's a divisor > 1.
        // Or, since 2 is often the most frequent, let's stick to 2 if possible.
        // If l is even, 2 is a divisor.
        // If l is odd, 2 is not a divisor.
        // So if l is even, 2 is a valid answer.
        // If l is odd, l itself is a valid answer.
        // This is consistent with the general logic.
        if (l % 2 == 0) {
            std::cout << 2 << std::endl;
        } else {
            std::cout << l << std::endl;
        }
    } else {
        // If l != r, the range contains at least two numbers.
        // The number 2 will always be a divisor for at least floor((r-l+1)/2) numbers.
        // For any other number x > 2, the count of its multiples will be less than or equal to
        // the count of multiples of 2.
        // Example: [19, 29]
        // Multiples of 2: 20, 22, 24, 26, 28 (5 numbers)
        // Multiples of 3: 21, 24, 27 (3 numbers)
        // Multiples of 4: 20, 24, 28 (3 numbers)
        // Multiples of 5: 20, 25 (2 numbers)
        // ...
        // The count of multiples of x in [l, r] is floor(r/x) - ceil(l/x) + 1.
        // This count is maximized when x is smallest.
        // Since we exclude 1, the smallest possible x is 2.
        // Thus, 2 will always be the integer that appears the maximum number of times
        // (or tied for maximum) when l != r.
        std::cout << 2 << std::endl;
    }

    return 0;
}

