void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q_i > q_{i-1} and q is valid
                // as q_i would be a new maximum, implying it hasn't been seen before as a p_j
                // for j < i. But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be <= q_{i-1}
            // We need to pick the smallest available number that is not used yet
            // and is less than or equal to q_{i-1}.
            // To maximize chances of finding a solution, we should pick the smallest
            // available number that is not used and is less than q_i (which is q_{i-1}).
            // The numbers available are 1 to n.
            // We need to find the smallest number `x` such that `x` is not in `used_numbers`
            // and `x < q_i`.
            // The largest possible value for p_i in this case is q_i - 1.
            // We can iterate downwards from q_i - 1 to find an unused number.
            // Or, we can collect all unused numbers and pick the smallest one.
            // Let's use a set of available numbers.
            p[i] = -1; // Placeholder
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that haven't been used yet
    std::vector<int> available_fillers;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_fillers.push_back(i);
        }
    }
    std::sort(available_fillers.rbegin(), available_fillers.rend()); // Sort descending for easy pop_back

    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q[i] == q[i-1]
            if (available_fillers.empty()) {
                possible = false;
                break;
            }
            int candidate = available_fillers.back();
            available_fillers.pop_back();

            if (candidate > q[i]) { // q[i] is q_{i-1}
                possible = false;
                break;
            }
            p[i] = candidate;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

