    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders available: k <= c
        // 2. The number of mathematicians available: k <= m
        // 3. The total number of students available: 3k <= c + m + x
        // Combining 1 and 2: k <= min(c, m)
        // Combining all: k <= min(c, m, (c + m + x) / 3)
        // This is because if we form k teams, we need at least k coders and k mathematicians.
        // The remaining k spots in the teams (3k total members - k coders - k mathematicians)
        // can be filled by any remaining students (coders, mathematicians, or unspecialized).
        // The total number of students available for these remaining k spots is (c - k) + (m - k) + x.
        // We need this to be at least k.
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k
        // So, k must satisfy all three conditions: k <= c, k <= m, and k <= (c + m + x) / 3.
        // Therefore, the maximum k is the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
