int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we'll use for the alternating sequence

    // Construct the first k+1 elements to generate k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining elements in increasing order
    // These will generate a difference of 1 with the previous element
    // (e.g., p[k] and p[k+1] will have difference 1 if p[k] is left and p[k+1] is left+1)
    // or p[k] and p[k+1] will have difference 1 if p[k] is right and p[k+1] is right+1
    // The 'left' variable now holds the next available number after the alternating sequence.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

