    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the first index `i` from the right such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-increasing suffix.
    // If i is 0, the whole array is non-increasing.

    // Find the first index `j` from the right such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix
    int j = i; // Start searching from `i`
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" array if we remove a prefix of length `j`.
    // The elements a[j...i-1] form a non-decreasing sequence.
    // The elements a[i...n-1] form a non-increasing sequence.
    // The combined sequence a[j...n-1] is of the form non-decreasing then non-increasing.

    std::cout << j << std::endl;
}

