#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to include m.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index of {1..m}
        // to the maximum index of {1..m}.

        // Update current_min_idx and current_max_idx to include the position of 'm'.
        // These variables track the minimum and maximum indices encountered so far
        // for numbers 1 to 'm'.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1 to m.
        // This means its length must be 'm'.
        // The length of this subsegment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

