int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // Friends who get w_i = 1: they get 2 * largest_available_number
        // These are the friends with the smallest w_i values after sorting w.
        // So, iterate w from largest index downwards for w_i = 1.
        // This means friends with w_i = 1 get the largest numbers.
        // The sorted w array has w_i = 1 at the beginning if any.
        // No, it's better to iterate w from largest index downwards.
        // The largest w_i values are at the end of the sorted w array.
        // The smallest w_i values are at the beginning of the sorted w array.

        // First, handle friends with w_i = 1.
        // These friends should get the largest available numbers.
        // Since w is sorted ascending, w_i = 1 will be at the beginning.
        // We want to give the largest numbers to these friends.
        // So, iterate w from k-1 down to 0.
        // If w[i] == 1, give a[a_ptr_right] to this friend.
        // This friend's happiness is a[a_ptr_right] + a[a_ptr_right].
        // Decrement a_ptr_right.

        // Let's re-think the strategy for w_i = 1.
        // To maximize sum of happiness, we want to maximize max_val and min_val for each friend.
        // For w_i = 1, happiness is 2 * val. These should be the largest values.
        // For w_i > 1, happiness is max_val + min_val.
        // The largest values (a[n-1], a[n-2], ...) should be used as max_val for friends.
        // The smallest values (a[0], a[1], ...) should be used as min_val for friends.

        // Strategy:
        // 1. Give the largest 'k' numbers as the 'max_val' for each friend.
        //    These are a[n-1], a[n-2], ..., a[n-k].
        //    Add these to total_happiness.
        //    a_ptr_right will be n-k-1 after this.
        // 2. For friends with w_i = 1:
        //    They already received one number (their max_val). Since w_i=1, this is also their min_val.
        //    So, their happiness is max_val + max_val.
        //    These friends should get the largest available numbers.
        //    These are the k friends. The largest k numbers are a[n-1]...a[n-k].
        //    So, for each friend, we add a[n-1-i] to total_happiness.
        //    This means we add a[n-1] + a[n-2] + ... + a[n-k] to total_happiness.
        //    This covers the 'max_val' part for all k friends.
        //    And for friends with w_i = 1, it also covers their 'min_val' part.

        // Let's iterate through w in descending order.
