// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, we need to find a divisor x of p
        // such that x is not divisible by q.
        // To maximize x, we should divide p by the smallest possible factor
        // that makes it not divisible by q.
        // This means we need to remove just enough prime factors from p
        // such that for at least one prime factor f of q,
        // the power of f in x is less than the power of f in q.

        // Get unique prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 0;

        // For each unique prime factor f of q
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // or until it's no longer divisible by f.
            while (current_p % q == 0) {
                current_p /= f;
            }
            // current_p is now a divisor of p that is not divisible by q.
            // We want the maximum such current_p.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

