void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string coloring(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');

        bool possible_split = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) {
                current_coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > split_digit) {
                current_coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == split_digit
                // Try to assign to color 2 first if possible
                // This ensures that if there are multiple 'split_digit' values,
                // the ones that come *after* the first 'split_digit' assigned to color 1
                // are assigned to color 2.
                // This is crucial for the non-decreasing property of S1 and S2.
                if (!s2_digits.empty() && d[i] < s2_digits.back()) {
                    // If current digit (split_digit) is less than the last digit in S2,
                    // it must go to S1.
                    current_coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                } else {
                    // Otherwise, assign to color 2.
                    current_coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // If both S1 and S2 are non-decreasing, we found a valid coloring.
        coloring = current_coloring;
        found_solution = true;
        break;
    }

    if (found_solution) {
        std::cout << coloring << "\n";
    } else {
        std::cout << "-\n";
    }
}

