// Function to check if a prefix of length 'len' is a permutation
bool is_permutation_prefix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_prefix, const std::vector<int>& freq_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_prefix[len - 1] != len) return false; // Max element must be 'len'
    if (freq_prefix[len - 1] != len) return false; // All elements from 1 to 'len' must be present exactly once
    return true;
}

// Function to check if a suffix of length 'len' is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix, const std::vector<int>& freq_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_suffix[n - len] != len) return false; // Max element must be 'len'
    if (freq_suffix[n - len] != len) return false; // All elements from 1 to 'len' must be present exactly once
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max_prefix[i] = max(a[0]...a[i])
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
    }

    // Precompute max_suffix[i] = max(a[i]...a[n-1])
    std::vector<int> max_suffix(n);
    max_suffix[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute freq_prefix[i] = count of distinct elements in a[0...i]
    // and check if all elements are <= max_prefix[i]
    std::vector<int> freq_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n-1, but using n+1 for safety
    int distinct_count_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (!possible_prefix) {
            freq_prefix[i] = -1; // Mark as invalid
            continue;
        }
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            possible_prefix = false;
            freq_prefix[i] = -1;
        } else {
            seen_prefix[a[i]] = true;
            distinct_count_prefix++;
            if (distinct_count_prefix != max_prefix[i]) { // If distinct count doesn't match max, it's not a permutation
                possible_prefix = false;
                freq_prefix[i] = -1;
            } else {
                freq_prefix[i] = distinct_count_prefix;
            }
        }
    }

    // Precompute freq_suffix[i] = count of distinct elements in a[i...n-1]
    // and check if all elements are <= max_suffix[i]
    std::vector<int> freq_suffix(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix
    int distinct_count_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (!possible_suffix) {
            freq_suffix[i] = -1; // Mark as invalid
            continue;
        }
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            possible_suffix = false;
            freq_suffix[i] = -1;
        } else {
            seen_prefix[a[i]] = true;
            distinct_count_suffix++;
            if (distinct_count_suffix != max_suffix[i]) { // If distinct count doesn't match max, it's not a permutation
                possible_suffix = false;
                freq_suffix[i] = -1;
            } else {
                freq_suffix[i] = distinct_count_suffix;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_permutation_prefix(l1, n, a, max_prefix, freq_prefix) &&
            is_permutation_suffix(l2, n, a, max_suffix, freq_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

