int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.
    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_inner_sum = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_inner_sum = (sum_k_inner_sum * inv2) % MOD;

    long long sum_k_term = (b % MOD * sum_k_inner_sum) % MOD;
    sum_k_term = (sum_k_term + (a % MOD)) % MOD;

    // Total sum = (sum_r_term * sum_k_term) % MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

