int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To form 'one': needs 'o', 'n', 'e'
    // To form 'zero': needs 'z', 'e', 'r', 'o'

    // Prioritize 'one's to make the number as large as possible
    // Each 'one' uses one 'o', one 'n', one 'e'.
    int num_ones = count_n; // 'n' is unique to 'one' among 'o', 'n', 'e' for 'one' and 'z', 'e', 'r', 'o' for 'zero'
                            // More precisely, 'n' is only used by 'one'.
                            // So, the number of 'one's is directly limited by 'n'.
                            // The problem guarantees that it's possible to form a sequence of "zero" and "one".
                            // This implies that if we have 'n's, we will have enough 'o's and 'e's to form 'one's.
                            // Let's verify:
                            // If we have `k` 'n's, we can form `k` 'one's.
                            // This uses `k` 'o's and `k` 'e's.
                            // The remaining 'o's and 'e's, along with 'z's and 'r's, must form 'zero's.
                            // This logic holds because 'n' is exclusive to 'one'.

    // After forming `num_ones` 'one's:
    // Remaining 'o's: count_o - num_ones
    // Remaining 'e's: count_e - num_ones

    // Now, form 'zero's. Each 'zero' needs 'z', 'e', 'r', 'o'.
    // The number of 'zero's is limited by 'z' (unique to 'zero').
    int num_zeros = count_z; // 'z' is exclusive to 'zero'.

    // Output the '1's first, then the '0's, separated by spaces.
    bool first_output = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << "1";
        first_output = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << "0";
        first_output = false;
    }
    std::cout << std::endl;

    return 0;
}

