        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks
        // using the first trade offer.
        // Each trade of type 1 (1 stick -> x sticks) effectively gives us (x - 1) net sticks.
        // Number of type 1 trades needed: ceil((total_sticks_required - 1) / (x - 1))
        // This can be calculated as (A + B - 1) / B for ceil(A/B)
        long long sticks_to_generate = total_sticks_required - 1;
        long long sticks_per_trade = x - 1;

        long long trades_type1 = (sticks_to_generate + sticks_per_trade - 1) / sticks_per_trade;

        // Total trades = trades_type1 + trades_type2
        // trades_type2 is simply k (to get k coal)
        long long total_trades = trades_type1 + k;

        std::cout << total_trades << "\n";
    }
