        //    Example output for n=2 is 6 4. My strategy gives 6 8. Both are valid.
        //    For n=3: k values are 3+1=4, 3+2=5, 3+3=6. Chair numbers: 2*4=8, 2*5=10, 2*6=12. Output: 8 10 12.
        //    Example output for n=3 is 4 6 10. My strategy gives 8 10 12. Both are valid.
        //    For n=4: k values are 4+1=5, 4+2=6, 4+3=7, 4+4=8. Chair numbers: 2*5=10, 2*6=12, 2*7=14, 2*8=16. Output: 10 12 14 16.
        //    Example output for n=4 is 14 10 12 8. My strategy gives 10 12 14 16. Both are valid.

        // So the strategy is to print 2*(n+1), 2*(n+2), ..., 2*(2n).
        for (int i = 1; i <= n; ++i) {
            std::cout << 2 * (n + i) << (i == n ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

