            balance += a_i;
            // If balance becomes negative, it means we have a deficit
            // that must have been covered by moving units from a later index (j > i)
            // to an earlier index (k <= i). This costs coins.
            // The amount of deficit is -balance. These units must be moved
            // from some j > i to some k <= i. This costs 1 coin per unit.
            // So, we add -balance to coins and reset balance to 0,
            // effectively "paying" for the deficit and making it up.
            if (balance < 0) {
                coins += -balance;
                balance = 0;
            }
        }
        std::cout << coins << "\n";
