    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_post_duration) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_post_duration) {
            // This post's duration exceeded the target, so no solution
            std::cout << "No\n";
            return 0;
        }
    }

    // After iterating through all videos, check if we formed exactly k posts
    // and if the last post (if any) was correctly terminated.
