#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_for_i.
        // This logic is based on the observation that if p[i] is not n,
        // then max(min(p[i], p[j])) for j!=i will be p[i] itself,
        // because there must be some p[j] > p[i].
        // If p[i] is n, then max(min(n, p[j])) for j!=i will be n-1.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int bad_prices_count = 0;
    // min_price_so_far stores the minimum price encountered from the right end of the array up to the current index.
    // Initialize with the last element's price.
    int min_price_so_far = a[n - 1]; 

    // Iterate from the second to last element backwards to the first element.
    // For each element a[i], we compare it with the minimum price found in a[i+1...n-1].
    // This minimum price is stored in min_price_so_far.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_price_so_far) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_so_far, it means a[i] is
            // either equal to or smaller than the minimum price to its right.
            // In this case, a[i] itself becomes a new candidate for the minimum
            // price for elements further to its left.
            min_price_so_far = a[i];
        }
    }
    std::cout << bad_prices_count << std::endl;
}

