#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos (0-indexed).
                // The gap is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance from last_r_pos to current_r_pos is (i+1) - (last_r_pos+1)
                // The distance from last_r_pos (0-indexed) to current_r_pos (0-indexed) is i - last_r_pos.
                // The number of 'L' cells between last_r_pos and i is i - last_r_pos - 1.
                // The length of the segment of 'L's is i - (last_r_pos + 1).
                // The jump needed to clear this segment is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos + 1.
                // Example: 0 R L L R 4. last_r_pos = -1. i = 0 (s[0] is R). Gap = 0 - (-1) = 1.
                // Example: 0 R L L R 4. last_r_pos = 0. i = 3 (s[3] is R). Gap = 3 - 0 = 3.
                // The distance from the previous 'R' (or 0) to the current 'R' is (current_R_index_0based + 1) - (previous_R_index_0based + 1)
                // This is (i+1) - (last_r_pos+1) = i - last_r_pos.
                // The maximum jump needed to get from last_r_pos to i+1 is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos + 1.
                // No, it's simpler: the distance from last_r_pos (cell index) to i+1 (cell index) is (i+1) - (last_r_pos + 1) + 1.
                // The distance from cell `last_r_pos + 1` to cell `i + 1` is `(i+1) - (last_r_pos + 1)`.
                // The jump from `last_r_pos + 1` to `i + 1` requires `d >= (i+1) - (last_r_pos + 1)`.
                // The actual distance is `(i+1) - (last_r_pos + 1)`.
                // The number of cells to jump over is `(i+1) - (last_r_pos + 1)`.
                // The distance from cell `last_r_pos + 1` to cell `i + 1` is `i - last_r_pos`.
                // The required `d` must be at least `i - last_r_pos`.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After the loop, consider the jump from the last 'R' to cell n+1.
        // The last 'R' was at index `last_r_pos` (0-indexed), which corresponds to cell `last_r_pos + 1`.
        // We need to reach cell `n+1`.
        // The distance is `(n+1) - (last_r_pos + 1)`.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
