int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cost = 1; // Cost for n=1 staircase
        long long sum_of_powers_of_2 = 1; // 2^0

        while (true) {
            // Calculate the cost for the next nice staircase.
            // If current_stair_cost is for n, the next one is for 2n+1.
            // The cost for n stairs is n*(n+1)/2.
            // The cost for 2n+1 stairs is (2n+1)*(2n+2)/2 = (2n+1)*(n+1).
            // This is also 2 * (cost for n stairs) + (n+1)^2.
            // Or, more simply, the cost for a nice staircase with (2^k - 1) stairs is (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // The sequence of costs for nice staircases (n=1, 3, 7, 15, ...) is:
            // n=1: cost = 1 * 2 / 2 = 1
            // n=3: cost = 3 * 4 / 2 = 6
            // n=7: cost = 7 * 8 / 2 = 28
            // n=15: cost = 15 * 16 / 2 = 120
            // The cost for a staircase with (2^k - 1) stairs is (2^k - 1) * 2^(k-1).
            // Let's denote N_k = 2^k - 1. The cost is N_k * (N_k + 1) / 2.
            // The sequence of N_k is 1, 3, 7, 15, 31, ...
            // The sequence of costs is 1, 6, 28, 120, 496, ...
            // The current_stair_cost variable holds the cost for the current N_k.
            // The next N_k is 2 * N_k + 1.
            // The next cost is (2 * N_k + 1) * (2 * N_k + 2) / 2 = (2 * N_k + 1) * (N_k + 1).
            // This is equivalent to (2 * current_stair_cost) + (N_k + 1)^2.
            // N_k + 1 is 2^k.
            // So, the next cost is 2 * current_stair_cost + (2^k)^2 = 2 * current_stair_cost + 2^(2k).
            // The sum_of_powers_of_2 variable holds 2^k.
            // So, the next cost is 2 * current_stair_cost + (sum_of_powers_of_2)^2.

            if (x >= current_stair_cost) {
                x -= current_stair_cost;
                count++;

                // Calculate the cost for the next nice staircase
                // The number of stairs for the current nice staircase is sum_of_powers_of_2 - 1.
                // The next number of stairs is 2 * (sum_of_powers_of_2 - 1) + 1 = 2 * sum_of_powers_of_2 - 1.
                // The cost for a staircase with N stairs is N * (N + 1) / 2.
                // Let N_prev = sum_of_powers_of_2 - 1.
                // Let N_curr = 2 * N_prev + 1 = 2 * (sum_of_powers_of_2 - 1) + 1 = 2 * sum_of_powers_of_2 - 1.
                // The cost for N_curr stairs is N_curr * (N_curr + 1) / 2.
                // N_curr + 1 = 2 * sum_of_powers_of_2.
                // So, cost = (2 * sum_of_powers_of_2 - 1) * (2 * sum_of_powers_of_2) / 2
                //          = (2 * sum_of_powers_of_2 - 1) * sum_of_powers_of_2.
                // This is the next current_stair_cost.

                // Update sum_of_powers_of_2 for the next iteration (it will be 2^(k+1))
                sum_of_powers_of_2 *= 2;
                current_stair_cost = (2 * sum_of_powers_of_2 - 1) * sum_of_powers_of_2;

            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

