int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The number of coders (each team needs at least one coder)
        // 2. The number of mathematicians (each team needs at least one mathematician)
        // 3. The total number of students (each team needs 3 students)
        // So, k <= c, k <= m, and 3*k <= c + m + x.
        // This implies k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'high'.
        // The lower bound is 0.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        // Binary search for the maximum k
        while (low <= high) {
            long long mid = low + (high - low) / 2; // Number of teams we are trying to form

            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians at minimum.
            // The remaining students are:
            // coders_left = c - mid
            // mathematicians_left = m - mid
            // unspecialized_left = x

            // Total students remaining after assigning one coder and one mathematician to each of 'mid' teams:
            // (c - mid) + (m - mid) + x
            // Each of the 'mid' teams still needs one more student.
            // So, we need 'mid' additional students from the remaining pool.
            // If (c - mid) + (m - mid) + x >= mid, then it's possible to form 'mid' teams.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // q_1 must be within [1, n]
        possible = false;
    } else {
        used_numbers.insert(p[0]);
    }

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used_numbers.count(p[i])) {
                possible = false;
                break;
            }
            used_numbers.insert(p[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number not yet used, and p_i < q_i
            // To maximize chances of finding a solution, we should pick the smallest available number
            // that is less than q_i.
            // However, the problem asks for *any* possible permutation.
            // A simpler strategy: fill these slots later with available numbers.
            // For now, mark p[i] as a placeholder (e.g., 0) and ensure q_i is not violated.
            p[i] = 0; // Placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort descending for greedy assignment

    // Fill in the placeholders
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) { // This is a placeholder
            if (available_numbers.empty()) {
                possible = false; // Not enough numbers to fill placeholders
                break;
            }
            int num_to_assign = available_numbers.back(); // Smallest available number
            available_numbers.pop_back();

            if (num_to_assign >= q[i]) { // If the smallest available number is not less than q_i
                possible = false; // Cannot satisfy p_i < q_i
                break;
            }
            p[i] = num_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Final check for validity (optional, but good for robustness)
    // Recompute prefix maximums and compare with q
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

