            break;
        }

        if (c == '(') {
            // If we still need open brackets and adding one won't make us exceed k/2 total open
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need close brackets and adding one won't make balance negative
            // and adding one won't make us exceed k/2 total close
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we extend the segment to include 'm'.
        // The segment containing 1, 2, ..., m must span from the minimum index
        // of any of these numbers to the maximum index of any of these numbers.
        // We maintain current_min_idx and current_max_idx for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include 'm'.

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // contains exactly numbers 1 to m.
        // This means its length must be m.
        // The length of the segment is (current_max_idx - current_min_idx + 1).
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

