int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    long long count01 = 0; // Number of positions where a[i] = '0' and b[i] = '1'
    long long count10 = 0; // Number of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            // We need a '1' here, but have a '0'.
            // If there's a '10' mismatch available, we can swap.
            // Otherwise, we might need to flip.
            if (count10 > 0) {
                // We have a '1' at some previous '10' mismatch position
                // and need a '1' here. We can swap the '1' from the '10' position
                // to this '01' position. This resolves both mismatches.
                // The cost of this swap is 1 (as if we flipped both).
                // This is equivalent to pairing a '01' with a '10' and paying 1.
                count10--;
            } else {
                // No '10' mismatch available to swap with.
                // This '01' mismatch must be resolved by a flip, or by a future swap
                // with a '10' mismatch. For now, we increment count01.
                // This '01' mismatch is "unpaired".
                count01++;
            }
        } else if (a[i] == '1' && b[i] == '0') {
            // We need a '0' here, but have a '1'.
            // If there's a '01' mismatch available, we can swap.
            // Otherwise, we might need to flip.
            if (count01 > 0) {
                // We have a '0' at some previous '01' mismatch position
                // and need a '0' here. We can swap the '0' from the '01' position
                // to this '10' position. This resolves both mismatches.
                // The cost of this swap is 1 (as if we flipped both).
                // This is equivalent to pairing a '10' with a '01' and paying 1.
                count01--;
            } else {
                // No '01' mismatch available to swap with.
                // This '10' mismatch must be resolved by a flip, or by a future swap
                // with a '01' mismatch. For now, we increment count10.
                // This '10' mismatch is "unpaired".
                count10++;
            }
        }
    }

    // After iterating through all positions, any remaining 'count01' or 'count10'
    // mismatches must be resolved by flipping. Each flip costs 1.
    cost = count01 + count10;

    std::cout << cost << std::endl;

    return 0;
}

