        if (total_toys == 1) {
            if (C == 1) can_be_box3 = true;
        } else {
            // To get a positive result, we need an even number of negative factors.
            if ((A + B) % 2 == 0) { // Final sign can be positive
                // To get magnitude < 1:
                // If B+C > 0, we have at least one toy with magnitude < 1.
                // If B+C == 0, all initial toys have magnitude >= 1.
