        // find the rightmost point x[right_ptr] such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, all points x[j] where i < j < right_ptr will also satisfy x[j] - x[i] <= d.
        // The right_ptr only moves forward, making this O(N) overall.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }

        // Now, all points from x[i+1] to x[right_ptr-1] can be the middle or rightmost point
        // of a valid triplet starting with x[i].
        // The number of points available to choose from (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1
        // which simplifies to right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points to form a triplet with x[i].
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = static_cast<long long>(right_ptr - 1 - i);

        if (m >= 2) { // We need at least 2 points to choose from
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // If a[i] > s for i < median_idx, we must decrease a[i] to s.
    // The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // If a[i] < s for i > median_idx, we must increase a[i] to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareA);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    // Create the result array A'
    // The i-th smallest B value should be paired with the i-th largest A value.
    // This means b_elements[i] (which is the i-th smallest B)
    // should be paired with a_elements[m - 1 - i] (which is the i-th largest A).
    // The original index of b_elements[i] tells us where in the output array A'
    // the value a_elements[m - 1 - i].value should go.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_prefix, const std::vector<bool>& distinct_prefix) {
    if (len == 0) return false; // Permutations must have non-zero length
    return distinct_prefix[len - 1] && max_prefix[len - 1] == len;
}

// Function to check if a suffix is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& max_suffix, const std::vector<bool>& distinct_suffix) {
    if (len == 0) return false; // Permutations must have non-zero length
    return distinct_suffix[n - len] && max_suffix[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_prefix(n);
    std::vector<bool> distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n-1, but for safety use n+1
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_prefix[i] = current_max_prefix;
        distinct_prefix[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_suffix(n);
    std::vector<bool> distinct_suffix(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_suffix[a[i]]) { // a[i] > n is not possible based on constraints a_i <= n-1
            current_distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_suffix[i] = current_max_suffix;
        distinct_suffix[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_permutation_prefix(l1, a, max_prefix, distinct_prefix) &&
            is_permutation_suffix(l2, n, a, max_suffix, distinct_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (wins == 0) { // All L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k L's to W's. Best to make them consecutive.
                // If k=1, score=1. If k=2, score=1+2=3. If k=3, score=1+2+2=5.
                // Score = 1 + 2*(k-1) = 2*k - 1
                std::cout << std::max(0, 2 * k - 1) << "\n";
            }
            continue;
        }

        // If there are already wins, we want to fill gaps between W's
        // and then extend from the ends.

        // Collect lengths of L-segments between W's
        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // If all are W's, no gaps to fill.
        if (first_W == -1) { // Should be handled by wins == 0 case
             // This case should not be reached if wins > 0
        }

        int current_gap_len = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap_len++;
            } else { // s[i] == 'W'
                if (current_gap_len > 0) {
                    gaps.push_back(current_gap_len);
                }
                current_gap_len = 0;
            }
        }
        if (current_gap_len > 0) {
            gaps.push_back(current_gap_len);
        }
        std::sort(gaps.begin(), gaps.end());

        // Fill gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W, connecting two Ws.
                                                  // Each L adds 2 points (1 for itself, 1 for making previous W consecutive)
                                                  // The +1 is because the W after the gap now gets 2 points instead of 1.
                                                  // Example: W L W -> W W W. Score changes from (1+1) to (1+2+2). Diff = 3.
                                                  // L changes to W. It gets 1 point. The W after it gets +1 point.
                                                  // So, for each L changed, we get 2 points.
                                                  // The +1 is for the W that was previously separated by the gap.
                                                  // W L L W -> W W W W. Score changes from (1+1) to (1+2+2+2). Diff = 4.
                                                  // 2 L's changed. Each L adds 2 points. Total 4.
                                                  // The formula 2*gap_len + 1 is correct.
                                                  // W L W (score 1+1=2) -> W W W (score 1+2+2=5). Diff = 3. gap_len=1. 2*1+1=3.
                                                  // W L L W (score 1+1=2) -> W W W W (score 1+2+2+2=7). Diff = 5. gap_len=2. 2*2+1=5.
            } else {
                current_score += 2 * k; // Can only fill part of the gap. Each L adds 2 points.
                k = 0;
                break;
            }
        }

        // Use remaining k to extend from ends
        if (k > 0) {
            // Left side: first_W L's before the first W
            int left_L = first_W;
            int to_change_left = std::min(k, left_L);
            current_score += 2 * to_change_left; // Each L becomes W, adds 2 points (1 for itself, 1 for making next W consecutive)
            k -= to_change_left;

            // Right side: (n - 1 - last_W) L's after the last W
            int right_L = n - 1 - last_W;
            int to_change_right = std::min(k, right_L);
            current_score += 2 * to_change_right; // Each L becomes W, adds 2 points
            k -= to_change_right;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char move : s) {
            counts[move]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine as per problem statement.
        // R, P, S order is arbitrary but consistent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints),
        // or if there's a tie, the first one encountered in the above order wins.
        // For example, if R=2, P=2, S=1, then P would be chosen.
        // If R=2, P=1, S=2, then R would be chosen.
        // This is fine as any optimal answer is accepted.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends who get w_i = 1 numbers:
    // These friends should get the largest available numbers, as their happiness is 2 * number.
    // Since w is sorted, these are the first elements of w.
    // We assign the largest numbers from 'a' to these friends.
    int a_ptr_max = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // All w_i = 1 are processed. Break and handle w_i > 1.
            // Since w is sorted, all remaining w[i] will be > 1.
            break;
        }
    }

    // Friends who get w_i > 1 numbers:
    // These friends should get the largest available number and the smallest available number
    // from their assigned w_i numbers.
    // To maximize sum of (max_val + min_val), we should give the largest remaining 'a' values
    // to these friends as their 'max_val'.
    // We should give the smallest remaining 'a' values to these friends as their 'min_val'.
    // The 'w' values are sorted.
    // The friends with larger w_i values will "consume" more intermediate numbers,
    // leaving the smallest numbers for friends with smaller w_i values (but still > 1).
    // This means we should iterate w in descending order for w_i > 1.
    // The largest w_i will consume the most numbers, effectively pushing the 'min_val'
    // further into the sorted 'a' array.

    int a_ptr_min = 0;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            // This friend gets a[a_ptr_max] as their max_val.
            total_happiness += a[a_ptr_max];
            a_ptr_max--;

            // This friend gets a[a_ptr_min] as their min_val.
            total_happiness += a[a_ptr_min];
            a_ptr_min += (w[i] - 1); // Consume w[i]-1 intermediate numbers
        } else {
            // All w_i > 1 are processed. Break.
            // Since w is sorted, all remaining w[i] will be 1.
            break;
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Otherwise, we need to append elements.
    // We can always append 2 elements: current_xor_sum and current_sum + current_xor_sum.
    // Let's verify this strategy.
    // New elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum S' = current_sum + b1 + b2
    //            = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //            = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum X' = current_xor_sum ^ b1 ^ b2
    //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                = 0 ^ (current_sum + current_xor_sum)
    //                = current_sum + current_xor_sum
    //
    // We need S' = 2 * X'.
    // Is (2 * current_sum + 2 * current_xor_sum) == 2 * (current_sum + current_xor_sum)?
    // Yes, this is always true.
    //
    // The problem states we can append at most 3 elements.
    // This strategy uses 2 elements.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
    // The problem statement says b_i can be up to 10^18, so this is fine.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

