#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' will eventually be
            // moved past by all 'a's to its left.
            // Each 'a' to its left will effectively duplicate this 'b'
            // when it moves past it.
            // So, the number of 'a's that will eventually pass this 'b'
            // will double the number of 'b's that are effectively "available"
            // for future 'a's to pass.
            // This is equivalent to saying that each 'a' to the left of this 'b'
            // will contribute `(current_count_of_b_blocks + 1)` steps.
            // The `count_a` variable represents the number of 'a's that are
            // currently "active" and need to pass 'b's.
            // When an 'a' passes a 'b', it consumes one 'b' and creates two 'b's.
            // This means the number of 'b's available for the next 'a' effectively doubles.
            // So, if we have `count_a` 'a's, and we encounter a 'b',
            // these `count_a` 'a's will each take `count_a` steps to pass this 'b'.
            // No, this is not right.
            // Let's re-evaluate:
            // When we see a 'b', it means any 'a's to its left will eventually
            // interact with it.
            // The number of 'a's that are currently "active" (i.e., `count_a`)
            // will each need to pass this 'b'.
            // Each such 'a' passing this 'b' costs 1 step.
            // So, `count_a` steps are added to `total_steps`.
            // After these `count_a` 'a's pass this 'b', this 'b' effectively
            // turns into `2 * count_a` 'b's (one for each 'a' that passed it,
            // plus the original 'b' which is now duplicated for each 'a').
            // This means the number of 'a's that are "active" for the next 'b'
            // (to its left) effectively doubles.
            // So, `count_a` becomes `2 * count_a`.

            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' needs to pass
            // all the 'b's that are currently "active" to its right.
            // The `count_a` variable represents the number of 'a's that
            // are currently "active" and need to pass 'b's.
            // When we see a new 'a', it adds itself to this pool of active 'a's.
            // So, `count_a` increments.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequence_length = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;

        int prev_doll = -1;
        for (int j = 0; j < m; ++j) {
            int current_doll;
            std::cin >> current_doll;

            if (prev_doll != -1 && current_doll == prev_doll + 1) {
                // This is a correct nesting (prev_doll -> current_doll)
                // that contributes to the final 1 -> 2 -> ... -> n chain.
                // We count the length of such a sequence.
                correct_sequence_length++;
            }
            prev_doll = current_doll;
        }
    }

    // Total operations needed to form the final chain 1 -> 2 -> ... -> n
    // is (n-1) "put" operations.
    //
    // We save 'correct_sequence_length' operations because these dolls
    // are already nested correctly.
    //
    // For each chain, if it's not part of the 1 -> 2 -> ... -> n sequence,
    // we need to disassemble it.
    // Each chain has m_i dolls. To disassemble a chain of m_i dolls,
    // we need m_i - 1 "get out" operations.
    //
    // The total number of "get out" operations is (n - k) - correct_sequence_length.
    // (n - k) is the total number of existing nestings in the initial configuration.
    // 'correct_sequence_length' is the number of existing nestings that are correct.
    // So, (n - k) - correct_sequence_length is the number of existing nestings that are incorrect
    // and need to be undone. Each such undo costs 1 second.
    //
    // The total number of "put" operations needed is (n - 1).
    // We save 'correct_sequence_length' "put" operations because they are already done.
    // So, (n - 1) - correct_sequence_length is the number of "put" operations we still need to do.
    //
    // Total time = (operations to undo incorrect nestings) + (operations to create new correct nestings)
    // Total time = ((n - k) - correct_sequence_length) + ((n - 1) - correct_sequence_length)
    // Total time = n - k - correct_sequence_length + n - 1 - correct_sequence_length
    // Total time = 2 * n - k - 1 - 2 * correct_sequence_length

    total_operations = (long long)2 * n - k - 1 - (long long)2 * correct_sequence_length;

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // px[i] stores count of 'x' in s[0...i-1]
    std::vector<int> px(n + 1, 0);
    std::vector<int> py(n + 1, 0);
    std::vector<int> pz(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        px[i + 1] = px[i];
        py[i + 1] = py[i];
        pz[i + 1] = pz[i];
        if (s[i] == 'x') {
            px[i + 1]++;
        } else if (s[i] == 'y') {
            py[i + 1]++;
        } else { // s[i] == 'z'
            pz[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing for prefix sums
        // Substring is s[l-1 ... r-1]
        // Length of substring is r - l + 1
        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = px[r] - px[l - 1];
        int count_y = py[r] - py[l - 1];
        int count_z = pz[r] - pz[l - 1];

        // The condition for infinite loop is that the counts of 'x', 'y', 'z'
        // in the substring are too far apart.
        // Specifically, if max_count - min_count > 1, then it's impossible
        // to make all 3-char substrings have counts (1,1,1) or (2,1,0) permutations.
        // If max_count - min_count <= 1, it means the counts are either (C, C, C) or (C+1, C, C)
        // which allows for rearrangement to (1,1,1) or (2,1,0) permutations.
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) { // temp_q is a prime factor itself
        long long current_p = p;
        while (current_p % temp_q == 0 && current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string coloring(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');

        bool possible_split = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) {
                current_coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > split_digit) {
                current_coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == split_digit
                // Try to assign to color 2 first if possible
                if (!s2_digits.empty() && d[i] < s2_digits.back()) {
                    // Cannot assign to color 2, must assign to color 1
                    current_coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                } else {
                    // Assign to color 2
                    current_coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) continue;

        // If we reach here, this coloring is valid
        coloring = current_coloring;
        found_solution = true;
        break; // Found a solution, no need to check other split_digits
    }

    if (found_solution) {
        std::cout << coloring << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
