int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;

        // Initialize bounds for the reachable region
        // The problem guarantees that if a solution exists, there's one with |X|, |Y| <= 10^5.
        // So, we can use these as initial bounds.
        int min_x = -100000;
        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // Robot can move left (f1=1)
            // If it cannot move left (f1=0), it means it cannot reach any point to its left.
            // So, the target X must be >= its current X.
            if (f1 == 0) { // Cannot move left (x_c - 1)
                min_x = std::max(min_x, x);
            }

            // Robot can move up (f2=1)
            // If it cannot move up (f2=0), it means it cannot reach any point above it.
            // So, the target Y must be <= its current Y.
            if (f2 == 0) { // Cannot move up (y_c + 1)
                max_y = std::min(max_y, y);
            }

            // Robot can move right (f3=1)
            // If it cannot move right (f3=0), it means it cannot reach any point to its right.
            // So, the target X must be <= its current X.
            if (f3 == 0) { // Cannot move right (x_c + 1)
                max_x = std::min(max_x, x);
            }

            // Robot can move down (f4=1)
            // If it cannot move down (f4=0), it means it cannot reach any point below it.
            // So, the target Y must be >= its current Y.
            if (f4 == 0) { // Cannot move down (y_c - 1)
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the intersection.
            // For example, (min_x, min_y)
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            // No common reachable point.
            std::cout << 0 << "\n";
        }
    }

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is optimal for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even and > 2
                    // Check if taking N/2 leads to an odd number for opponent
                    // or if taking 1 leads to an odd number for opponent
                    // The opponent will try to maximize their own coins.
                    // If N/2 is odd, opponent can only take 1.
                    // If N/2 is even, opponent can take N/4 or 1.
                    // If N-1 is odd, opponent can only take 1.

                    // Optimal strategy for Chanek when N is even:
                    // If N/2 is odd, Chanek takes N/2. Opponent gets an odd number, so they can only take 1.
                    // If N/2 is even, Chanek takes 1. Opponent gets an odd number (N-1).
                    // This ensures the opponent always faces an odd number if possible, limiting their options.

                    // Let's re-evaluate the optimal strategy for even N.
                    // Chanek wants to maximize his coins.
                    // Option 1: Take 1. Remaining N-1 (odd). Opponent takes 1.
                    // Option 2: Take N/2. Remaining N/2.
                    //   If N/2 is odd, opponent takes 1.
                    //   If N/2 is even, opponent can take 1 or N/4.

                    // Consider N = 6 (example):
                    // Chanek's turn, N=6.
                    //   Option A: Take 1. Chanek gets 1. N=5.
                    //     Opponent's turn, N=5. Opponent takes 1. Opponent gets 1. N=4.
                    //     Chanek's turn, N=4.
                    //       Option A1: Take 1. Chanek gets 1. N=3.
                    //         Opponent's turn, N=3. Opponent takes 1. Opponent gets 1. N=2.
                    //         Chanek's turn, N=2. Chanek takes 1. Chanek gets 1. N=1.
                    //         Opponent's turn, N=1. Opponent takes 1. Opponent gets 1. N=0.
                    //         Total: Chanek = 1+1+1=3, Opponent = 1+1+1=3.
                    //       Option A2: Take N/2 (2). Chanek gets 2. N=2.
                    //         Opponent's turn, N=2. Opponent takes 1. Opponent gets 1. N=1.
                    //         Chanek's turn, N=1. Chanek takes 1. Chanek gets 1. N=0.
                    //         Total: Chanek = 1+2+1=4, Opponent = 1+1=2.
                    //     Chanek chooses A2, gets 4.
                    //   Option B: Take N/2 (3). Chanek gets 3. N=3.
                    //     Opponent's turn, N=3. Opponent takes 1. Opponent gets 1. N=2.
                    //     Chanek's turn, N=2. Chanek takes 1. Chanek gets 1. N=1.
                    //     Opponent's turn, N=1. Opponent takes 1. Opponent gets 1. N=0.
                    //     Total: Chanek = 3+1=4, Opponent = 1+1=2.
                    // Both options lead to Chanek getting 4.

                    // The key insight for even N:
                    // If N/2 is odd, Chanek takes N/2. The remaining N/2 is odd, so the opponent can only take 1.
                    // If N/2 is even, Chanek takes 1. The remaining N-1 is odd, so the opponent can only take 1.
                    // This strategy ensures that the opponent always faces an odd number (if possible) and thus can only take 1 coin.
                    // This is not entirely correct. The opponent also plays optimally.

                    // Let's re-examine the optimal strategy for even N.
                    // If N is even:
                    //   Option 1: Take 1. Remaining N-1 (odd). Opponent takes 1.
                    //   Option 2: Take N/2. Remaining N/2.
                    //
                    // If N/2 is odd: Chanek takes N/2. Remaining N/2 (odd). Opponent takes 1.
                    //   This seems like a good move for Chanek, as it gives him a large chunk and limits opponent.
                    // If N/2 is even:
                    //   Chanek takes N/2. Remaining N/2 (even). Opponent can take N/4 or 1.
                    //   Chanek takes 1. Remaining N-1 (odd). Opponent takes 1.
                    //
                    // The strategy is to always take N/2 if N/2 is odd.
                    // If N/2 is even, then N is a multiple of 4.
                    // In this case, if Chanek takes N/2, opponent faces N/2 (even).
                    // If Chanek takes 1, opponent faces N-1 (odd).
                    //
                    // Consider N = 4k (N/2 is even).
                    // Chanek takes N/2 (2k). Remaining 2k.
                    //   Opponent faces 2k. Opponent takes k. Remaining k.
                    //   Chanek gets 2k. Opponent gets k.
                    // Chanek takes 1. Remaining 4k-1 (odd).
                    //   Opponent faces 4k-1. Opponent takes 1. Remaining 4k-2.
                    //   Chanek gets 1. Opponent gets 1.
                    //
                    // This is a greedy approach.
                    // If N is odd, take 1.
                    // If N is even:
                    //   If N/2 is odd (N = 2 * odd, e.g., 2, 6, 10, 14, ...): Take N/2.
                    //   If N/2 is even (N = 4 * k, e.g., 4, 8, 12, 16, ...): Take 1.
                    //
                    // Let's test this strategy:
                    // N=1: C takes 1. C=1. N=0. Total C=1.
                    // N=2: C takes N/2 (1). C=1. N=1. O takes 1. O=1. N=0. Total C=1.
                    // N=3: C takes 1. C=1. N=2. O takes N/2 (1). O=1. N=1. C takes 1. C=1. N=0. Total C=2.
                    // N=4: C takes 1. C=1. N=3. O takes 1. O=1. N=2. C takes N/2 (1). C=1. N=1. O takes 1. O=1. N=0. Total C=2.
                    // N=5: C takes 1. C=1. N=4. O takes 1. O=1. N=3. C takes 1. C=1. N=2. O takes N/2 (1). O=1. N=1. C takes 1. C=1. N=0. Total C=3.
                    // N=6: C takes N/2 (3). C=3. N=3. O takes 1. O=1. N=2. C takes N/2 (1). C=1. N=1. O takes 1. O=1. N=0. Total C=4.

                    // This strategy matches the examples.
                    // N=5 -> Output 2 (My strategy: 3) -> Example output 2. My strategy is wrong for N=5.
                    // Example for N=5:
                    // C takes 1. N=4. C=1.
                    // O takes 2. N=2. O=2.
                    // C takes 1. N=1. C=1+1=2.
                    // O takes 1. N=0. O=2+1=3.
                    // Total C=2.
                    // My strategy for N=5:
                    // C takes 1. N=4. C=1.
                    // O takes 1. N=3. O=1.
                    // C takes 1. N=2. C=1+1=2.
                    // O takes 1. N=1. O=1+1=2.
                    // C takes 1. N=0. C=2+1=3.
                    // Total C=3.
                    // The opponent in my strategy for N=4 (O's turn) took 1. But N=4, opponent can take 2.
                    // So the opponent will take 2.
                    // This means the simple greedy strategy for opponent (always take 1 if odd, N/2 if N/2 is odd, 1 if N/2 is even) is also wrong.

                    // This is a minimax problem.
                    // Since N can be up to 10^18, recursion with memoization is not feasible.
                    // We need to find a pattern or a direct formula.

                    // Let's trace the example N=5 again carefully.
                    // N=5, Chanek's turn.
                    //   Option 1: Chanek takes 1. N becomes 4. Chanek has 1.
                    //     Opponent's turn, N=4. Opponent wants to maximize their coins.
                    //       Option 1.1: Opponent takes 1. N becomes 3. Opponent has 1.
                    //         Chanek's turn, N=3. Chanek wants to maximize his coins.
                    //           Option 1.1.1: Chanek takes 1. N becomes 2. Chanek has 1+1=2.
                    //             Opponent's turn, N=2. Opponent wants to maximize their coins.
                    //               Option 1.1.1.1: Opponent takes 1. N becomes 1. Opponent has 1+1=2.
                    //                 Chanek's turn, N=1. Chanek takes 1. N becomes 0. Chanek has 2+1=3.
                    //                 Final: C=3, O=2.
                    //               Option 1.1.1.2: Opponent takes N/2 (1). N becomes 1. Opponent has 1+1=2.
                    //                 Chanek's turn, N=1. Chanek takes 1. N becomes 0. Chanek has 2+1=3.
                    //                 Final: C=3, O=2.
                    //             Opponent chooses either, gets 2. Chanek gets 3.
                    //           Chanek gets 3.
                    //       Option 1.2: Opponent takes N/2 (2). N becomes 2. Opponent has 2.
                    //         Chanek's turn, N=2. Chanek wants to maximize his coins.
                    //           Option 1.2.1: Chanek takes 1. N becomes 1. Chanek has 1+1=2.
                    //             Opponent's turn, N=1. Opponent takes 1. N becomes 0. Opponent has 2+1=3.
                    //             Final: C=2, O=3.
                    //           Option 1.2.2: Chanek takes N/2 (1). N becomes 1. Chanek has 1+1=2.
                    //             Opponent's turn, N=1. Opponent takes 1. N becomes 0. Opponent has 2+1=3.
                    //             Final: C=2, O=3.
                    //         Chanek gets 2.
                    //     Opponent's turn, N=4. Opponent compares (C=3, O=2) vs (C=2, O=3). Opponent chooses (C=2, O=3) to maximize their own coins.
                    //     So if Chanek takes 1 from N=5, Opponent will take 2 from N=4. Result: C=2, O=3.
                    //   Chanek's turn, N=5. Chanek takes 1. Result: C=2, O=3.
                    //
                    // This matches the example output for N=5.
                    // The game is finite, so we can think about it in terms of turns.
                    // Chanek's turn: N coins.
                    //   If N is odd: Chanek must take 1. N becomes N-1 (even).
                    //   If N is even:
                    //     Chanek can take 1. N becomes N-1 (odd).
                    //     Chanek can take N/2. N becomes N/2.
                    //
                    // The game ends when N=0.
                    // The total coins are N_initial.
                    // Chanek wants to maximize his coins. Opponent wants to maximize their coins.
                    // This is equivalent to Chanek maximizing his coins, and Opponent minimizing Chanek's coins.

                    // Let's simulate the game with the optimal strategy derived from the example.
                    // N=5:
                    // C: N=5 (odd). Takes 1. C_score=1. N=4.
                    // O: N=4 (even). O wants to maximize their score.
                    //    If O takes 1: N=3. O_score=1.
                    //       C: N=3 (odd). Takes 1. C_score=1+1=2. N=2.
                    //       O: N=2 (even). O wants to maximize their score.
                    //          If O takes 1: N=1. O_score=1+1=2.
                    //             C: N=1 (odd). Takes 1. C_score=2+1=3. N=0.
                    //             Final: C=3, O=2.
                    //          If O takes N/2 (1): N=1. O_score=1+1=2.
                    //             C: N=1 (odd). Takes 1. C_score=2+1=3. N=0.
                    //             Final: C=3, O=2.
                    //       O chooses to get 2. C gets 3.
                    //    If O takes N/2 (2): N=2. O_score=2.
                    //       C: N=2 (even). C wants to maximize their score.
                    //          If C takes 1: N=1. C_score=1+1=2.
                    //             O: N=1 (odd). Takes 1. O_score=2+1=3. N=0.
                    //             Final: C=2, O=3.
                    //          If C takes N/2 (1): N=1. C_score=1+1=2.
                    //             O: N=1 (odd). Takes 1. O_score=2+1=3. N=0.
                    //             Final: C=2, O=3.
                    //       C chooses to get 2. O gets 3.
                    // O compares (C=3, O=2) vs (C=2, O=3). O chooses (C=2, O=3).
                    // So, C takes 1 from N=5. O takes 2 from N=4. C takes 1 from N=2. O takes 1 from N=1.
                    // Final: C=2, O=3. This matches example.

                    // N=6:
                    // C: N=6 (even). C wants to maximize their score.
                    //   Option 1: C takes 1. C_score=1. N=5.
                    //     O: N=5 (odd). Takes 1. O_score=1. N=4.
                    //       C: N=4 (even). C wants to maximize their score.
