#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operations 2 and 3: Do nothing
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // Select segment [1, n-1] (0-indexed: [0, n-2])
        // Length is n-1.
        // For each a[i] in this segment, we want to add b_i such that (a[i] + b_i) % n == 0.
        // b_i must be a multiple of n-1.
        // We can choose b_i = (n - (a[i] % n) % n) % n * (n-1).
        // This makes a[i] % n == 0.
        // No, this is not correct. We need a[i] + b_i to be divisible by n.
        // And b_i must be divisible by (n-1).
        // This is the tricky part.
        // Let's use the strategy:
        // 1. For elements a[0] to a[n-2]:
        //    Select segment [1, n-1] (0-indexed: [0, n-2]). Length is n-1.
        //    For each a[i] in this segment, we want to add b_i such that a[i] + b_i is divisible by n.
        //    And b_i must be a multiple of (n-1).
        //    Let target_val = a[i] + b_i. We want target_val % n == 0.
        //    We know b_i = k * (n-1) for some integer k.
        //    So a[i] + k * (n-1) must be divisible by n.
        //    a[i] + k * (-1) must be divisible by n (since n-1 = -1 mod n).
        //    a[i] - k must be divisible by n.
        //    So k must be congruent to a[i] mod n.
        //    We can choose k = a[i] % n. If a[i] % n is negative, add n. So k = (a[i] % n + n) % n.
        //    Then b_i = k * (n-1).
        //    After this operation, a[i] becomes a[i] + b_i, which is divisible by n.

        std::cout << 1 << " " << n - 1 << "\n"; // Segment [0, n-2]
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // a[i] mod n, always non-negative
            long long k = remainder; // k = a[i] mod n
            long long b_i = k * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] divisible by n
        // Select segment [n, n] (0-indexed: [n-1, n-1]). Length is 1.
        // For a[n-1], we want to add b_{n-1} such that a[n-1] + b_{n-1} is divisible by n.
        // b_{n-1} must be a multiple of 1.
        // We can choose b_{n-1} = (n - (a[n-1] % n) % n) % n.
        // This makes a[n-1] % n == 0.
        // No, this is not correct. We want a[n-1] + b_{n-1} to be 0.
        // We can add -a[n-1] to a[n-1]. This is a multiple of 1.
        // But we need to make it divisible by n.
        // The strategy is to make all elements divisible by n first.
        // Then in the third step, make them all zero.

        std::cout << n << " " << n << "\n"; // Segment [n-1, n-1]
        long long remainder_n_minus_1 = (a[n - 1] % n + n) % n;
        long long b_n_minus_1 = remainder_n_minus_1; // b_i must be multiple of 1.
        std::cout << b_n_minus_1 << "\n";
        a[n - 1] += b_n_minus_1; // Update a[n-1]
        // Now all a[i] are divisible by n.

        // Operation 3: Make all elements zero
        // Select segment [1, n] (0-indexed: [0, n-1]). Length is n.
        // For each a[i], we want to add b_i such that a[i] + b_i = 0.
        // b_i must be a multiple of n.
        // Since all a[i] are already divisible by n, we can choose b_i = -a[i].
        // -a[i] is a multiple of n.
        std::cout << 1 << " " << n << "\n"; // Segment [0, n-1]
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    // Calculate prefix sums for the right side (from n to 2n-1)
    // Suffix sums for the right side, but calculated as prefix sums from n to 2n-1
    // right_sums[k] = sum of a[n]...a[n+k-1]
    // This means right_sums[0] = 0 (no jars removed from right)
    // right_sums[1] = a[n] (jar n+1 in 1-indexed)
    // right_sums[k] = sum of a[n]...a[n+k-1]
    std::vector<int> right_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_sums[i + 1] = right_sums[i] + a[n + i];
    }

    // Store the first occurrence of each sum value for the right side
    // map: sum_value -> number of jars removed from right (k)
    std::map<int, int> right_sum_to_k;
    for (int k = 0; k <= n; ++k) {
        if (right_sum_to_k.find(right_sums[k]) == right_sum_to_k.end()) {
            right_sum_to_k[right_sums[k]] = k;
        }
    }

    // Calculate prefix sums for the left side (from n-1 down to 0)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    // This means left_sums[0] = 0 (no jars removed from left)
    // left_sums[1] = a[n-1] (jar n in 1-indexed)
    // left_sums[j] = sum of a[n-1]...a[n-j]
    std::vector<int> left_sums(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_sums[i + 1] = left_sums[i] + a[n - 1 - i];
    }

    int min_removed = 2 * n; // Initialize with maximum possible jars removed

    // Iterate through all possible numbers of jars removed from the left (j)
    for (int j = 0; j <= n; ++j) {
        int current_left_sum = left_sums[j];
        // We need the remaining jars to have a sum of -current_left_sum
        // This means the sum of jars from the right side (right_sums[k]) should be -current_left_sum
        int target_right_sum = -current_left_sum;

        if (right_sum_to_k.count(target_right_sum)) {
            int k = right_sum_to_k[target_right_sum];
            min_removed = std::min(min_removed, j + k);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
        // This is achieved by distributing the '0's as evenly as possible.
        // The 'm' ones divide the string into 'm + 1' potential blocks of zeros.
        // Let k be the number of blocks of zeros.
        // If m > 0, we can always place ones such that there are m+1 blocks of zeros (some might be empty).
        // For example, 10101 has m=3, n=5. Zeros: n-m = 2. Blocks: m+1 = 4.
        // The zeros are distributed into these m+1 blocks.
        // Number of blocks with floor(num_zeros / (m + 1)) zeros
        // Number of blocks with ceil(num_zeros / (m + 1)) zeros

        long long k = m + 1; // Number of segments where zeros can be placed

        long long q = num_zeros / k; // Minimum number of zeros in a segment
        long long r = num_zeros % k; // Number of segments that get one extra zero

        // Number of segments with q+1 zeros
        long long segments_q_plus_1 = r;
        // Number of segments with q zeros
        long long segments_q = k - r;

        // Calculate the number of substrings consisting only of '0's
        // For a block of 'x' zeros, there are x * (x + 1) / 2 such substrings.
        long long zero_substrings_count = 0;

        // Segments with q zeros
        if (q > 0) { // Only count if there are actual zeros in these segments
            zero_substrings_count += segments_q * (q * (q + 1) / 2);
        }

        // Segments with q+1 zeros
        if (q + 1 > 0) { // Only count if there are actual zeros in these segments
            zero_substrings_count += segments_q_plus_1 * ((q + 1) * (q + 2) / 2);
        }

        // The maximum value of f(s) is total_substrings - zero_substrings_count
        std::cout << total_substrings - zero_substrings_count << "\n";
    }
    return 0;
}

