            best_partition[elements[i].original_index] = 1;
        }
    }

    // Sub-strategy B: elements[0] in S1, elements[n-1] in S2. All other elements in S1.
    // S1: {elements[0], elements[1], ..., elements[n-2]}
    // S2: {elements[n-1]}
    //
    // The values of f are:
    // 1. elements[0] + elements[n-1] + h (different)
    // 2. elements[i] + elements[j] (same, i, j <= n-2)
    //
    // The minimum f value will be min(elements[0] + elements[n-1] + h, elements[0] + elements[1]).
    // The maximum f value will be max(elements[0] + elements[n-1] + h, elements[n-2] + elements[n-3] (if n>=3)).
    //
    // Let's calculate goodness for this specific partition:
    // Partition: elements[0...n-2] -> 1, elements[n-1] -> 2.
    long long current_min_f_B;
    long long current_max_f_B;

    if (n == 2) {
        current_min_f_B = elements[0].value + elements[1].value + h;
        current_max_f_B = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        current_min_f_B = std::min(elements[0].value + elements[n-1].value + h, elements[0].value + elements[1].value);
        current_max_f_B = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-3].value);
    }

    long long goodness_B = current_max_f_B - current_min_f_B;

    if (goodness_B < min_goodness) {
        min_goodness = goodness_B;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[elements[i].original_index] = 1;
        }
        best_partition[elements[n-1].original_index] = 2;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

