#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v, d, p;
    int original_index;
    bool is_removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].is_removed = false;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].is_removed) {
            continue;
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_index);
        children[i].is_removed = true;

        long long current_v_cry = children[i].v;
        long long d_cry_sum = 0; // Accumulates d_j cries from children leaving

        for (int j = i + 1; j < n; ++j) {
            if (children[j].is_removed) {
                continue;
            }

            // Apply d_cry_sum first (from previous children who left)
            children[j].p -= d_cry_sum;

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].is_removed = true;
                d_cry_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

