#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers of the form 2k where k is odd,
        // specifically 2 * (2i + 1) for i = 0, 1, ..., n-1.
        // This gives numbers 2, 6, 10, 14, ...
        // However, the problem statement example for n=3 gives 4 6 10.
        // And for n=4 gives 14 10 12 8.
        // This suggests picking numbers that are multiples of 2, but not multiples of 4,
        // or numbers that are multiples of 4.
        // Let's re-evaluate the example outputs.
        // n=2: 6 4. Both are even. gcd(6,4)=2. 4 does not divide 6, 6 does not divide 4. OK.
        // n=3: 4 6 10. All are even. gcd(4,6)=2, gcd(4,10)=2, gcd(6,10)=2.
        //      4 does not divide 6, 6 does not divide 4.
        //      4 does not divide 10, 10 does not divide 4.
        //      6 does not divide 10, 10 does not divide 6. OK.
        // n=4: 14 10 12 8. All are even. gcd(a,b) is always >= 2.
        //      8 does not divide 10, 10 does not divide 8.
        //      8 does not divide 12, 12 does not divide 8.
        //      8 does not divide 14, 14 does not divide 8.
        //      10 does not divide 12, 12 does not divide 10.
        //      10 does not divide 14, 14 does not divide 10.
        //      12 does not divide 14, 14 does not divide 12. OK.

        // The common property of the example outputs is that all chosen numbers are even.
        // This guarantees gcd(a,b) >= 2, so gcd(a,b) != 1.
        // We also need to ensure that 'a does not divide b' and 'b does not divide a'.
        // A simple way to achieve this is to pick numbers that are all greater than 2n
        // and less than or equal to 4n, and are even.
        // If we pick numbers from the range (2n, 4n], and they are all even,
        // then for any two chosen numbers a, b:
        // 2n < a <= 4n
        // 2n < b <= 4n
        // If a divides b, then b = k*a for some integer k.
        // Since a < b, k must be >= 2.
        // But if k >= 2, then b = k*a >= 2*a > 2*(2n) = 4n.
        // This contradicts b <= 4n.
        // Therefore, no number in the range (2n, 4n] can divide another number in the same range.
        // So, we just need to pick n distinct even numbers from (2n, 4n].
        // The available even numbers are 2n+2, 2n+4, ..., 4n.
        // The count of these numbers is (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n.
        // So there are exactly n such even numbers.
        // We can simply print them all.

        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + i + 1) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

