#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only consider numbers up to 2048
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of 'val' to the current_sum.
        // Each 'val' contributes 'val * count' to the total sum,
        // but we only care about the sum up to 2048.
        // If current_sum + val * count exceeds 2048, we cap it at 2048.
        // This is equivalent to saying we have enough 'val's to form 2048
        // or contribute to it.
        current_sum += val * count;
        if (current_sum >= 2048) {
            std::cout << "YES\n";
            return;
        }
    }

    std::cout << "NO\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // We need to reach total_sticks_required sticks starting from 1 stick.
        // The number of sticks we need to "generate" is total_sticks_required - 1.
        // Let num_stick_trades be the number of times we use the first trade offer.
        // (num_stick_trades * (x - 1)) >= (total_sticks_required - 1)
        // num_stick_trades = ceil((total_sticks_required - 1) / (x - 1))
        long long num_stick_trades = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = trades to get enough sticks + trades to get enough coal
        // Trades to get enough sticks = num_stick_trades
        // Trades to get enough coal = k (since 1 trade gives 1 coal)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

