#include <iostream>
#include <vector>
#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_videos_count = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_duration) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_found++;
        } else if (current_post_sum > target_duration) {
            // If at any point the current post sum exceeds the target, no solution.
            std::cout << "No\n";
            return 0;
        }
    }

    // After iterating through all videos, we should have exactly k posts.
    // The last post's sum should have exactly matched target_duration.
    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_post_sum > target_duration
        // or if total_sum % k != 0, but as a safeguard.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it should be n.
    // This handles the case where n is the largest value in the permutation.
    // If p_i = n, then min(p_i, p_j) = p_j for all j != i.
    // The maximum of these p_j values would be n-1.
    // So, if max_val_in_row is n-1, it means p_i must be n.
    // If no p_i is n, then the largest value in the permutation is n-1,
    // which is impossible as it's a permutation of 1 to n.
    // Thus, exactly one p_i must be n.
    bool found_n_minus_1 = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            found_n_minus_1 = true;
            break;
        }
    }

    if (found_n_minus_1) {
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such element can be n
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

