                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }

        // After iterating through the string, consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The distance is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
