#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_elements.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q[i] is a new maximum, then p[i] must be q[i]
            p[i] = q[i];
            if (used_elements.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But as a safety check for permutation validity
                possible = false;
                break;
            }
            used_elements.insert(q[i]);
        } else {
            // If q[i] == q[i-1], then p[i] must be some value <= q[i-1]
            // and not yet used. We want to pick the smallest available value
            // to maximize chances for future elements.
            p[i] = -1; // Placeholder
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_elements.find(i) == used_elements.end()) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort descending for easy pop_back

    // Fill in the remaining p[i] values
    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q[i] == q[i-1]
            if (available_numbers.empty()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int val_to_assign = available_numbers.back();
            available_numbers.pop_back();

            if (val_to_assign > q[i]) { // p[i] must be <= q[i] (which is q[i-1])
                possible = false;
                break;
            }
            p[i] = val_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

