int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int current_val = 1;
    int max_val = k + 1; // The largest value we will use for the alternating part

    // Construct the first k+1 elements to generate k distinct differences
    // This part generates differences 1, 2, ..., k
    // Example for k=3: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}
    int left = 1;
    int right = k + 1;
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smaller)
            p[i] = left++;
        } else { // Odd index, take from right (larger)
            p[i] = right--;
        }
    }

    // The remaining elements are simply increasing from k+2 to n
    // This ensures that subsequent differences are 1, which are already covered
    // by the first part (e.g., |2-3|=1 in the example above).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

