bool is_good(const std::vector<int>& a, int start_idx) {
    int n = a.size();
    if (start_idx >= n) { // Empty array or single element array
        return true;
    }

    // Find the first decreasing point from the right
    int i = n - 1;
    while (i > start_idx && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i == start_idx, the whole suffix is non-decreasing, which is good.
    // If i > start_idx, then a[i-1] > a[i]. This is the first "dip" from the right.

    // Find the first increasing point from the left (of the remaining part)
    int j = start_idx;
    while (j < i && a[j] >= a[j+1]) {
        j++;
    }
    // Now a[start_idx...j] is non-increasing.
    // If j == i, then a[start_idx...i] is non-increasing.
    // If j < i, then a[j] < a[j+1]. This is the first "rise" from the left.

    // If j == i, it means the segment a[start_idx...i] is non-increasing.
    // Combined with a[i...n-1] being non-decreasing, this forms a "valley" shape.
    // The condition for being good is that the entire remaining segment
    // can be partitioned into a non-increasing prefix and a non-decreasing suffix.
    // The point 'i' marks the start of the non-decreasing suffix from the right.
    // The point 'j' marks the end of the non-increasing prefix from the left.
    // If j < i, it means there's a "peak" or "valley" in between that cannot be resolved.
    // For example, [..., 5, 4, 3, 2, 3, 4, 5, ...]
    // Here, i would be 2 (index of 2), j would be 3 (index of 2).
    // The condition for being good is that the entire segment from start_idx to n-1
    // must be representable as a non-increasing sequence followed by a non-decreasing sequence.
    // This means that after finding the first decreasing point from the right (i),
    // the remaining prefix a[start_idx ... i-1] must be non-increasing.

    // The loop for 'i' finds the first index from the right such that a[i-1] > a[i].
    // So, a[i], a[i+1], ..., a[n-1] is non-decreasing.
    // For the array to be good, the prefix a[start_idx], ..., a[i-1] must be non-increasing.
    // We check this by iterating from start_idx up to i-1.

    int k = start_idx;
    while (k < i && a[k] >= a[k+1]) {
        k++;
    }
    // If k reaches i, it means a[start_idx...i-1] is non-increasing.
    // If k < i, it means a[k] < a[k+1], which breaks the non-increasing property.
    return k == i;
}

