int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Current position i is a mismatch
            // Check if the next position i+1 is also a mismatch
            // AND if a[i] and a[i+1] are different, and b[i] and b[i+1] are different
            // This implies a[i] != b[i] and a[i+1] != b[i+1]
            // AND a[i] == b[i+1] and a[i+1] == b[i]
            // Example: a = "01", b = "10"
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] == b[i+1] && a[i+1] == b[i]) {
                // We can swap a[i] and a[i+1] to fix both positions
                // Cost is |(i+1) - i| = 1
                total_cost += 1;
                i += 2; // Both positions i and i+1 are now fixed
            } else {
                // Cannot perform a beneficial swap with i+1, or i+1 is out of bounds
                // or the conditions for a beneficial swap are not met.
                // The only option is to flip a[i]. Cost is 1.
                total_cost += 1;
                i += 1; // Position i is fixed
            }
        } else {
            // Position i is already correct, move to the next
            i += 1;
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

