// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: x <= -1 (Negative, |x| >= 1)
    // Final toy must be negative and have magnitude >= 1.

    // Case 1: Final toy is negative.
    // This requires an odd number of initial negative toys (A + B).
    // If (A + B) is even, the final toy will be positive.
    if ((A + B) % 2 == 0) {
        return false; // Final toy must be positive
    }

    // Case 2: Final toy has magnitude >= 1.
    // This is the tricky part. We need to ensure we can make the magnitude large enough.
    // If there are any toys in Box 1 or Box 4, we can potentially make the magnitude large.
    // If there are no toys in Box 1 or Box 4, all initial toys have magnitude < 1.
    // In this case, the product of any number of such toys will always have magnitude < 1.
    // So, if A=0 and D=0, the final toy's magnitude will be < 1, and it cannot be in Box 1.
    if (A == 0 && D == 0) {
        return false;
    }

    // If (A+B) is odd and (A+D > 0), it's generally possible.
    // The only edge case is if A+B+C+D == 1.
    // If A+B+C+D == 1, and the single toy is in Box 1, then it's possible.
    if (A + B + C + D == 1) {
        return A == 1;
    }

    // Otherwise, if (A+B) is odd and (A+D > 0), it's always possible.
    // We can always arrange multiplications to keep magnitude >= 1 if A+D > 0,
    // and control the sign to be negative if A+B is odd.
    return true;
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: -1 < x < 0 (Negative, 0 < |x| < 1)
    // Final toy must be negative and have magnitude < 1.

    // Case 1: Final toy is negative.
    // This requires an odd number of initial negative toys (A + B).
    if ((A + B) % 2 == 0) {
        return false; // Final toy must be positive
    }

    // Case 2: Final toy has magnitude < 1.
    // This is generally possible if we have enough toys with magnitude < 1 (B or C).
    // If A+B+C+D == 1, and the single toy is in Box 2, then it's possible.
    if (A + B + C + D == 1) {
        return B == 1;
    }

    // If there are no toys in B or C, and A+D > 0, it's hard to guarantee magnitude < 1.
    // However, we can always make magnitude < 1 if we have at least one toy from B or C.
    // If B+C > 0, we can always multiply by a small number at the end.
    // If B+C == 0, then all toys are from A or D. Their product will have magnitude >= 1.
    // So, if B+C == 0, it's impossible to get magnitude < 1.
    if (B == 0 && C == 0) {
        return false;
    }

    // Otherwise, if (A+B) is odd and (B+C > 0), it's always possible.
    // We can always arrange multiplications to keep magnitude < 1 if B+C > 0,
    // and control the sign to be negative if A+B is odd.
    return true;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: 0 < x < 1 (Positive, 0 < |x| < 1)
    // Final toy must be positive and have magnitude < 1.

    // Case 1: Final toy is positive.
    // This requires an even number of initial negative toys (A + B).
    if ((A + B) % 2 != 0) {
        return false; // Final toy must be negative
    }

    // Case 2: Final toy has magnitude < 1.
    // If A+B+C+D == 1, and the single toy is in Box 3, then it's possible.
    if (A + B + C + D == 1) {
        return C == 1;
    }

    // If B+C == 0, then all toys are from A or D. Their product will have magnitude >= 1.
    // So, if B+C == 0, it's impossible to get magnitude < 1.
    if (B == 0 && C == 0) {
        return false;
    }

    // Otherwise, if (A+B) is even and (B+C > 0), it's always possible.
    // We can always arrange multiplications to keep magnitude < 1 if B+C > 0,
    // and control the sign to be positive if A+B is even.
    return true;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: x >= 1 (Positive, |x| >= 1)
    // Final toy must be positive and have magnitude >= 1.

    // Case 1: Final toy is positive.
    // This requires an even number of initial negative toys (A + B).
    if ((A + B) % 2 != 0) {
        return false; // Final toy must be negative
    }

    // Case 2: Final toy has magnitude >= 1.
    // If A+B+C+D == 1, and the single toy is in Box 4, then it's possible.
    if (A + B + C + D == 1) {
        return D == 1;
    }

    // If A == 0 and D == 0, all initial toys have magnitude < 1.
    // In this case, the product of any number of such toys will always have magnitude < 1.
    // So, if A=0 and D=0, the final toy's magnitude will be < 1, and it cannot be in Box 4.
    if (A == 0 && D == 0) {
        return false;
    }

    // Otherwise, if (A+B) is even and (A+D > 0), it's always possible.
    // We can always arrange multiplications to keep magnitude >= 1 if A+D > 0,
    // and control the sign to be positive if A+B is even.
    return true;
}

