        // for a potential triplet (x[i], x[j], x[k]).
        // If right_ptr is less than i+2, it means there aren't enough points to form a triplet
        // starting with x[i] and ending at right_ptr.
        // We need at least x[i], x[i+1], x[i+2]. So k must be at least i+2.
        right_ptr = std::max(right_ptr, i + 2);

        // Move right_ptr forward as long as the condition x[right_ptr] - x[i] <= d holds
        // and right_ptr is within bounds.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }

        // At this point, right_ptr is the first index such that x[right_ptr] - x[i] > d,
        // OR right_ptr == n.
        // All points from x[i+2] up to x[right_ptr-1] can be the third point (k).
        // The number of such points is (right_ptr - 1) - (i + 2) + 1 = right_ptr - i - 2.
        // Let's call this number 'm'.
        // These 'm' points are x[i+2], x[i+3], ..., x[right_ptr-1].
        // For each such x[k], we need to choose one point x[j] such that i < j < k.
        // The number of choices for x[j] is k - (i + 1).
        // This is equivalent to choosing 2 points from the range (i, k].
        // The number of points in the range (i, k] (exclusive of i, inclusive of k) is k - i.
        // We need to choose 2 points from these k-i points.
        // The number of ways to choose 2 points from N items is N * (N - 1) / 2.
        // Here, N = (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // So, N = (right_ptr - 1) - (i + 1) + 1 = right_ptr - i - 1.
        // The number of points available for j and k (excluding i) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - i - 1.
        // Let num_available_for_j_k = right_ptr - i - 1.
        // If num_available_for_j_k >= 2, then we can choose 2 points from them.
        // The number of ways to choose 2 points from num_available_for_j_k is
        // num_available_for_j_k * (num_available_for_j_k - 1) / 2.

        long long num_points_in_range = right_ptr - i - 1; // Number of points x[j] and x[k] that can be chosen after x[i]
                                                           // and satisfy x[k] - x[i] <= d.
                                                           // These points are x[i+1], ..., x[right_ptr-1].

        if (num_points_in_range >= 2) {
            count += num_points_in_range * (num_points_in_range - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

