    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array, this is the middle element

    // Operations for elements before the median (inclusive)
    // These elements must be <= s
    for (int i = 0; i <= median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements after the median (exclusive)
    // These elements must be >= s
    for (int i = median_idx; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order based on value, but keep original indices
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we pair A[i] with B[i].
    // However, we need to output A' in the original order of B.
    // So, we need to store the result in an array indexed by B's original positions.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[i].value is the i-th smallest value from original A.
        // b_elements[i].original_index is the original index of the i-th smallest value from original B.
        // We want to assign the i-th largest A value to the position corresponding to the i-th largest B value.
        // Since both are sorted ascending, a_elements[i] is the i-th smallest A value.
        // b_elements[i] is the i-th smallest B value.
        // To maximize sum(F(A'_i, B_i)), we need to pair largest A with largest B, etc.
        // So, the largest A value (a_elements[m-1]) should be paired with the B value that was originally at b_elements[m-1].original_index.
        // The second largest A value (a_elements[m-2]) should be paired with the B value that was originally at b_elements[m-2].original_index.
        // In general, a_elements[m-1-i] (the (i+1)-th largest A value) should be paired with the B value
        // that was originally at b_elements[m-1-i].original_index.
        // This means result_a_prime[b_elements[m-1-i].original_index] = a_elements[m-1-i].value.
        // Or, equivalently, result_a_prime[b_elements[i].original_index] = a_elements[i].value.
        // Let's re-evaluate.
        // We want to pair (A_sorted[k], B_sorted[k]) for all k.
        // The B_sorted[k] value was originally at index B_elements[k].original_index.
        // So, A'_at_original_B_index[B_elements[k].original_index] = A_sorted[k].value.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of its length
// This version uses a frequency array and checks max value
bool is_permutation_check(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len <= 0) return false; // Permutations must have non-zero length
    if (end_idx - start_idx + 1 != expected_len) return false; // Length mismatch

    std::vector<bool> seen(expected_len + 1, false);
    int max_val = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] <= 0 || arr[i] > expected_len) {
            return false; // Value out of range [1, expected_len]
        }
        if (seen[arr[i]]) {
            return false; // Duplicate value
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }

    // All values from 1 to expected_len must be present
    // This is implicitly checked by max_val == expected_len and no duplicates
    // If max_val is less than expected_len, then some number is missing.
    // If max_val is equal to expected_len, and no duplicates, and all numbers are in range [1, expected_len],
    // then it must be a permutation.
    return max_val == expected_len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix and suffix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i-1], a[i]);
    }

    std::vector<int> max_suffix(n);
    max_suffix[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i+1], a[i]);
    }

    // Precompute prefix and suffix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[k] means a[0...k-1] is a perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k-1];
        if (!possible_prefix || val <= 0 || val > k || seen_prefix[val]) {
            possible_prefix = false;
        } else {
            seen_prefix[val] = true;
            current_max_prefix = std::max(current_max_prefix, val);
            if (current_max_prefix == k) {
                is_prefix_perm[k] = true;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[k] means a[n-k...n-1] is a perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[n-k];
        if (!possible_suffix || val <= 0 || val > k || seen_suffix[val]) {
            possible_suffix = false;
        } else {
            seen_suffix[val] = true;
            current_max_suffix = std::max(current_max_suffix, val);
            if (current_max_suffix == k) {
                is_suffix_perm[k] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of p1, so p1 is a[0...l1-1]
    // l2 is the length of p2, so p2 is a[l1...n-1]
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if p1 is a permutation of length l1
        // This requires max_prefix[l1-1] == l1 and no duplicates in a[0...l1-1]
        // The precomputed is_prefix_perm[l1] handles this.
        if (!is_prefix_perm[l1]) {
            continue;
        }

        // Check if p2 is a permutation of length l2
        // This requires max_suffix[l1] == l2 and no duplicates in a[l1...n-1]
        // The precomputed is_suffix_perm[l2] handles this.
        if (!is_suffix_perm[l2]) {
            continue;
        }

        results.push_back({l1, l2});
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

