#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        long long current_score = 0;
        int initial_wins = 0;
        bool first_win_found = false;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i-1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
                first_win_found = true;
            }
        }

        if (initial_wins == 0) {
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (k - 1) << "\n";
            }
            continue;
        }

        // If k is large enough to turn all Ls into Ws
        if (initial_wins + k >= n) {
            std::cout << 1 + 2 * (n - 1) << "\n";
            continue;
        }

        // Strategy:
        // 1. Fill gaps between existing Ws. This creates 2 points per L.
        // 2. Extend existing W sequences. This creates 2 points per L.
        // 3. Create new Ws. This creates 1 point per L.

        // Collect lengths of L-segments between Ws
        std::vector<int> gap_lengths;
        int current_gap = 0;
        bool in_gap = false;
        int first_W_idx = -1;
        int last_W_idx = -1;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W_idx == -1) first_W_idx = i;
                last_W_idx = i;
            }
        }

        if (first_W_idx != -1) { // There is at least one 'W'
            for (int i = first_W_idx; i <= last_W_idx; ++i) {
                if (s[i] == 'L') {
                    current_gap++;
                    in_gap = true;
                } else { // s[i] == 'W'
                    if (in_gap) {
                        gap_lengths.push_back(current_gap);
                        current_gap = 0;
                        in_gap = false;
                    }
                }
            }
        }

        std::sort(gap_lengths.begin(), gap_lengths.end());

        // Fill gaps
        for (int gap_len : gap_lengths) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len; // Each L in gap becomes W, adding 2 points
            } else {
                current_score += 2 * k;
                k = 0;
                break;
            }
        }

        // Extend W sequences (from ends)
        // Count Ls at the beginning and end
        int prefix_L = 0;
        for (int i = 0; i < first_W_idx; ++i) {
            if (s[i] == 'L') prefix_L++;
        }
        int suffix_L = 0;
        for (int i = last_W_idx + 1; i < n; ++i) {
            if (s[i] == 'L') suffix_L++;
        }

        // Prioritize extending from the right (last_W_idx) if possible, as it adds 2 points per L.
        // Then from the left (first_W_idx), which also adds 2 points per L.
        // The order doesn't matter for points, only for k.

        // Extend from right
        if (k > 0 && suffix_L > 0) {
            long long to_change = std::min((long long)suffix_L, k);
            current_score += 2 * to_change;
            k -= to_change;
        }

        // Extend from left
        if (k > 0 && prefix_L > 0) {
            long long to_change = std::min((long long)prefix_L, k);
            current_score += 2 * to_change;
            k -= to_change;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w to process friends who need 1 item first, then those who need more

    long long total_happiness = 0;

    // First, handle friends who need exactly 1 item.
    // They will get one of the largest remaining numbers, and their happiness is that number + itself.
    // These are the friends with w_i = 1.
    // Since w is sorted, these will be at the beginning of w.
    // We assign the largest available numbers to these friends.
    int a_ptr_max = n - 1;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_max] * 2;
            a_ptr_max--;
        } else {
            // Since w is sorted, all subsequent w[i] will be > 1.
            // We can break here and handle the rest.
            break;
        }
    }

    // Now, handle friends who need more than 1 item (w_i > 1).
    // These friends will get one of the largest remaining numbers as their max_val.
    // And one of the smallest remaining numbers as their min_val.
    // We iterate through w in reverse order (largest w_i first) to assign the largest remaining numbers
    // as max_val to friends who need more items.
    // The smallest remaining numbers will be assigned as min_val.
    int a_ptr_min = 0;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            // This friend gets a[a_ptr_max] as their maximum.
            total_happiness += a[a_ptr_max];
            a_ptr_max--;

            // This friend needs w[i] - 1 additional items.
            // The smallest of these w[i] items will be the minimum for this friend.
            // We assign a[a_ptr_min] as the minimum.
            total_happiness += a[a_ptr_min];
            a_ptr_min += (w[i] - 1); // Move a_ptr_min past the w[i]-1 smallest items used
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

