#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // can form an "ab" pair with this 'b'.
            // Each such 'a' will eventually "pass" this 'b'.
            // When an 'a' passes a 'b', it generates 2 new 'b's.
            // So, the number of 'a's that need to pass this 'b'
            // effectively doubles for the next 'b' to its left.
            // The current 'a_count' represents the number of 'a's
            // that are currently "active" and need to pass 'b's to their right.
            // When an 'a' passes a 'b', it contributes to the total steps.
            // The number of steps contributed by this 'b' is the current 'a_count'.
            total_steps = (total_steps + a_count) % mod;

            // After an 'a' passes this 'b', it effectively generates two new 'b's.
            // This means for any 'b' further to the left, the number of 'a's
            // that need to pass it effectively doubles.
            // So, we double the 'a_count' for the next iteration (moving left).
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now active
            // and needs to pass any 'b's to its right.
            // We increment the 'a_count'.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_reconstructed[i] = '1';
        } else {
            s_reconstructed[i] = '0';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

