#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 0;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long operations = 0;
    int correct_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Check if the first element of the chain is 1
        if (chain[0] == 1) {
            // Count how many consecutive correct pairs (j, j+1) exist starting from 1
            int current_correct_in_chain = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    current_correct_in_chain++;
                } else {
                    break; // Sequence 1, 2, 3... is broken
                }
            }
            correct_pairs = current_correct_in_chain;
        }
    }

    // Total operations needed:
    // 1. Disassemble all existing chains:
    //    Each chain of length m_i has m_i - 1 internal nestings.
    //    To disassemble these, we need m_i - 1 'get out' operations.
    //    Sum of (m_i - 1) over all chains = (sum of m_i) - k = n - k.
    //    This is the number of 'get out' operations.
    // 2. Assemble the final chain 1 -> 2 -> ... -> n:
    //    This requires n - 1 'put in' operations.
    //
    // Total operations = (n - k) + (n - 1)
    //
    // However, we can save operations if parts of the final chain 1 -> 2 -> ... -> n
    // are already correctly formed and positioned.
    // The only part that can be directly reused is the prefix 1 -> 2 -> ... -> `correct_pairs`.
    //
    // If we have `correct_pairs` dolls already in the sequence 1 -> 2 -> ... -> `correct_pairs`,
    // then `correct_pairs - 1` nesting operations are already done.
    // These `correct_pairs - 1` operations do not need to be disassembled (get out)
    // and do not need to be re-assembled (put in).
    //
    // So, we save `(correct_pairs - 1)` 'get out' operations and `(correct_pairs - 1)` 'put in' operations.
    //
    // The number of 'get out' operations needed is (n - k) - (correct_pairs - 1).
    // (n - k) is the total number of existing nestings.
    // (correct_pairs - 1) is the number of existing nestings in the 1->2->... prefix.
    //
    // The number of 'put in' operations needed is (n - 1) - (correct_pairs - 1).
    // (n - 1) is the total number of nestings in the final chain.
    // (correct_pairs - 1) is the number of nestings already present in the 1->2->... prefix.
    //
    // Total operations = [(n - k) - (correct_pairs - 1)] + [(n - 1) - (correct_pairs - 1)]
    //                  = n - k - correct_pairs + 1 + n - 1 - correct_pairs + 1
    //                  = 2*n - k - 2*correct_pairs + 1
    //
    // Let's re-evaluate:
    // Total 'put in' operations required for 1->...->n is (n-1).
    // Of these, `correct_pairs - 1` are already done. So, `(n-1) - (correct_pairs - 1)` new 'put in' operations are needed.
    //
    // Total 'get out' operations required to break all existing non-prefix nestings.
    // There are `n-k` existing nestings in total across all chains.
    // `correct_pairs - 1` of these are part of the desired prefix and don't need to be broken.
    // So, `(n-k) - (correct_pairs - 1)` 'get out' operations are needed.
    //
    // Total operations = ( (n - 1) - (correct_pairs - 1) ) + ( (n - k) - (correct_pairs - 1) )
    //                  = (n - correct_pairs) + (n - k - correct_pairs + 1)
    //                  = 2*n - k - 2*correct_pairs + 1

    operations = (long long)(n - correct_pairs) + (long long)(n - k - correct_pairs + 1);

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_val = 0; pivot_val <= 9; ++pivot_val) {
        std::vector<int> current_colors(n);
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2
        bool possible_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot_val) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_pivot = false;
                    break;
                }
                current_colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > pivot_val) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_pivot = false;
                    break;
                }
                current_colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == pivot_val
                // Can be color 1 or 2
                // Prefer color 2 if possible, to keep last1 small
                if (d[i] >= last2) {
                    current_colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) {
                    current_colors[i] = 1;
                    last1 = d[i];
                } else {
                    possible_pivot = false;
                    break;
                }
            }
        }

        if (possible_pivot) {
            // Verify the combined sequence
            std::string s1_str = "";
            std::string s2_str = "";
            for (int i = 0; i < n; ++i) {
                if (current_colors[i] == 1) {
                    s1_str += s[i];
                } else {
                    s2_str += s[i];
                }
            }

            std::string combined_str = s1_str + s2_str;
            bool sorted = true;
            for (int i = 0; i < n - 1; ++i) {
                if (combined_str[i] > combined_str[i+1]) {
                    sorted = false;
                    break;
                }
            }

            if (sorted) {
                for (int i = 0; i < n; ++i) {
                    result[i] = (char)(current_colors[i] + '0');
                }
                found_solution = true;
                break;
            }
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each remainder i % k

    bool possible = true;

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                possible = false; // Conflict detected
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Count 0s and 1s in the first k positions based on fixed_chars
    int count0 = 0;
    int count1 = 0;
    int count_q = 0; // Count of '?' in fixed_chars for the first k positions

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    // Step 3: Check if it's possible to achieve k/2 zeros and k/2 ones
    int target_half = k / 2;

    if (count0 > target_half || count1 > target_half) {
        possible = false; // Too many 0s or 1s already
    } else {
        // We need (target_half - count0) more 0s and (target_half - count1) more 1s
        // from the '?' positions.
        // The total number of '?' positions must be enough to cover these needs.
        if (count_q < (target_half - count0) + (target_half - count1)) {
            possible = false; // Not enough '?' to satisfy the counts
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

