int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x_c - 1, y_c)
            // If f1 == 0, robot cannot move left.
            // This means it can only reach points with x >= its current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x_c, y_c + 1)
            // If f2 == 0, robot cannot move up.
            // This means it can only reach points with y <= its current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x_c + 1, y_c)
            // If f3 == 0, robot cannot move right.
            // This means it can only reach points with x <= its current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x_c, y_c - 1)
            // If f4 == 0, robot cannot move down.
            // This means it can only reach points with y >= its current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the valid range.
            // The problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // So, we can clamp the chosen coordinates to this range if they fall outside.
            // However, min_x and min_y are guaranteed to be within the range if a solution exists.
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // The initial coordinates are up to 10^5.
            // If a robot cannot move left (f1=0), min_x becomes its x_i.
            // If a robot cannot move right (f3=0), max_x becomes its x_i.
            // So min_x and max_x will be within [-10^5, 10^5] if they are set by a robot.
            // If they are not set, they remain at -2e9 or 2e9.
            // The problem guarantees that if a solution exists, one within [-10^5, 10^5] exists.
            // So, we can just output min_x and min_y, as they will be valid.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

