int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 0) {
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(static_cast<double>(n))));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_val = std::max(1, current_val - k + 1);
        for (int j = 0; j < k && current_val >= 1; ++j) {
            p[i + j] = current_val;
            current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

