void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s_count = 0;
    int initial_b_count = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s_count++;
        } else {
            initial_b_count++;
        }
    }

    int initial_diff = initial_s_count - initial_b_count;

    if (initial_diff == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // s_left_prefix_diff[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // for k from 0 to n
    std::vector<int> s_left_prefix_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left_prefix_diff[i + 1] = s_left_prefix_diff[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // s_right_suffix_diff[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // for k from 0 to n
    std::vector<int> s_right_suffix_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_right_suffix_diff[i + 1] = s_right_suffix_diff[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain diff
    // map: diff_value -> jars_removed_from_left
    std::map<int, int> left_diff_to_removed_count;
    for (int k = 0; k <= n; ++k) { // k is number of jars removed from left (0 to n)
        int current_diff = s_left_prefix_diff[k];
        if (left_diff_to_removed_count.find(current_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_diff] = k;
        }
    }

    int min_removed_jars = 2 * n; // Max possible jars removed

    for (int k = 0; k <= n; ++k) { // k is number of jars removed from right (0 to n)
        int current_right_diff = s_right_suffix_diff[k];
        // We want (initial_diff - current_left_diff - current_right_diff) = 0
        // So, current_left_diff = initial_diff - current_right_diff
        int target_left_diff = initial_diff - current_right_diff;

        if (left_diff_to_removed_count.count(target_left_diff)) {
            int removed_from_left = left_diff_to_removed_count[target_left_diff];
            min_removed_jars = std::min(min_removed_jars, removed_from_left + k);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

