#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
        // This is achieved by distributing the '0's as evenly as possible among the 'm+1' possible gaps
        // created by the 'm' ones.
        // The 'm' ones divide the string into m+1 potential blocks of zeros.
        // Let k be the number of zeros in each of the 'm+1' blocks.
        // We distribute num_zeros among m+1 blocks.
        // There will be (num_zeros % (m+1)) blocks of size (num_zeros / (m+1)) + 1
        // And (m+1 - (num_zeros % (m+1))) blocks of size (num_zeros / (m+1))

        long long k_base = num_zeros / (m + 1);
        long long remainder = num_zeros % (m + 1);

        long long num_blocks_large = remainder;
        long long num_blocks_small = (m + 1) - remainder;

        long long large_block_size = k_base + 1;
        long long small_block_size = k_base;

        long long substrings_from_zeros = 0;
        substrings_from_zeros += num_blocks_large * large_block_size * (large_block_size + 1) / 2;
        substrings_from_zeros += num_blocks_small * small_block_size * (small_block_size + 1) / 2;

        long long result = total_substrings - substrings_from_zeros;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Dummy operation
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make a[0] zero using segment [0, n-2]
        // This operation will make a[0] zero, and other elements a[i] (i < n-1) will become a[i] + k_i * (n-1).
        // We choose k_i such that a[i] + k_i * (n-1) is divisible by n.
        // Specifically, we want a[i] + k_i * (n-1) = 0 (mod n).
        // Since n-1 is coprime to n, (n-1)^-1 (mod n) exists and is -1 (mod n) or n-1 (mod n).
        // So, k_i * (n-1) = -a[i] (mod n)
        // k_i = -a[i] * (n-1)^-1 (mod n)
        // k_i = -a[i] * (n-1) (mod n)
        // k_i = a[i] (mod n)
        // So we add (a[i] - a[i] % n) to a[i] if a[i] % n != 0.
        // Or more simply, we want to add x_i such that x_i is a multiple of (n-1) and a[i] + x_i is a multiple of n.
        // Let x_i = k_i * (n-1). We want a[i] + k_i * (n-1) = 0 (mod n).
        // a[i] + k_i * (-1) = 0 (mod n)
        // k_i = a[i] (mod n).
        // So we can choose k_i = a[i] % n. If a[i] % n is negative, add n to make it positive.
        // The value to add is (a[i] % n) * (n-1).
        // This makes a[i] become a[i] + (a[i] % n) * (n-1).
        // This new value is a[i] + (a[i] % n) * (-1) (mod n) = a[i] - (a[i] % n) (mod n) = 0 (mod n).
        // This is not quite right. We want to make a[i] become a multiple of n.
        // Let's make a[i] become a[i] - (a[i] % n) * n. This is not a multiple of n-1.
        // The strategy is:
        // 1. For elements a[0] to a[n-2], make them multiples of n.
        //    Segment [1, n-1] (0-indexed: [0, n-2]), length n-1.
        //    For each a[i] in this segment, we want to add x_i such that x_i is a multiple of (n-1)
        //    and a[i] + x_i is a multiple of n.
        //    Let x_i = k_i * (n-1).
        //    a[i] + k_i * (n-1) = 0 (mod n)
        //    a[i] + k_i * (-1) = 0 (mod n)
        //    k_i = a[i] (mod n).
        //    So, we add (a[i] % n) * (n-1) to a[i].
        //    If a[i] % n is negative, we need to adjust it to be in [0, n-1].
        //    Let rem = a[i] % n. If rem < 0, rem += n.
        //    Then add rem * (n-1).
        //    After this, a[i] becomes a[i] + rem * (n-1).
        //    This new value is a[i] + rem * (-1) (mod n) = a[i] - rem (mod n) = 0 (mod n).
        //    So, a[i] becomes a multiple of n.
        //    The value to add is rem * (n-1).
        //    This is for elements a[0] to a[n-2].

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long rem = a[i] % n;
            if (rem < 0) {
                rem += n;
            }
            long long add_val = rem * (n - 1);
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val;
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] zero.
        // Segment [n, n] (0-indexed: [n-1, n-1]), length 1.
        // We can add any multiple of 1.
        // Add -a[n-1] to a[n-1].
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0;

        // Operation 3: Make all elements a[0] to a[n-2] zero.
        // At this point, a[0] to a[n-2] are all multiples of n.
        // Segment [1, n] (0-indexed: [0, n-1]), length n.
        // For each a[i] in this segment, we want to add x_i such that x_i is a multiple of n
        // and a[i] + x_i = 0.
        // So, we add -a[i] to a[i]. Since a[i] is already a multiple of n, -a[i] is also a multiple of n.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Simulate the effect of operations on two initial values: 0 and 1023
    // 0 represents all bits being 0
    // 1023 represents all bits being 1
    int current_val_for_0 = 0;
    int current_val_for_1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_for_0 &= x;
            current_val_for_1023 &= x;
        } else if (op_char == '|') {
            current_val_for_0 |= x;
            current_val_for_1023 |= x;
        } else if (op_char == '^') {
            current_val_for_0 ^= x;
            current_val_for_1023 ^= x;
        }
    }

    // Now, current_val_for_0 is the result if input was 0.
    // And current_val_for_1023 is the result if input was 1023.

    // We need to find a sequence of at most 5 operations that transforms
    // 0 -> current_val_for_0
    // 1023 -> current_val_for_1023
    // for all bits independently.

    // Let's determine the target AND, OR, XOR constants.
    // For each bit position j (0 to 9):
    // Let b0_j be the j-th bit of current_val_for_0
    // Let b1_j be the j-th bit of current_val_for_1023
    // Let x_j be the j-th bit of the input.

    // If x_j = 0, it becomes b0_j.
    // If x_j = 1, it becomes b1_j.

    // We are looking for A, O, X such that:
    // (x & A | O) ^ X
    // This is equivalent to (x | O) & A ^ X if we consider the order.
    // The problem states "arbitrary sequence", but we can simplify to at most 3 operations.
    // A common simplification is (x & A_const | O_const) ^ X_const.
    // Let's try to find A_const, O_const, X_const.

    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        int b0_j = (current_val_for_0 >> j) & 1;
        int b1_j = (current_val_for_1023 >> j) & 1;

        // Case 1: Input bit 0 -> b0_j, Input bit 1 -> b1_j
        // If b0_j = 0, b1_j = 0:
        //   x_j must become 0 regardless of its initial value.
        //   This means (x_j & 0) or (x_j | 0) & 0 or (x_j ^ 1) & 0 etc.
        //   Simplest: final_and_mask_j = 0.
        if (b0_j == 0 && b1_j == 0) {
            final_and_mask &= ~(1 << j); // Set j-th bit of AND mask to 0
            final_or_mask &= ~(1 << j);  // Set j-th bit of OR mask to 0
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
        // If b0_j = 0, b1_j = 1:
        //   x_j must become x_j. (0->0, 1->1)
        //   Simplest: no change to this bit.
        //   final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 0.
        else if (b0_j == 0 && b1_j == 1) {
            final_and_mask |= (1 << j); // Set j-th bit of AND mask to 1
            final_or_mask &= ~(1 << j); // Set j-th bit of OR mask to 0
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
        // If b0_j = 1, b1_j = 0:
        //   x_j must become NOT x_j. (0->1, 1->0)
        //   Simplest: final_xor_mask_j = 1.
        //   final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 1.
        else if (b0_j == 1 && b1_j == 0) {
            final_and_mask |= (1 << j); // Set j-th bit of AND mask to 1
            final_or_mask &= ~(1 << j); // Set j-th bit of OR mask to 0
            final_xor_mask |= (1 << j); // Set j-th bit of XOR mask to 1
        }
        // If b0_j = 1, b1_j = 1:
        //   x_j must become 1 regardless of its initial value.
        //   Simplest: final_or_mask_j = 1.
        //   final_and_mask_j = 1, final_or_mask_j = 1, final_xor_mask_j = 0.
        else if (b0_j == 1 && b1_j == 1) {
            final_and_mask |= (1 << j); // Set j-th bit of AND mask to 1
            final_or_mask |= (1 << j);  // Set j-th bit of OR mask to 1
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_and_mask != 1023) { // 1023 is all 1s for 10 bits
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

