#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal (i.e., addition order)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back

        active_vertices[k] = true; // Mark this vertex as active

        // Update shortest paths using the newly active vertex 'k'
        // Floyd-Warshall step: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider paths between active vertices
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider paths between active vertices

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After adding k, update paths through k for all existing active vertices
        // This is the standard Floyd-Warshall triple loop, but restricted to active vertices
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                for (int l = 0; l < n; ++l) {
                    if (!active_vertices[l]) continue;

                    if (dist[i][l] != -1 && dist[l][j] != -1) {
                        if (dist[i][j] == -1 || dist[i][l] + dist[l][j] < dist[i][j]) {
                            dist[i][j] = dist[i][l] + dist[l][j];
                        }
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, LLONG_MAX); // b[i] stores the maximum possible initial value for a[i]

    // Iterate operations in reverse to determine upper bounds for initial values
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If a type 1 operation (l, r, d) was applied, it means
            // that any element a[j] in this range had d added to it.
            // When we consider the initial values, this d must be subtracted
            // from the current upper bound for a[j] to get the upper bound
            // for its initial value.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != LLONG_MAX) { // Only adjust if an upper bound has been set
                    b[j] -= ops[i].val;
                }
            }
        } else { // ops[i].type == 2
            // If a type 2 operation (l, r, m) was applied, it means
            // max(a[j]) for j in [l, r] must be m.
            // This implies that for all j in [l, r], a[j] <= m.
            // So, the initial value a_0[j] must be <= m - (sum of d's applied to a[j] *after* this operation).
            // Since we are iterating backwards, the 'sum of d's applied after this operation'
            // is already incorporated into b[j].
            // So, for each j in [l, r], a_0[j] <= m.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // Initialize the candidate initial array a_0
    // If b[i] is still LLONG_MAX, it means no type 2 operation constrained a[i].
    // In this case, we can set a_0[i] to 0 (or any value within [-10^9, 10^9]).
    // We choose 0 as it's simple and satisfies the absolute value constraint.
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            a0[i] = 0;
        } else {
            a0[i] = b[i];
        }
        // Ensure a0[i] is within the allowed range [-10^9, 10^9]
        // If b[i] was already outside this range, it's an invalid solution.
        // However, the problem statement implies that if a solution exists,
        // such an array can be found. The constraints on m_i and d_i
        // are such that intermediate values might exceed 10^9, but the
        // initial values should be within 10^9.
        // For simplicity, we'll assume that if a solution exists,
        // the derived a0[i] will be within this range or can be clamped.
        // The problem asks for *a* suitable array, so clamping might be an option
        // if it doesn't violate conditions. But usually, if it goes out of bounds,
        // it means no solution. Let's stick to the derived b[i] values.
        // The problem states "all numbers in his array didn't exceed 10^9 in their absolute value"
        // for the *initial* array.
        if (a0[i] > 1000000000LL || a0[i] < -1000000000LL) {
            // This case should ideally not happen if a solution exists and m_i are within bounds.
            // If it does, it implies no solution.
            // For now, we proceed and let the verification step catch it.
        }
    }

    // Verify the constructed initial array
    std::vector<long long> current_a = a0;
    std::vector<long long> current_deltas(n, 0); // Stores sum of d's applied to each element

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_deltas[j] += op.val;
            }
        } else { // op.type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, a0[j] + current_deltas[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    // Iterate through powers of 2 from largest possible down to 1
    // 2^60 is roughly 10^18, but we need to fit X.
    // X can be up to 10^9. 2^29 is ~5*10^8, 2^30 is ~10^9.
    // So we need to check up to 2^29 or 2^30.
    // The maximum number of elements is 10^4.
    // If we use 29 distinct "blocks", each block contributes 2^k-1.
    // The maximum k for a block is 29.
    // So we can have at most 29 blocks.
    // The total number of elements would be sum of k_i.
    // If X is 10^9, and we use 2^29, we need 29 elements.
    // If X is 10^9, and we use 2^1, we need 10^9 elements, which is too many.
    // The strategy is to decompose X into sum of (2^k - 1) terms.
    // X = sum(c_i * (2^i - 1)) where c_i is the count of blocks of size i.
    // This is equivalent to decomposing X+1 into sum of c_i * 2^i.
    // X+1 = sum(c_i * 2^i). This is just binary representation of X+1.
    // So, if X+1 has a 1 at bit position `k`, it means we need a block of `k` elements.
    // For example, if X=10, X+1=11 (binary 1011).
    // This means 11 = 2^3 + 2^1 + 2^0.
    // So we need blocks of size 3, 1, 0.
    // A block of size 0 means 2^0-1 = 0 subsequences, which is useless.
    // A block of size 1 means 2^1-1 = 1 subsequence.
    // A block of size k means 2^k-1 subsequences.
    // So if X+1 has bit k set, we add k elements to the array.
    // The maximum k is around 60 (for 2^60 > 10^18, but X is 10^9, so k up to 30).
    // The maximum number of elements is 10^4.
    // If X = 10^9, X+1 is roughly 2^30.
    // The binary representation of X+1 will have at most 30 bits set.
    // If all 30 bits are set, total elements = 0+1+2+...+29 = 29*30/2 = 435 elements.
    // This is well within 10^4.

    // The values in the array must be distinct enough so that elements from different "blocks"
    // don't form valid subsequences together.
    // We can achieve this by making the minimum difference between elements from different blocks
    // greater than or equal to `d`.
    // For example, if we have a block of `k` elements, all equal to `V`.
    // Then the next block of `j` elements, all equal to `V'`.
    // We need `V' - V >= d`.
    // So we can set `V' = V + d + 1`.
    // This ensures that `max(subsequence from block 1 and block 2) - min(subsequence from block 1 and block 2)`
    // will be at least `(V + d + 1) - V = d + 1`, which is `>= d`.
    // So, elements from different blocks will not combine to form valid subsequences.
    // The total number of subsequences will be the sum of subsequences from each block.
    // Each block of `k` identical elements contributes `2^k - 1` valid subsequences.

    // Let's iterate `k` from 1 to 60 (or until X becomes 0).
    // `k` represents the number of identical elements in a block.
    // `(1LL << k) - 1` is the number of subsequences from a block of `k` elements.
    // We want to find `k` such that `(1LL << k) - 1` is the largest power-of-2-minus-1 less than or equal to `X`.
    // This is equivalent to finding `k` such that `(1LL << k)` is the largest power of 2 less than or equal to `X+1`.
    // So we can iterate `k` from 60 down to 1.
    // If `X` has `(1LL << k) - 1` as a component, we add `k` elements.
    // This is essentially greedily picking the largest `k` such that `(1LL << k) - 1 <= X`.
    // This is equivalent to finding the highest set bit in `X+1`.

    for (int k = 60; k >= 1; --k) {
        long long num_subsequences_from_k_elements = (1LL << k) - 1;
        if (X >= num_subsequences_from_k_elements) {
            // Add k elements, all equal to current_val
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            X -= num_subsequences_from_k_elements;
            // Move to the next block, ensuring separation by d
            current_val += d + 1;
        }
    }

    // If X is not 0 after the loop, it means we couldn't form X.
    // This should not happen if X is positive, as we can always use blocks of size 1.
    // The loop covers all powers of 2.
    // The logic is that X can be uniquely represented as sum of (2^k - 1) terms.
    // For example, X = 10.
    // k=4: (1LL << 4) - 1 = 15. 10 < 15. Skip.
    // k=3: (1LL << 3) - 1 = 7. 10 >= 7. Add 3 elements (e.g., 1, 1, 1). X = 10 - 7 = 3. current_val = 1 + d + 1.
    // k=2: (1LL << 2) - 1 = 3. 3 >= 3. Add 2 elements (e.g., 1+d+1, 1+d+1). X = 3 - 3 = 0. current_val = 1+d+1 + d + 1.
    // k=1: (1LL << 1) - 1 = 1. 0 < 1. Skip.
    // This decomposition is equivalent to X+1 in binary.
    // X=10, X+1=11 (binary 1011).
    // Bit 0 (2^0): 1. Corresponds to k=1. Add 1 element.
    // Bit 1 (2^1): 1. Corresponds to k=2. Add 2 elements.
    // Bit 2 (2^2): 0.
    // Bit 3 (2^3): 1. Corresponds to k=3. Add 3 elements.
    // So for X=10, we need blocks of size 1, 2, 3. Total 1+2+3 = 6 elements.
    // This is exactly what the example output shows: 6 elements.
    // The example output values are 5, 50, 7, 15, 6, 100.
    // This suggests a different construction for values, but the number of elements is the same.
    // My construction:
    // k=3: add 3 elements (e.g., 1, 1, 1). X=3. current_val = 1+d+1.
    // k=2: add 2 elements (e.g., 1+d+1, 1+d+1). X=0. current_val = 1+d+1+d+1.
    // k=1: add 1 element (e.g., 1+d+1+d+1). X=0. current_val = 1+d+1+d+1+d+1.
    // This is not quite right. The loop should be for `k` from 1 to 60.
    // If `(X >> (k-1)) & 1` is true, it means `X+1` has `k`-th bit set.
    // No, it's `X` itself.
    // The number of subsequences is `X`.
    // We want to represent `X` as `sum_{i=1 to M} (2^{k_i} - 1)`.
    // This is equivalent to `X + M = sum_{i=1 to M} 2^{k_i}`.
    // This is not a simple binary representation.

    // Let's re-evaluate the decomposition.
    // If we have `k` identical elements, they contribute `2^k - 1` subsequences.
    // We want to represent `X` as a sum of `(2^k - 1)` terms.
    // This is a greedy approach: find the largest `k` such that `2^k - 1 <= X`.
    // Add `k` elements. Subtract `2^k - 1` from `X`. Repeat.
    // Example: X=10, d=5
    // 1. Largest k such that 2^k - 1 <= 10.
    //    k=1: 2^1-1=1 <= 10
    //    k=2: 2^2-1=3 <= 10
    //    k=3: 2^3-1=7 <= 10
    //    k=4: 2^4-1=15 > 10
    //    So, k=3. Add 3 elements (e.g., 1, 1, 1). X = 10 - 7 = 3. current_val = 1 + d + 1 = 7.
    // 2. Largest k such that 2^k - 1 <= 3.
    //    k=1: 1 <= 3
    //    k=2: 3 <= 3
    //    k=3: 7 > 3
    //    So, k=2. Add 2 elements (e.g., 7, 7). X = 3 - 3 = 0. current_val = 7 + d + 1 = 13.
    // 3. X is 0. Stop.
    // Result array: [1, 1, 1, 7, 7]. Size 5.
    // This is different from the example output [5, 50, 7, 15, 6, 100] which has size 6.
    // The example output has 10 subsequences.
    // [5], [5,7], [5,6], [5,7,6] -> 4 subsequences from {5,7,6} if d is large enough.
    // [50] -> 1
    // [7] -> 1
    // [15] -> 1
    // [6] -> 1
    // [100] -> 1
    // Total 4+1+1+1+1+1 = 9. This is not 10.
    // The example output explanation is confusing.
    // "remaining subsequences ... are [5], [5, 7], [5, 6], [5, 7, 6], [50], [7], [7, 6], [15], [6], [100]. There are 10 of them."
    // Let's check the example output [5, 50, 7, 15, 6, 100] with d=5.
    // Valid subsequences must have max - min < 5.
    // Consider elements {5, 7, 6}. Max=7, Min=5. Max-Min=2 < 5. All subsequences from {5,7,6} are valid.
    // These are: [5], [7], [6], [5,7], [5,6], [7,6], [5,7,6]. Total 2^3-1 = 7 subsequences.
    // Consider {50}. [50]. 1 subsequence.
    // Consider {15}. [15]. 1 subsequence.
    // Consider {100}. [100]. 1 subsequence.
    // Total = 7 + 1 + 1 + 1 = 10. This matches X=10.
    // So the example output uses a "block" of elements that are not identical, but are close enough.
    // {5, 7, 6} is a block. Max-Min = 7-5 = 2 < 5.
    // {50} is a block.
    // {15} is a block.
    // {100} is a block.
    // The elements from different blocks are far apart:
    // 50 - 7 = 43 >= 5.
    // 15 - 7 = 8 >= 5.
    // 100 - 7 = 93 >= 5.
    // This confirms the strategy: create "blocks" of elements.
    // Each block `B_i` has elements `b_{i,1}, ..., b_{i,k_i}` such that `max(B_i) - min(B_i) < d`.
    // And for any two blocks `B_i, B_j` (i != j), `|min(B_i) - max(B_j)| >= d`.
    // If this is true, then any subsequence containing elements from different blocks will be invalid.
    // The total number of valid subsequences will be `sum (2^{k_i} - 1)`.
    // The simplest way to make a block `B_i` is to have `k_i` identical elements.
    // This is what my current code does.
    // The example output for X=10, d=5: [5, 50, 7, 15, 6, 100]
    // My code for X=10, d=5: [1, 1, 1, 7, 7]
    // Both are valid. My code produces 5 elements, example produces 6. Both <= 10^4.
    // My code is simpler and correct.

    // The maximum value of `current_val` can be large.
    // `X` up to 10^9. `d` up to 10^9.
    // If `X` is 1, `k=1`. `current_val` becomes `1 + d + 1`.
    // If `X` is `2^29 - 1`, `k=29`. `current_val` becomes `1 + d + 1`.
    // If `X` is `2^29 - 1 + 2^28 - 1 + ... + 2^1 - 1`.
    // This means `X` is sum of `(2^k - 1)` for `k=1` to `29`.
    // Number of blocks `M` is at most 29 (since `X` is up to `10^9`, `2^29` is max power).
    // `current_val` can be `1 + M * (d + 1)`.
    // `1 + 29 * (10^9 + 1)` is roughly `29 * 10^9`, which is less than `10^18`.
    // So `current_val` will fit in `long long`.
    // The number of elements `result_array.size()`:
    // Max `k` is 29. If `X` is `2^29 - 1`, `result_array.size()` is 29.
    // If `X` is `sum_{k=1 to 29} (2^k - 1)`, then `result_array.size()` is `sum_{k=1 to 29} k = 29 * 30 / 2 = 435`.
    // This is well within 10^4.

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Option 1: All elements in one subsequence (e.g., S1)
    // f values are a_i + a_j
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Option 2: Partition into two non-empty subsequences
    // min_f can be a_1 + a_2 (same subsequence) or a_1 + a_2 + h (different subsequences)
    // max_f can be a_{n-1} + a_n (same subsequence) or a_{n-1} + a_n + h (different subsequences)

    // Consider a specific partition strategy:
    // Put elements[0] into S1, and elements[1]...elements[n-1] into S2.
    // This ensures a_1 and a_2 are in different subsequences.
    // min_f:
    //   - If S1 has other elements: a_1 + a_k (k in S1)
    //   - If S2 has other elements: a_2 + a_3 (if n >= 3)
    //   - a_1 + a_2 + h (a_1 in S1, a_2 in S2)
    // The smallest possible sum is a_1 + a_2.
    // If a_1 and a_2 are in different subsequences, this sum becomes a_1 + a_2 + h.
    // If a_1 and a_2 are in the same subsequence, this sum is a_1 + a_2.

    // Let's analyze the min/max f values for a general partition.
    // min_f_val = min(a_i + a_j, a_i + a_j + h)
    // max_f_val = max(a_i + a_j, a_i + a_j + h)

    // The smallest possible sum of two elements is elements[0].value + elements[1].value.
    // The largest possible sum of two elements is elements[n-1].value + elements[n-2].value.

    // If elements[0] and elements[1] are in the same subsequence, min_f_val <= elements[0].value + elements[1].value.
    // If elements[0] and elements[1] are in different subsequences, min_f_val <= elements[0].value + elements[1].value + h.

    // If elements[n-1] and elements[n-2] are in the same subsequence, max_f_val >= elements[n-1].value + elements[n-2].value.
    // If elements[n-1] and elements[n-2] are in different subsequences, max_f_val >= elements[n-1].value + elements[n-2].value + h.

    // Consider the partition where elements[0] is in S1, and all other elements are in S2.
    // This is a common strategy for minimizing range when h is large.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Possible f values:
    // 1. From S2: elements[i].value + elements[j].value for i,j in [1, n-1]
    //    Min: elements[1].value + elements[2].value (if n >= 3)
    //    Max: elements[n-1].value + elements[n-2].value (if n >= 3)
    // 2. Between S1 and S2: elements[0].value + elements[j].value + h for j in [1, n-1]
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f:
    //   If n=2: only elements[0].value + elements[1].value + h
    //   If n>=3: min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f:
    //   If n=2: only elements[0].value + elements[1].value + h
    //   If n>=3: max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)

    long long min_f2, max_f2;
    if (n == 2) {
        min_f2 = elements[0].value + elements[1].value + h;
        max_f2 = elements[0].value + elements[1].value + h;
    } else {
        min_f2 = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        max_f2 = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    }
    long long goodness2 = max_f2 - min_f2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Consider the partition where elements[n-1] is in S1, and all other elements are in S2.
    // S1 = {elements[n-1]}
    // S2 = {elements[0], ..., elements[n-2]}
    //
    // Possible f values:
    // 1. From S2: elements[i].value + elements[j].value for i,j in [0, n-2]
    //    Min: elements[0].value + elements[1].value (if n >= 3)
    //    Max: elements[n-2].value + elements[n-3].value (if n >= 3)
    // 2. Between S1 and S2: elements[n-1].value + elements[j].value + h for j in [0, n-2]
    //    Min: elements[n-1].value + elements[0].value + h
    //    Max: elements[n-1].value + elements[n-2].value + h
    //
    // Overall min_f:
    //   If n=2: only elements[0].value + elements[1].value + h
    //   If n>=3: min(elements[0].value + elements[1].value, elements[n-1].value + elements[0].value + h)
    // Overall max_f:
    //   If n=2: only elements[0].value + elements[1].value + h
    //   If n>=3: max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h)

    long long min_f3, max_f3;
    if (n == 2) {
        min_f3 = elements[0].value + elements[1].value + h;
        max_f3 = elements[0].value + elements[1].value + h;
    } else {
        min_f3 = std::min(elements[0].value + elements[1].value, elements[n - 1].value + elements[0].value + h);
        max_f3 = std::max(elements[n - 2].value + elements[n - 3].value, elements[n - 1].value + elements[n - 2].value + h);
    }
    long long goodness3 = max_f3 - min_f3;
    std::vector<int> partition3(n);
    partition3[elements[n - 1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition3[elements[i].original_index] = 2;
    }

    // Compare the goodness values
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition = partition2;
    }
    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition = partition3;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2. We reorder to s2s1.
    // s2s1 must be a palindrome and s2s1 != s.
    // s1 and s2 must be non-empty.
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // This means 3 pieces: s1, s2, s3.
    // We need to form a palindrome s' != s.
    // The problem statement implies that if k=1 doesn't work, we try k=2.
    // If k=1 doesn't work, it means no single cut and swap creates a new palindrome.
    // This implies that for any split s = s1s2, if s2s1 is a palindrome, then s2s1 must be s.
    // This happens if s is a "rotationally symmetric" palindrome, e.g., "abccba" -> "ccbaab" (not palindrome)
    // or "ababa" -> "babaa" (not palindrome)
    // or "otto" -> "ttoo" (palindrome, k=1)
    // or "nolon" -> "lonno" (not palindrome)
    //
    // The only case where k=1 fails is if all possible rotations s2s1 are either not palindromes
    // or are equal to s.
    //
    // Consider the structure of s. Since s is a palindrome, s[i] == s[n-1-i].
    // If all characters in s are the same (e.g., "qqqq"), then any reordering of pieces will result in the same string.
    // For example, "qqqq" cut into "q|q|qq" and reordered to "q|qq|q" is still "qqqq".
    // In this case, it's impossible to form a new string.
    // We can check this by counting unique characters. If there's only one unique character, it's impossible.
    //
    // If s consists of only one distinct character, e.g., "aaaaa", then any permutation of its substrings will result in "aaaaa".
    // In this case, it's impossible to form a new string different from s.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If n is odd, and the middle character is different from others,
    // e.g., "abacaba", "nolon".
    // If n is odd, and all characters except the middle one are the same,
    // e.g., "aaabaaa".
    //
    // If k=1 fails, it means for any split s=s1s2, either s2s1 is not a palindrome, or s2s1 == s.
    //
    // Consider the case where s has an odd length, and all characters are the same except for the middle one.
    // Example: "ababa" (n=5).
    // s1="a", s2="baba". new_s="babaa" (not palindrome)
    // s1="ab", s2="aba". new_s="abaab" (not palindrome)
    // s1="aba", s2="ba". new_s="baaba" (not palindrome)
    // s1="abab", s2="a". new_s="aabab" (not palindrome)
    //
    // Example: "nolon" (n=5).
    // s1="n", s2="olon". new_s="olonn" (not palindrome)
    // s1="no", s2="lon". new_s="lonno" (not palindrome)
    // s1="nol", s2="on". new_s="onnol" (not palindrome)
    // s1="nolo", s2="n". new_s="nnolo" (not palindrome)
    //
    // The problem statement for "nolon" says k=2.
    // "no|l|on" -> "on|l|no" which is "onlno". This is a palindrome.
    // This implies that if k=1 fails, k=2 is always possible unless all characters are the same.
    //
    // Why is k=2 always possible if not all characters are the same?
    // Let s = s_prefix + s_middle + s_suffix.
    // s_prefix is s[0...n/2 - 1]
    // s_suffix is s[n/2 + (n%2)...n-1]
    // s_middle is s[n/2] if n is odd, empty if n is even.
    //
    // Consider cutting s into three pieces:
    // s[0...i-1], s[i...n-1-i], s[n-i...n-1]
    // Let A = s[0...i-1]
    // Let B = s[i...n-1-i]
    // Let C = s[n-i...n-1]
    // Since s is a palindrome, A is the reverse of C. (A = reverse(C))
    //
    // We can choose i = 1.
    // A = s[0]
    // B = s[1...n-2]
    // C = s[n-1]
    // We know s[0] == s[n-1].
    //
    // If we reorder to C + B + A, this forms s[n-1] + s[1...n-2] + s[0].
    // Since s[n-1] == s[0], this is effectively s[0] + s[1...n-2] + s[0].
    // This is the same as s. This doesn't work.
    //
    // What if we cut s into s[0...i-1], s[i...j-1], s[j...n-1]?
    //
    // The example "nolon" -> "no|l|on" -> "on|l|no"
    // Here s1="no", s2="l", s3="on".
    // s1 is s[0...1]
    // s2 is s[2]
    // s3 is s[3...4]
    //
    // The reordering is s3 + s2 + s1.
    // s3 = "on"
    // s2 = "l"
    // s1 = "no"
    // Result: "onlno". This is a palindrome.
    //
    // This specific cut is:
    // s[0...i-1] (s1)
    // s[i...n-1-i] (s2)
    // s[n-i...n-1] (s3)
    //
    // Here i=2.
    // s1 = s[0...1] = "no"
    // s2 = s[2...2] = "l"
    // s3 = s[3...4] = "on"
    //
    // The reordering is s3 + s2 + s1.
    // Since s is a palindrome, s3 is the reverse of s1.
    // So, s3 + s2 + s1 = reverse(s1) + s2 + s1.
    // For this to be a palindrome, we need reverse(s1) + s2 + s1 == reverse(s1 + reverse(s2) + reverse(reverse(s1)))
    // reverse(s1) + s2 + s1 == reverse(s1) + reverse(s2) + s1
    // This implies s2 == reverse(s2), i.e., s2 must be a palindrome.
    //
    // In "nolon", s2="l" is a palindrome.
    // In "abacaba", if we take i=2, s1="ab", s2="aca", s3="ba".
    // s2="aca" is a palindrome.
    // Then s3+s2+s1 = "ba" + "aca" + "ab" = "baacaab". This is a palindrome.
    // And "baacaab" != "abacaba".
    //
    // So, if we can find an `i` such that `s[i...n-1-i]` is a palindrome,
    // and `s[0...i-1]` is not empty, and `s[0...i-1]` is not equal to `s[n-i...n-1]` (which is always true if i > 0),
    // then we can form `s[n-i...n-1] + s[i...n-1-i] + s[0...i-1]`.
