        if (p_arr[current_p_idx] < head_min_reach) {
            return false;
        }

        // Now we know `p_arr[current_p_idx] >= head_min_reach`.
        // This head `h_arr[i]` can cover `p_arr[current_p_idx]`.
        // It can also cover all tracks `p_arr[k]` such that `p_arr[k] <= head_max_reach`.
        // We want to find the furthest track this head can cover, starting from `p_arr[current_p_idx]`.
        long long current_head_coverage_end = head_max_reach;

        // The head can also move to `p_arr[current_p_idx]` and then cover a range.
        // If the head moves to `p_arr[current_p_idx]`, it takes `abs(h_arr[i] - p_arr[current_p_idx])` time.
        // The remaining time is `t - abs(h_arr[i] - p_arr[current_p_idx])`.
        // From `p_arr[current_p_idx]`, it can then cover tracks up to `p_arr[current_p_idx] + (t - abs(h_arr[i] - p_arr[current_p_idx]))`.
        // This is `p_arr[current_p_idx] + t - abs(h_arr[i] - p_arr[current_p_idx])`.
        // This is the correct greedy strategy.
        // The head `h_arr[i]` should move to `p_arr[current_p_idx]` and then sweep right as far as possible.
        // The time taken to reach `p_arr[current_p_idx]` is `abs(h_arr[i] - p_arr[current_p_idx])`.
        // The remaining time for sweeping is `t - abs(h_arr[i] - p_arr[current_p_idx])`.
        // So, the rightmost track it can cover is `p_arr[current_p_idx] + (t - abs(h_arr[i] - p_arr[current_p_idx]))`.

        long long rightmost_covered_by_this_head = p_arr[current_p_idx] + (t - std::abs(h_arr[i] - p_arr[current_p_idx]));

        // Advance current_p_idx past all tracks covered by this head
        while (current_p_idx < m_val && p_arr[current_p_idx] <= rightmost_covered_by_this_head) {
            current_p_idx++;
        }
    }

    return current_p_idx == m_val;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> n_val >> m_val;

    h_arr.resize(n_val);
    for (long long i = 0; i < n_val; ++i) {
        std::cin >> h_arr[i];
    }

    p_arr.resize(m_val);
    for (long long i = 0; i < m_val; ++i) {
        std::cin >> p_arr[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is now treated

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            children[j].p -= total_d_cry_from_leaving;

            // Apply v_cry from the child currently being treated
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure we only add d_cry once per child leaving
                    total_d_cry_from_leaving += children[j].d;
                    children[j].in_line = false; // Child j leaves the line
                }
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

