    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum 'l' such that the substring s[l...i]
    // does NOT contain any triple pattern.
    // Or, more precisely, dp[i] is the smallest starting index 'j'
    // such that the substring s[j...i] is "bad" (contains no triple).
    // If s[j...i] is bad, then any s[j'...i] for j' >= j is also bad.
    // We want to find the largest j such that s[j...i] is bad.
    // Let's redefine: dp[i] = the smallest index 'j' such that the substring s[j...i]
    // contains a triple. If no such j exists, dp[i] = 0.
    // This is equivalent to: dp[i] = max(0, max_j_such_that_s[j...i]_is_bad + 1)
    // No, this is not right.

    // Let's use the definition from the thought process:
    // `last_good_start[i]` is the smallest `l` such that `s[l...i]` contains a triple.
    // If no such `l` exists, `last_good_start[i]` is `i+1` (or `n` if 0-indexed).
    // This means for any `l < last_good_start[i]`, `s[l...i]` is a bad substring.
    // The number of bad substrings ending at `i` is `last_good_start[i]`.
    // The number of bad substrings ending at `i` is `i - (last_good_start[i] - 1) + 1`
    // which is `i - last_good_start[i] + 2`.
    // No, this is also confusing.

    // Let's use `max_l_for_bad_suffix[i]` = the largest `l` such that `s[l...i]` is a bad substring.
    // If `s[l...i]` is bad, then `s[l+1...i]` is also bad.
    // So, `max_l_for_bad_suffix[i]` is the smallest `l` such that `s[l...i]` contains a triple.
    // Let `min_good_l[i]` be the minimum `l` such that `s[l...i]` contains a triple.
    // If no such `l` exists, `min_good_l[i] = i+1`.
    // The number of bad substrings `s[l...i]` ending at `i` is `min_good_l[i]`.
    // For each `i`, `l` can range from `0` to `min_good_l[i]-1`.
    // So there are `min_good_l[i]` bad substrings ending at `i`.

    std::vector<int> min_good_l(n); // min_good_l[i] = smallest l (0-indexed) such that s[l...i] contains a triple.
                                    // If no such l, min_good_l[i] = i + 1.

