    // and then update it if a new triple ending at i is found.

    min_good_l[0] = 1; // s[0...0] cannot contain a triple. So min_good_l[0] = 0+1 = 1.
    bad_pairs += min_good_l[0]; // 1 bad pair (0,0)

    for (int i = 1; i < n; ++i) {
        min_good_l[i] = min_good_l[i-1]; // Inherit from previous

        // Check for new triples ending at i
        // A triple is s[x] = s[x+k] = s[x+2k]
        // Here, x+2k = i. So x = i-2k.
        // We need to check for k >= 1.
        // x must be >= 0, so i-2k >= 0 => 2k <= i => k <= i/2.
        // Also, x must be < x+k, so k >= 1.
        // So k ranges from 1 to i/2.

        for (int k = 1; k * 2 <= i; ++k) {
