// Using a global or static array for memoization to avoid passing it around
// and to allow for larger N without stack overflow for recursion.
// Max N is 2e5.
// Each state is (current_x, is_step2).
// We need to store the resulting y value and whether it terminates or loops.
// A pair {y_value, status} where status: 0=loop, 1=terminates, 2=calculating
// For y_value, we can use -1 for loop, and actual y for termination.
// To detect cycles, we can use a special value like -2 for 'currently calculating'.

// dp[x][0] stores result for (x, step2)
// dp[x][1] stores result for (x, step3)
// The value stored will be the final y if terminates, or -1 if loops.
// We need to distinguish between 'not yet computed' and 'loops'.
// Let's use a struct or pair for memoization: {long long final_y, bool is_computed, bool is_looping}
// Or, more simply:
// dp[x][0] = {y_val, true} if terminates, {0, false} if loops, {-1, false} if not computed yet.
// dp[x][1] = {y_val, true} if terminates, {0, false} if loops, {-1, false} if not computed yet.

struct Result {
    long long final_y;
    bool is_computed; // true if this state has been fully computed (either terminates or loops)
    bool is_looping;  // true if this state leads to a loop
};

// Using a 2D vector for memoization.
// dp[x][0] for step 2, dp[x][1] for step 3.
// Max x is N, so size N+1.
std::vector<std::vector<Result>> memo;
std::vector<long long> a_values; // a_values[0] is unused, a_values[1] is the current i, a_values[2...N] are fixed.
int N_global;

// Function to solve for a given (x, is_step2) state
// current_x: the current value of x
// is_step2: true if we are about to execute step 2, false if step 3
// current_y_offset: the y value accumulated so far in the current path (before this state)
Result solve(long long current_x, bool is_step2) {
    // Termination check
    if (current_x <= 0 || current_x > N_global) {
        return {0, true, false}; // Base case: terminates, adds 0 to y from this point
    }

    // Check memoization table
    int state_idx = is_step2 ? 0 : 1;
    if (memo[current_x][state_idx].is_computed) {
        return memo[current_x][state_idx];
    }

    // Mark as currently calculating to detect cycles
    memo[current_x][state_idx].is_computed = true;
    memo[current_x][state_idx].is_looping = true; // Assume looping until proven otherwise

    long long val_ax = a_values[current_x];

    Result next_res;
    if (is_step2) {
        // Execute step 2: x = x + a[x], y = y + a[x]
        next_res = solve(current_x + val_ax, false); // Next is step 3
    } else {
        // Execute step 3: x = x - a[x], y = y + a[x]
        next_res = solve(current_x - val_ax, true); // Next is step 2
    }

    if (next_res.is_looping) {
        // If the next state leads to a loop, then this state also leads to a loop.
        memo[current_x][state_idx].final_y = -1;
        memo[current_x][state_idx].is_looping = true;
    } else {
        // If the next state terminates, add val_ax to its final_y.
        memo[current_x][state_idx].final_y = val_ax + next_res.final_y;
        memo[current_x][state_idx].is_looping = false;
    }

    return memo[current_x][state_idx];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_global;

    a_values.resize(N_global + 1);
    for (int k = 2; k <= N_global; ++k) {
        std::cin >> a_values[k];
    }

    // Initialize memoization table once for all runs
    // Max x is N_global, so size N_global+1.
    // Each state (x, is_step2) can be reached from any starting i.
    // So, we need to clear/reset memo for each i.
    // However, the problem states a_1 = i, and a_2...a_n are fixed.
    // This means the 'a' array changes for each i.
    // So, the DP states (x, is_step2) depend on a_1.
    // This implies we need to re-run the DP for each i.
    // This is too slow if N is large (N * N * 2 states).
    // N = 2e5, N^2 = 4e10. This approach is wrong.

    // Let's re-read the problem carefully:
    // "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_{n}."
    // This means a[1] is set to 'i' for each run.
    // The values a[2]...a[n] are constant.
    // The state (x, is_step2) depends on a[x].
    // If x=1, a[1] changes. If x > 1, a[x] is constant.
    // This means the DP table for x > 1 is constant across all runs for different 'i'.
    // Only the DP for x=1 depends on 'i'.

    // We can precompute results for x > 1.
    // For x=1, we need to compute it for each 'i'.
    // The `solve` function needs to be called with `a_values[1]` set to `i`.

    // Initialize memo table for x > 1.
    // For x=1, we will compute it on the fly.
    memo.resize(N_global + 1, std::vector<Result>(2, {0, false, false}));

    // Precompute for x from 2 to N_global.
    // The order of computation matters for DP.
    // A recursive DP with memoization handles this naturally.
    // We need to call solve for all possible (x, is_step2) where x > 1.
    // A simple loop won't work because of dependencies.
    // The recursive `solve` function will fill the memo table as needed.
    // We can call `solve` for all (x, is_step2) where x > 1.
    // But we don't know which states are reachable.
    // The most efficient way is to just let the main loop for `i` fill it.
    // When `a_values[1]` is set to `i`, the `solve` function will be called.
    // If `x > 1`, it will compute and memoize. If `x=1`, it will compute for the current `i`.
    // The problem is that `memo[1]` will be overwritten for each `i`. This is correct.
    // The `memo[x]` for `x > 1` will be filled once and reused.

    for (long long i = 1; i < N_global; ++i) {
        a_values[1] = i;

        // Reset memo[1] for the current 'i'
        memo[1][0] = {0, false, false};
        memo[1][1] = {0, false, false};

        // Initial state: x=1, y=0, about to execute step 2.
        // The first step is always step 2.
        Result final_res = solve(1, true);

        if (final_res.is_looping) {
            std::cout << -1 << "\n";
        } else {
            // The initial y is 0. The first a[x] is a[1].
            // The first step 2 adds a[1] to y.
            // So the total y is a[1] + final_res.final_y (where final_res.final_y is from the state after the first step 2).
            std::cout << a_values[1] + final_res.final_y << "\n";
        }
    }

    return 0;
}

