void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long total_spells = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (where i > 0), we can add min_val to it
        // as many times as possible without exceeding k.
        // a[i] + X * min_val <= k
        // X * min_val <= k - a[i]
        // X <= (k - a[i]) / min_val
        // Since X must be an integer, X = floor((k - a[i]) / min_val)
        if (min_val == 0) { // Should not happen based on constraints (a_i >= 1)
            // If min_val is 0, we can add it infinitely many times without changing a[i].
            // But the problem implies a_i >= 1.
            // If it could be 0, this would be an infinite loop or special case.
            // Given a_i >= 1, min_val >= 1.
        } else {
            total_spells += (k - a[i]) / min_val;
        }
    }

    std::cout << total_spells << std::endl;
}

