void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are useful
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // We only care about numbers up to 2048.
    // Numbers larger than 2048 cannot be used to form 2048.
    // Numbers equal to 2048 mean we win.
    // We can iterate through powers of two from smallest to largest.
    // If we have two 'x's, they combine to form one '2x'.
    // We need to accumulate enough 'smaller' numbers to form '2048'.

    int current_sum = 0; // This will store the total sum of numbers that can be combined to form 2048 or smaller.

    for (int power_of_two = 1; power_of_two <= 2048; power_of_two *= 2) {
        if (counts.count(power_of_two)) {
            current_sum += power_of_two * counts[power_of_two];
        }
        if (current_sum >= 2048) {
            std::cout << "YES\n";
            return;
        }
    }

    std::cout << "NO\n";
}

