    while (t--) {
        int n, m;
        std::cin >> n >> m;
        std::vector<bool> row_used(n, false);
        std::vector<bool> col_used(m, false);
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int cell_val;
                std::cin >> cell_val;
                if (cell_val == 1) {
