int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_post_duration) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_post_duration) {
            // This post exceeds the target duration, so no solution
            std::cout << "No\n";
            return 0;
        }
    }

    // After iterating through all videos, we should have formed exactly k posts
    // and the last post's sum should have matched target_post_duration.
    // If current_post_sum is not 0, it means the last segment didn't sum up correctly.
    // This check is implicitly covered by posts_formed == k and current_post_sum == 0
    // (because if current_post_sum != 0, it means the last post wasn't completed,
    // or it exceeded the target, which would have been caught earlier).
    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally not be reached if the logic is correct,
        // as current_post_sum > target_post_duration would catch issues,
        // and if current_post_sum == target_post_duration, posts_formed would increment.
        // The only way posts_formed != k is if the last segment didn't sum up to target_post_duration
        // and current_post_sum was less than target_post_duration at the end,
        // which means total_sum was not divisible by k, but we checked that.
        // Or if total_sum was 0, but a_i are positive.
        // So this else branch is mostly a safeguard.
        std::cout << "No\n";
    }

    return 0;
}

