#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell index or -1 for cell 0

        // Iterate through the string to find 'R' positions
        // The string s has length n. s[i] corresponds to cell i+1.
        // So, cell 0 is before s[0].
        // Cell i+1 is s[i].
        // Cell n+1 is after s[n-1].

        // The distance from the starting point (0) to the first 'R' or to n+1 if no 'R's.
        // Or, the distance between consecutive 'R's.
        // Or, the distance from the last 'R' to n+1.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // Current 'R' is at cell i+1.
                // The previous safe point was last_R_pos (or 0 if last_R_pos == -1).
                // The distance needed to jump from last_R_pos to i+1 is (i+1) - last_R_pos.
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }

        // After iterating through all characters, consider the jump from the last 'R' cell
        // to the target cell n+1.
        // If no 'R's were found, last_R_pos is still -1.
        // In this case, the jump is from cell 0 to cell n+1.
        // The distance is (n+1) - 0 = n+1.
        // If 'R's were found, last_R_pos is the cell index of the last 'R'.
        // The distance is (n+1) - last_R_pos.
        max_dist = std::max(max_dist, (int)s.length() + 1 - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

