void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    std::vector<int> available_for_fill;

    // Determine p_i for indices where q_i > q_{i-1}
    // These p_i values are fixed and must be q_i.
    // Also collect values that are not yet used and are candidates for p_i where q_i == q_{i-1}.

    p[0] = q[0];
    used_values.insert(q[0]);

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i must be a new maximum.
                // But as a safety check, if q_i was already used, it's impossible.
                std::cout << -1 << "\n";
                return;
            }
            used_values.insert(q[i]);
        } else {
            // p_i needs to be filled later with an unused value < q_i
            p[i] = -1; // Placeholder
        }
    }

    // Populate available_for_fill with numbers from 1 to n that haven't been used yet.
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            available_for_fill.push_back(i);
        }
    }
    std::sort(available_for_fill.rbegin(), available_for_fill.rend()); // Sort in descending order

    // Fill the remaining p_i values
    for (int i = 0; i < n; ++i) {
        if (p[i] == -1) { // This means q[i] == q[i-1]
            if (available_for_fill.empty()) {
                // Not enough numbers to fill
                std::cout << -1 << "\n";
                return;
            }
            int val_to_fill = available_for_fill.back();
            available_for_fill.pop_back();

            if (val_to_fill > q[i]) {
                // The smallest available number is greater than q[i],
                // which means it cannot be p_i because p_i <= q_i.
                std::cout << -1 << "\n";
                return;
            }
            p[i] = val_to_fill;
        }
    }

    // Final check: Verify if the constructed p generates the given q
    // This check is crucial because the greedy strategy might fail if
    // the smallest available number is too large for a later slot.
    // However, by sorting available_for_fill in descending order and picking from back (smallest),
    // we ensure that we use the smallest possible value for each p_i where q_i == q_{i-1}.
    // This maximizes the chances of success.
    // The condition `val_to_fill > q[i]` already catches the impossibility.
    // The problem guarantees `q_i <= q_{i+1}`.
    // The only remaining check is if the constructed p actually produces the given q.
    // Let's re-calculate prefix maximums for p and compare with q.

    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            std::cout << -1 << "\n";
            return;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

