    int left = 1;
    int right = k + 1; // The largest difference we want to generate is k.
                       // This means we need numbers up to k+1 to get differences up to k.
                       // For example, if k=1, we need 1 and 2 to get difference 1.
                       // If k=2, we need 1, 2, 3 to get differences 1, 2.
                       // So, we use numbers from 1 to k+1 to generate the first k distinct differences.

    // Generate the first k distinct differences: k, k-1, ..., 1
    // This can be done by alternating between the smallest available number and the largest available number
    // from the range [1, k+1].
    // For example, if k=2, numbers are 1, 2, 3.
    // p_1 = 1
    // p_2 = 3 (diff = 2)
    // p_3 = 2 (diff = 1)
    // This gives differences {1, 2}.
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...)
            p[i] = left;
            left++;
        } else { // Odd index (1, 3, 5, ...)
            p[i] = right;
            right--;
        }
    }

    // After generating the first k+1 elements, we have used numbers from 1 to k+1.
    // The remaining numbers are from k+2 to n.
    // We need to append these remaining numbers in increasing order to ensure
    // the differences are always 1, which we already have in our set of k differences.
    // The last element generated was either 'left-1' or 'right+1'.
    // The next available number is 'left' (which is now k/2 + 1 if k is even, or (k+1)/2 + 1 if k is odd)
