void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.

        // For m > 1, we consider the number 'm'.
        // We need to expand the current segment [min_idx, max_idx] to include 'm'.
        // The new segment will span from min(current_min_idx, pos[m]) to max(current_max_idx, pos[m]).
        // This new segment must contain all numbers from 1 to m.
        // The minimum value in this new segment will be 1 (since 1 is already included).
        // The maximum value in this new segment will be m (since we are expanding to include m, and all numbers 1 to m-1 are already covered).
        // So, the only condition to check is if the length of this new segment is exactly m.

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

