#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int last_diff_01 = -1; // Index of the last '0' in a that needs to be '1' in b
    int last_diff_10 = -1; // Index of the last '1' in a that needs to be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] is '0', b[i] is '1' (needs to become '1')
                if (last_diff_10 != -1) { // Found a '1' in a that needs to be '0' in b
                    // We can swap a[last_diff_10] and a[i]
                    // This changes a[last_diff_10] from '1' to '0' (correct for b[last_diff_10])
                    // This changes a[i] from '0' to '1' (correct for b[i])
                    // Cost is |i - last_diff_10|
                    total_cost += (i - last_diff_10);
                    last_diff_10 = -1; // This '10' difference is resolved
                } else {
                    // No pending '10' difference to swap with.
                    // This '01' difference might be resolved by a future '10' difference,
                    // or it will eventually need a flip.
                    // Store its index.
                    last_diff_01 = i;
                }
            } else { // a[i] is '1', b[i] is '0' (needs to become '0')
                if (last_diff_01 != -1) { // Found a '0' in a that needs to be '1' in b
                    // We can swap a[last_diff_01] and a[i]
                    // This changes a[last_diff_01] from '0' to '1' (correct for b[last_diff_01])
                    // This changes a[i] from '1' to '0' (correct for b[i])
                    // Cost is |i - last_diff_01|
                    total_cost += (i - last_diff_01);
                    last_diff_01 = -1; // This '01' difference is resolved
                } else {
                    // No pending '01' difference to swap with.
                    // This '10' difference might be resolved by a future '01' difference,
                    // or it will eventually need a flip.
                    // Store its index.
                    last_diff_10 = i;
                }
            }
        }
    }

    // Any remaining 'last_diff_01' or 'last_diff_10' means there's an unresolved difference.
    // These must be resolved by flipping. Each flip costs 1.
    if (last_diff_01 != -1) {
        total_cost += 1;
    }
    if (last_diff_10 != -1) {
        total_cost += 1;
    }

    std::cout << total_cost << std::endl;

    return 0;
}

