int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x_i, find the maximum index 'right_ptr' such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, x[right_ptr] will be the largest coordinate satisfying the condition.
        // We can optimize this by not resetting right_ptr for each i, as it only moves forward.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // After the loop, right_ptr points to the first element that violates the condition
        // or is equal to n if all remaining elements satisfy it.
        // So, elements from i+1 to right_ptr-1 are potential x_k candidates.

        // The number of points between x_i and x[right_ptr-1] (inclusive) is (right_ptr - 1) - (i + 1) + 1
        // which simplifies to right_ptr - 1 - i.
        // Let this be 'm'. These are the points x_j and x_k that can be chosen.
        // We need to choose 2 points from these 'm' points.
        // The number of points available to choose from (excluding x_i) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let's call this 'num_available_points'.
        // These are points x_{i+1}, x_{i+2}, ..., x_{right_ptr-1}.
        // If we pick x_k from this range, then x_j must be chosen from x_{i+1}, ..., x_{k-1}.
        // The number of points available to choose from for x_j and x_k is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i.
        // If m >= 2, we can choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // The number of points available for j and k (excluding x_i) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let's denote this as `num_valid_points_after_i`.
        // These are points x[i+1], x[i+2], ..., x[right_ptr-1].
        // If `num_valid_points_after_i` is `m`, we need to choose 2 points from these `m` points.
        // The number of ways to choose 2 points from `m` points is `m * (m - 1) / 2`.

        long long m = (long long)(right_ptr - 1) - (i + 1) + 1; // Number of points x_j, x_k such that i < j < k and x_k - x_i <= d
