// Function to check if a prefix of length `len` is a permutation
// This function is optimized to use precomputed max_val and counts
bool is_permutation_prefix(int len, int max_val_prefix, const std::vector<int>& counts_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_val_prefix != len) return false; // Max element must be equal to length
    // Check if all numbers from 1 to len appear exactly once.
    // Since max_val_prefix == len, we only need to check if all counts are 1.
    // This is implicitly handled by checking if the sum of counts is `len`
    // and max_val_prefix is `len`. If max_val_prefix is `len`, and all numbers
    // are positive, and there are `len` numbers, then they must be 1 to `len`
    // each appearing once.
    // The `counts_prefix` vector is not directly used here for checking counts,
    // but rather the `max_val_prefix` and the fact that we are building it
    // from left to right, ensuring no duplicates up to `len` if `max_val_prefix == len`.
    // The `is_valid_prefix` array precomputes this.
    return true;
}

// Function to check if a suffix of length `len` is a permutation
// This function is optimized to use precomputed max_val and counts
bool is_permutation_suffix(int len, int max_val_suffix, const std::vector<int>& counts_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_val_suffix != len) return false; // Max element must be equal to length
    // Similar logic as is_permutation_prefix.
    // The `is_valid_suffix` array precomputes this.
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<bool> is_valid_prefix(n + 1, false);
    std::vector<int> prefix_counts(n + 1, 0); // Max value can be n-1, but using n+1 for 1-based indexing
    int current_max_prefix = 0;
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || val < 1) { // Values must be within [1, n] for a permutation of length up to n
            // This case should not happen based on constraints (1 <= a_i <= n-1)
            // but good to be robust. If it happens, no permutation is possible from this point.
            break;
        }

        if (prefix_counts[val] == 0) {
            distinct_count_prefix++;
        }
        prefix_counts[val]++;

        current_max_prefix = std::max(current_max_prefix, val);

        if (distinct_count_prefix == i + 1 && current_max_prefix == i + 1) {
            is_valid_prefix[i + 1] = true;
        }
    }

    // Precompute for suffixes
    std::vector<bool> is_valid_suffix(n + 1, false);
    std::vector<int> suffix_counts(n + 1, 0);
    int current_max_suffix = 0;
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        // The length of the suffix is (n - i)
        int suffix_len = n - i;

        if (val > n || val < 1) {
            break;
        }

        if (suffix_counts[val] == 0) {
            distinct_count_suffix++;
        }
        suffix_counts[val]++;

        current_max_suffix = std::max(current_max_suffix, val);

        if (distinct_count_suffix == suffix_len && current_max_suffix == suffix_len) {
            is_valid_suffix[suffix_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1 (so l1 < n)
        int l2 = n - l1;
        if (is_valid_prefix[l1] && is_valid_suffix[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

