void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let's try to append at most 3 elements.
    // A simple strategy is to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let X = current_xor_sum
    // Let S = current_sum
    // Append b1 = X
    // New XOR sum: X' = X ^ b1 = X ^ X = 0
    // New sum: S' = S + b1 = S + X
    // Now we need to append b2 such that (S + X + b2) = 2 * (0 ^ b2) = 2 * b2
    // S + X + b2 = 2 * b2
    // S + X = b2
    // So, b2 = S + X
    //
    // The elements to append are X and S+X.
    // Let's verify:
    // Original sum: S
    // Original XOR sum: X
    // Appended elements: X, S+X
    // New sum: S_new = S + X + (S+X) = 2S + 2X
    // New XOR sum: X_new = X ^ X ^ (S+X) = 0 ^ (S+X) = S+X
    //
    // Check condition: S_new = 2 * X_new
    // 2S + 2X = 2 * (S+X)
    // This is always true.
    //
    // The problem states we can append at most 3 elements.
    // This strategy appends 2 elements.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // S+X can be up to 10^14 + 10^9, which fits in long long.
    // The problem states appended elements can be up to 10^18, so this is fine.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

