#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int calculate_score(int n, const std::string& s) {
    if (n == 0) {
        return 0;
    }
    int score = 0;
    bool prev_won = false;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (prev_won) {
                score += 2;
            } else {
                score += 1;
            }
            prev_won = true;
        } else {
            prev_won = false;
        }
    }
    return score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) return 0; // Should not happen based on constraints n>=1
            std::cout << 1 + 2 * (n - 1) << "\n";
            continue;
        }

        if (initial_wins == 0 && k == 0) { // All L's, no changes
            std::cout << 0 << "\n";
            continue;
        }

        if (initial_wins == 0) { // All L's, but k > 0. Make one W.
            std::cout << 1 << "\n";
            continue;
        }

        // Strategy:
        // 1. Convert k 'L's to 'W's.
        // 2. Prioritize filling gaps between existing 'W's to create longer 'W' streaks.
        // 3. If k still remains, convert 'L's at the ends or in isolated 'L' blocks.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect lengths of 'L' segments between 'W's
        if (first_W != -1) { // If there's at least one 'W'
            int current_L_count = 0;
            for (int i = first_W + 1; i <= last_W; ++i) {
                if (s[i] == 'L') {
                    current_L_count++;
                } else { // s[i] == 'W'
                    if (current_L_count > 0) {
                        gaps.push_back(current_L_count);
                    }
                    current_L_count = 0;
                }
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_score = calculate_score(n, s);
        int changes_made = 0;

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W, adds 2 points. Connecting two W blocks adds 1 point.
                                                   // Example: W L L W -> W W W W. Score changes from (1+1) to (1+2+2+2).
                                                   // The L's become W's, each adding 2 points. The connection adds 1 point.
                                                   // W L W -> W W W. Score changes from (1+1) to (1+2+2).
                                                   // The L becomes W, adds 2 points. The connection adds 1 point.
                                                   // This is equivalent to: each L becomes W, adds 2 points.
                                                   // The original W's adjacent to the gap already contributed.
                                                   // When an L becomes W, it gets 2 points if prev is W.
                                                   // If it's the first L in a gap, it connects to a W, gets 2.
                                                   // If it's a middle L, it connects to a W, gets 2.
                                                   // If it's the last L, it connects to a W, gets 2.
                                                   // The W after the gap was getting 1 point (from L). Now it gets 2 (from W).
                                                   // So, for each L in the gap, it adds 2 points.
                                                   // And the W after the gap gets an extra 1 point.
                                                   // Total: 2 * gap_len + 1.
            } else {
                current_score += 2 * k; // Use remaining k to convert L's in this gap
                k = 0;
                break;
            }
        }

        // If k still remains, convert L's at the ends or in isolated blocks
        // Each such L converted to W adds 1 point (if it's the first W) or 2 points (if it extends a W streak).
        // Since we've filled all internal gaps, any remaining k will convert L's that are not between W's.
        // These will either extend existing W blocks or create new isolated W's.
        // Each such conversion adds 2 points if it extends a W block (e.g., LWW -> WWWW, adds 2 for L).
        // Or 1 point if it's the first W (e.g., LLL -> WLL, adds 1 for W).
        // The current_score already accounts for existing W's.
        // Each new W adds 1 point (base) + 1 point (if previous is W).
        // If we convert an L to W, it adds 1 point. If it connects to an existing W, it adds another 1 point.
        // So, each L converted to W adds 1 point. If it connects to an existing W, it adds another 1 point.
        // The `initial_wins` count is the number of W's we started with.
        // Each of these W's contributes 1 point. If it's preceded by a W, it contributes an additional 1 point.
        // The `current_score` already reflects the score after filling internal gaps.
        // Now we have `k` changes left. Each change converts an 'L' to a 'W'.
        // Each such 'W' will contribute 1 point. If it's adjacent to an existing 'W' (or another 'W' we just created), it contributes 2.
        // The most efficient way to use remaining `k` is to extend existing 'W' blocks.
        // Each 'L' converted to 'W' will add 2 points if it extends a 'W' block.
        // If it creates a new 'W' block, it adds 1 point.
        // Since we've filled internal gaps, any remaining 'L's are either before the first 'W', after the last 'W', or in blocks of 'L's that were not between 'W's.
        // If we convert an 'L' to 'W', it adds 1 point. If it connects to an existing 'W' (or another 'W' we just created), it adds another 1 point.
