#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // to move past this 'b' (and generate an extra 'b').
            // The 'count_a' here represents the number of 'a's
            // that are currently "active" and need to move past 'b's.
            // When an 'a' moves past a 'b', it effectively doubles
            // the number of 'a's that need to move past subsequent 'b's
            // (because 'ab' -> 'bba', the 'a' is still there, but now
            // it's followed by two 'b's instead of one).
            // So, when we encounter a 'b', we add the current 'count_a'
            // to the total steps.
            total_steps = (total_steps + count_a) % MOD;

            // After this 'b' is processed by all 'count_a' 'a's,
            // each of those 'a's will have effectively generated an
            // additional 'b' (from 'ab' -> 'bba').
            // So, the number of 'a's that need to move past *future* 'b's
            // (i.e., 'b's further to the left) effectively doubles.
            // This is because the original 'a' is still there, and it
            // will interact with the next 'b' to its left.
            // The 'b' generated by 'ab' -> 'bba' is to the right of 'a',
            // so it doesn't affect 'a's to its left.
            // The 'count_a' represents the number of 'a's that are
            // "waiting" to be processed by 'b's to their right.
            // When an 'a' interacts with a 'b', it effectively doubles
            // its "power" to interact with future 'b's.
            // So, count_a = (count_a * 2) % MOD.
            // This is the core logic: each 'a' effectively doubles its
            // contribution to future 'b's.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now
            // "active" and needs to be processed by 'b's to its right.
            // We increment the count of active 'a's.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

