    // We need to form the chain 1 -> 2 -> ... -> n. This requires n-1 "put" operations.
    // If we already have 1 -> 2 -> ... -> X, we don't need to perform X-1 "put" operations.
    // The number of "put" operations saved is (consecutive_one_two_chain_count - 1).
    // For example, if we have 1->2->3, we save 2 "put" operations (1 into 2, 2 into 3).
    // If consecutive_one_two_chain_count is 0 or 1, we save 0 operations.

    // Total "put" operations needed for the final chain is (n - 1).
    // The number of "put" operations we DON'T need to do is (consecutive_one_two_chain_count - 1).
    // So, actual "put" operations = (n - 1) - (consecutive_one_two_chain_count - 1)
    // = n - consecutive_one_two_chain_count.
    total_operations += (n - consecutive_one_two_chain_count);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <numeric>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // q can be up to 10^9, so its prime factors can be up to 10^9.
    // We need to iterate up to sqrt(q) to find prime factors.
    // If q remains > 1 after loop, it's a prime factor itself.
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    if (temp_q > 1) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    int overall_max_val = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                overall_max_val = std::max(overall_max_val, a[i][j]);
            }
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a[i][j]);
            }
        }
        // If max_val_for_i is less than the overall maximum value found in the matrix,
        // it means p[i] must be equal to max_val_for_i.
        // Otherwise, p[i] must be the largest possible value, which is n.
        if (max_val_for_i < overall_max_val) {
            p[i] = max_val_for_i;
        } else {
            p[i] = n;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string coloring(n, ' ');
        char last1_char = '0'; // Represents the last digit placed in color 1
        char last2_char = '0'; // Represents the last digit placed in color 2
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];

            if (current_digit < pivot_digit + '0') {
                // Must be color 1
                if (current_digit < last1_char) {
                    possible_with_pivot = false;
                    break;
                }
                coloring[i] = '1';
                last1_char = current_digit;
            } else if (current_digit > pivot_digit + '0') {
                // Must be color 2
                if (current_digit < last2_char) {
                    possible_with_pivot = false;
                    break;
                }
                coloring[i] = '2';
                last2_char = current_digit;
            } else { // current_digit == pivot_digit + '0'
                // Can be either color 1 or color 2
                // Prioritize color 1 if possible
                if (current_digit >= last1_char) {
                    coloring[i] = '1';
                    last1_char = current_digit;
                } else if (current_digit >= last2_char) {
                    coloring[i] = '2';
                    last2_char = current_digit;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
