void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, happiness is 2 * number.
    // To maximize, give them the largest available numbers.
    // These are the k largest numbers from 'a'.
    // The largest k numbers are a[n-k], a[n-k+1], ..., a[n-1].
    // We assign these to friends with w_i = 1.
    // Since we want to maximize, we give the largest numbers to these friends.
    // The largest k numbers are a[n-1], a[n-2], ..., a[n-k].
    // Each of these will contribute 2 * a_j to the total happiness.
    // This is equivalent to taking a[n-1] + a[n-1], a[n-2] + a[n-2], ..., a[n-k] + a[n-k].
    // This covers the 'max' part for all k friends, and the 'min' part for friends with w_i=1.

    // The k largest numbers from 'a' will be the 'max' element for each of the k friends.
    // So, we add a[n-1] + a[n-2] + ... + a[n-k] to total_happiness.
    // This is the sum of the largest k elements.
    for (int i = 0; i < k; ++i) {
        total_happiness += a[n - 1 - i];
    }

    // Now, we need to assign the 'min' elements for friends with w_i > 1,
    // and the second 'max' element for friends with w_i = 1 (which is the same as the 'max' element).
    // The friends with w_i = 1 are those with the largest w_i values (which are 1).
    // Since w is sorted, these are w[0], w[1], ..., w[count_ones-1].
    // The friends with w_i > 1 are those with w_i values from w[count_ones] to w[k-1].

    // Iterate through w from largest to smallest.
    // Friends with w_i = 1: their happiness is 2 * (largest available number).
    // We've already added one instance of these largest numbers.
    // So, for each w_i = 1, we add another instance of the largest available number.
    // These are the k largest numbers from 'a'.
    // The largest k numbers are a[n-1], a[n-2], ..., a[n-k].
    // We assign a[n-1] to the friend who gets w[k-1] items, a[n-2] to w[k-2], etc.
    // This is because we want to pair the largest 'max' values with the friends who need the fewest additional items.
    // The friends with w_i = 1 are at the beginning of the sorted 'w' array.
    // The friends with w_i > 1 are at the end of the sorted 'w' array.

    // Let's re-think the assignment.
    // The k largest numbers a[n-1], a[n-2], ..., a[n-k] will be the maximums for the k friends.
    // We add these to total_happiness.
    // total_happiness = sum(a[n-1]...a[n-k])

    // Now, for friends with w_i = 1, their happiness is max_val + min_val = max_val + max_val = 2 * max_val.
    // We've already added max_val once. So we need to add max_val again.
    // These are the friends with w_i = 1. They should get the largest possible max_val.
    // Since w is sorted, friends with w_i = 1 are at the beginning of the sorted w array.
    // We pair them with the largest available numbers from 'a'.
    // The largest numbers are a[n-1], a[n-2], ...
    // So, the friend with w[k-1] (largest w_i) gets a[n-1] as their max.
    // The friend with w[k-2] gets a[n-2] as their max.
    // ...
    // The friend with w[0] (smallest w_i) gets a[n-k] as their max.

    // Let's process friends with w_i = 1 first.
    // These friends need to get 2 * max_val.
    // We should give them the largest available numbers from 'a'.
    // These are a[n-1], a[n-2], ...
    // The number of friends with w_i = 1 is `std::count(w.begin(), w.end(), 1)`.
    // Let's iterate `w` from `k-1` down to `0`.
    // The largest `w_i` values are at the end of the sorted `w` array.
    // The smallest `w_i` values (which are 1) are at the beginning of the sorted `w` array.

    // We assign the largest `k` elements of `a` as the `max` for each friend.
    // `a_ptr_max` points to the largest available element in `a` for a `max` value.
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_max]; // Add the second instance of max_val for w_i=1 friends
            a_ptr_max--;
        } else {
            // These are friends with w_i > 1.
            // Their max is a[a_ptr_max].
            // Their min needs to be assigned from the smallest available numbers.
            // We need to skip w[i]-2 elements from the smallest end of 'a'
            // and assign the next smallest element as their min.
            // The smallest elements are a[0], a[1], ...
            // We use a_ptr_min to track the smallest available element.
            // The friend with w[i] items will take w[i]-1 items from the smallest available pool.
            // The smallest of these w[i]-1 items will be their min.
            // The largest of these w[i]-1 items will be discarded (not min/max).
            // To maximize happiness, we want to give the smallest possible min to friends with large w_i.
            // But we want to give the largest possible min to friends with small w_i (but > 1).
            // This means we should assign the smallest available numbers to friends who need to skip many numbers.
            // These are friends with large w_i.
            // So, we iterate w from largest to smallest.
            // The friend with w[k-1] (largest w_i > 1) gets a[a_ptr_max] as max, and a[a_ptr_min] as min.
            // They consume w[k-1]-1 elements from the smallest end.
            // The friend with w[k-2] (next largest w_i > 1) gets a[a_ptr_max-1] as max, and a[a_ptr_min + (w[k-1]-1)] as min.
            // This is getting complicated. Let's simplify.

            // The k largest numbers are a[n-1], a[n-2], ..., a[n-k]. These are the maxes.
            // Sum them up: total_happiness = sum(a[n-1]...a[n-k]).
            // This covers the 'max' part for all k friends.

