#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters and check for conflicts
    // If s[i] is '0' or '1', then s[i+k], s[i+2k], ... must be the same.
    // If s[i] is '?', it can be determined by s[i-k] or s[i+k].
    // We can iterate through the string and update '?' characters.
    // A simpler way is to iterate through the first k characters.
    // For each i from 0 to k-1, all s[i], s[i+k], s[i+2k], ... must be the same.
    // We can determine the character for s[i % k] based on the first non-'?' character in its "k-chain".

    bool possible = true;
    for (int i = 0; i < k; ++i) {
        char determined_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (determined_char == '?') {
                    determined_char = s[j];
                } else if (determined_char != s[j]) {
                    // Conflict found: s[j] is different from a previously determined character
                    possible = false;
                    break;
                }
            }
        }
        if (!possible) break;

        // If a character was determined for this chain, propagate it back to '?'s
        if (determined_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = determined_char;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check if the first k characters can form a k-balanced substring
    // After propagation, the first k characters s[0...k-1] are either '0', '1', or '?'.
    // All '?'s in s[0...k-1] can be replaced by '0' or '1' freely to satisfy the balance.
    // We just need to count the existing '0's and '1's in s[0...k-1].
    int count0 = 0;
    int count1 = 0;
    int count_q = 0; // count of '?' in the first k characters

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else { // s[i] == '?'
            count_q++;
        }
    }

    // For the first k characters to be k-balanced, we need k/2 zeros and k/2 ones.
    // We have `count0` zeros, `count1` ones, and `count_q` question marks.
    // We need `k/2 - count0` more zeros and `k/2 - count1` more ones.
    // These must come from the `count_q` question marks.
    // The number of required zeros must be non-negative: `k/2 - count0 >= 0` => `count0 <= k/2`.
    // The number of required ones must be non-negative: `k/2 - count1 >= 0` => `count1 <= k/2`.
    // The total number of required characters must not exceed `count_q`:
    // `(k/2 - count0) + (k/2 - count1) <= count_q`.
    // This simplifies to `k - (count0 + count1) <= count_q`.
    // Since `count0 + count1 + count_q = k` (for the first k characters),
    // `k - (count0 + count1)` is exactly `count_q`.
    // So the condition simplifies to `count0 <= k/2` and `count1 <= k/2`.

    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

