int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // To divide by 2, multiply by modular inverse of 2.
    // MOD is 10^9 + 7, which is prime.
    // Modular inverse of 2 is (MOD + 1) / 2 = (1000000007 + 1) / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    long long sum_k_term_b = (a * (a + 1) / 2) % MOD; // Sum of k from 1 to a
    long long sum_k_term_1 = a % MOD; // Sum of 1 from 1 to a

    long long total_sum = 0;

    // Calculate SUM_{k=1 to a} (k * b + 1)
    // This is (b * SUM(k)) + SUM(1)
    // = (b * (a * (a+1) / 2)) + a
    long long inner_sum_k_part = (b % MOD * sum_k_term_b) % MOD;
    inner_sum_k_part = (inner_sum_k_part + sum_k_term_1) % MOD;

    total_sum = (sum_r_term * inner_sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_L = dq.empty() ? 0 : L[dq.back()];
        long long prev_h = dq.empty() ? 0 : h[dq.back()];

        L[i] = std::min(h[i], prev_max_L + (i - (dq.empty() ? -1 : dq.back())));
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_R = dq.empty() ? 0 : R[dq.back()];
        long long prev_h = dq.empty() ? 0 : h[dq.back()];

        R[i] = std::min(h[i], prev_max_R + ((dq.empty() ? n : dq.back()) - i));
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

