            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val; // Now a[i] is a multiple of n
        }
        std::cout << "\n";

        // Operation 2: Segment [n, n]
        // The last element a[n-1] is not yet a multiple of n.
        // We want to add b_{n-1} such that a[n-1] + b_{n-1} is 0.
        // b_{n-1} must be a multiple of n (segment length is 1).
        // We know that sum(a_i) is now a multiple of n (because a[0]...a[n-2] are multiples of n, and a[n-1] is the only one left).
        // So a[n-1] must be a multiple of n.
        // We can just add -a[n-1] to make it 0.
        std::cout << n << " " << n << "\n";
        std::cout << -a[n - 1] << "\n";
        a[n - 1] = 0; // Now all elements are multiples of n, and a[n-1] is 0.

        // Operation 3: Segment [1, n]
        // All elements a[0]...a[n-2] are multiples of n. a[n-1] is 0.
        // We want to make all elements 0.
        // For each a[i], we add -a[i].
        // Since a[i] is a multiple of n, -a[i] is also a multiple of n.
        // The segment length is n. So -a[i] is a multiple of the segment length.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // current_val_if_input_bit_is_0[bit_pos]
    // current_val_if_input_bit_is_1[bit_pos]
    // Initialize: if input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
    std::array<int, 10> val_if_0;
    std::array<int, 10> val_if_1;
    for (int i = 0; i < 10; ++i) {
        val_if_0[i] = 0;
        val_if_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int i = 0; i < 10; ++i) {
            int bit_x = (x >> i) & 1;
            if (op_char == '&') {
                val_if_0[i] &= bit_x;
                val_if_1[i] &= bit_x;
            } else if (op_char == '|') {
                val_if_0[i] |= bit_x;
                val_if_1[i] |= bit_x;
            } else { // '^'
                val_if_0[i] ^= bit_x;
                val_if_1[i] ^= bit_x;
            }
        }
    }

    // Reconstruct the operations
    // We need to find A, B, C such that:
    // ( ( (input_bit & A_bit) | B_bit ) ^ C_bit ) == val_if_input_bit_is_1
    // ( ( (0 & A_bit) | B_bit ) ^ C_bit ) == val_if_input_bit_is_0

    // Let's try to find A, B, C for each bit position.
    // For each bit i:
    // ( (0 & A_i) | B_i ) ^ C_i = val_if_0[i]  => (0 | B_i) ^ C_i = val_if_0[i] => B_i ^ C_i = val_if_0[i]
    // ( (1 & A_i) | B_i ) ^ C_i = val_if_1[i]  => (A_i | B_i) ^ C_i = val_if_1[i]

    // From B_i ^ C_i = val_if_0[i], we have C_i = B_i ^ val_if_0[i].
    // Substitute C_i into the second equation:
    // (A_i | B_i) ^ (B_i ^ val_if_0[i]) = val_if_1[i]

    // Let's determine A_i, B_i, C_i for each bit position.
    // We can iterate through all 8 possible (val_if_0[i], val_if_1[i]) pairs.
    // For each pair, we need to find A_i, B_i, C_i.

    int final_and_val = 1023; // All bits set
    int final_or_val = 0;     // All bits clear
    int final_xor_val = 0;    // All bits clear

    for (int i = 0; i < 10; ++i) {
        int v0 = val_if_0[i];
        int v1 = val_if_1[i];

        // Case 1: v0=0, v1=0. Output is always 0.
        //   (x & 0) | 0 ^ 0 = 0
        //   A_i=0, B_i=0, C_i=0
        if (v0 == 0 && v1 == 0) {
            final_and_val &= ~(1 << i); // A_i = 0
            final_or_val &= ~(1 << i);  // B_i = 0
            final_xor_val &= ~(1 << i); // C_i = 0
        }
        // Case 2: v0=0, v1=1. Output is x.
        //   (x & 1) | 0 ^ 0 = x
        //   A_i=1, B_i=0, C_i=0
        else if (v0 == 0 && v1 == 1) {
            final_and_val |= (1 << i);  // A_i = 1
            final_or_val &= ~(1 << i);  // B_i = 0
            final_xor_val &= ~(1 << i); // C_i = 0
        }
        // Case 3: v0=1, v1=0. Output is !x.
        //   (x & 1) | 0 ^ 1 = !x
        //   A_i=1, B_i=0, C_i=1
        else if (v0 == 1 && v1 == 0) {
            final_and_val |= (1 << i);  // A_i = 1
            final_or_val &= ~(1 << i);  // B_i = 0
            final_xor_val |= (1 << i);  // C_i = 1
        }
        // Case 4: v0=1, v1=1. Output is always 1.
        //   (x & 0) | 1 ^ 0 = 1
        //   A_i=0, B_i=1, C_i=0
        else if (v0 == 1 && v1 == 1) {
            final_and_val &= ~(1 << i); // A_i = 0
            final_or_val |= (1 << i);   // B_i = 1
            final_xor_val &= ~(1 << i); // C_i = 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_val != 1023) { // If not all bits are 1, then & operation is needed
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If not all bits are 0, then | operation is needed
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If not all bits are 0, then ^ operation is needed
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        long long zeros_count = n - m;

        // If there are m ones, they divide the string into m+1 potential blocks of zeros.
        // For example, 10101 has 3 ones, 4 blocks of zeros (some might be empty).
        // To minimize zero-only substrings, distribute zeros as evenly as possible.
        // This means we want blocks of zeros to be as close in length as possible.
        // There will be (m+1) blocks of zeros.
        // Let k be the length of the smaller blocks.
        // Let k+1 be the length of the larger blocks.
        // Number of blocks of length k: (m+1) - (zeros_count % (m+1))
        // Number of blocks of length k+1: zeros_count % (m+1)

        long long num_blocks = m + 1;
        long long k = zeros_count / num_blocks; // Length of smaller blocks
        long long num_larger_blocks = zeros_count % num_blocks; // Number of blocks of length k+1
        long long num_smaller_blocks = num_blocks - num_larger_blocks; // Number of blocks of length k

        long long zero_substrings_to_subtract = 0;

        // Contribution from smaller blocks (length k)
        if (k > 0) {
            zero_substrings_to_subtract += num_smaller_blocks * (k * (k + 1) / 2);
        }

        // Contribution from larger blocks (length k+1)
        if (k + 1 > 0) { // This condition is always true if k >= 0
            zero_substrings_to_subtract += num_larger_blocks * ((k + 1) * (k + 2) / 2);
        }

        std::cout << total_substrings - zero_substrings_to_subtract << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // balance_L[i] = (count of 1s in a_1...a_i) - (count of 2s in a_1...a_i)
    // We are interested in the balance of jars *remaining* on the left side.
    // If k_L jars are removed from the left, jars a_{k_L+1} ... a_n remain.
    // This is equivalent to considering the suffix a_{k_L+1} ... a_n.
    // Or, we can consider the prefix a_1 ... a_k_L that are *removed*.
    // Let's define balance_L[k] as the balance of the first k jars (a_0 to a_{k-1}).
    // So, balance_L[0] = 0.
    // balance_L[k] = balance of jars a_0 ... a_{k-1}.
    // The jars Karlsson can remove from the left are a_0, a_1, ..., a_{n-1}.
    // If he removes k jars from the left, these are a_0, ..., a_{k-1}.
    // The balance of these k removed jars is `prefix_balance_left[k]`.
    // The indices for the left side are 0 to n-1.
    std::vector<int> prefix_balance_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_balance_left[i + 1] = prefix_balance_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // The indices for the right side are n to 2n-1.
    // If he removes k jars from the right, these are a_{2n-1}, a_{2n-2}, ..., a_{2n-k}.
    // Let's define suffix_balance_right[k] as the balance of the last k jars (a_{2n-k} to a_{2n-1}).
    // suffix_balance_right[0] = 0.
    // suffix_balance_right[k] = balance of jars a_{2n-k} ... a_{2n-1}.
    std::vector<int> suffix_balance_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        suffix_balance_right[i + 1] = suffix_balance_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain balance
    // for the *removed* jars.
    // map_left[balance_val] = k_L (min jars removed from left to get this balance)
    std::map<int, int> map_left;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_balance_removed_left = prefix_balance_left[k_L];
        if (map_left.find(current_balance_removed_left) == map_left.end()) {
            map_left[current_balance_removed_left] = k_L;
        }
    }

    int min_total_removed = 2 * n; // Max possible jars to remove

    // Iterate through all possible numbers of jars removed from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_balance_removed_right = suffix_balance_right[k_R];

        // The total balance of all 2n jars is `prefix_balance_left[n] + suffix_balance_right[n]`.
        // No, this is not correct. The total balance is `prefix_balance_left[2n]`.
        // Let's calculate the total initial balance of all 2n jars.
        int total_initial_balance = 0;
        for (int x : a) {
            total_initial_balance += (x == 1 ? 1 : -1);
        }

        // If k_L jars are removed from left and k_R jars from right:
        // Balance of removed jars = (balance of a_0...a_{k_L-1}) + (balance of a_{2n-k_R}...a_{2n-1})
        // Let this be `balance_removed`.
        // `balance_removed = prefix_balance_left[k_L] + suffix_balance_right[k_R]`.
        // Balance of remaining jars = `total_initial_balance - balance_removed`.
        // We want `total_initial_balance - balance_removed = 0`.
        // So, we need `balance_removed = total_initial_balance`.
        // This means `prefix_balance_left[k_L] + suffix_balance_right[k_R] = total_initial_balance`.
        // We are looking for `prefix_balance_left[k_L] = total_initial_balance - suffix_balance_right[k_R]`.

        int target_balance_from_left = total_initial_balance - current_balance_removed_right;

        if (map_left.count(target_balance_from_left)) {
            int k_L = map_left[target_balance_from_left];
            min_total_removed = std::min(min_total_removed, k_L + k_R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, or any small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, (1LL << k) <= X + 1

        // Iterate k from 60 down to 0 to find the largest k
        // (1LL << 60) is approx 10^18, X is up to 10^9, so k won't exceed 30 for X.
        // However, we need to consider the case where X is large and we are looking for the largest power of 2.
        // The maximum value for k such that 2^k - 1 fits in long long is 62 (2^63-1).
        // For X up to 10^9, k will be at most 29 (2^29 - 1 < 10^9, 2^30 - 1 > 10^9).
        // So, k can be found by iterating from 29 down to 0.
        // Or, more generally, use `std::log2` or `std::bit_width` (C++20) or `__builtin_clzll` (GCC/Clang).
        // Since X is up to 10^9, `std::log2(X+1)` is safe.

        if (X == 1) { // Special case for X=1, k=0, 2^0-1=0, but we need 1 element.
            k = 0;
        } else {
            k = static_cast<long long>(std::log2(X + 1));
            // Ensure (1LL << k) - 1 <= X
            if (((1LL << k) - 1) > X) {
                k--;
            }
        }

        // If k is 0, it means X is 1. We add one element.
        // If k is 1, it means X is 2 or 3. We add one element.
        // If k is 2, it means X is 4, 5, 6, 7. We add one element.
        // The number of elements to add is k+1.
        // For example, if X=1, k=0. We add 1 element.
        // If X=3, k=1. We add 2 elements.
        // If X=7, k=2. We add 3 elements.
        // If X=10, k=3. We add 4 elements. (2^3-1 = 7 <= 10, 2^4-1 = 15 > 10)

        // The number of elements to add for this block is k+1.
        // This is because a block of `m` identical elements contributes `2^m - 1` subsequences.
        // If we want to contribute `2^k - 1` subsequences, we need `k` identical elements.
        // However, the problem statement implies that if we add `k` elements, we get `k` subsequences of size 1,
        // `k*(k-1)/2` subsequences of size 2, etc.
        // The logic is that if we add `m` elements, they form `2^m - 1` subsequences.
        // So, if we want to account for `2^k - 1` subsequences, we need `k` elements.
        // The `k` here is the exponent.

        // Let's re-evaluate the number of elements to add.
        // If we add `m` elements, they contribute `2^m - 1` subsequences.
        // We want to find `m` such that `2^m - 1` is the largest possible value less than or equal to `X`.
        // So, `m = k` where `k` is the exponent.
        // For example, if X=10, largest `2^m-1 <= 10` is `2^3-1 = 7`. So `m=3`.
        // We add 3 elements.

        long long num_elements_in_block = k;
        if (k == 0 && X == 1) { // Special case for X=1, we need to add 1 element.
            num_elements_in_block = 1;
        } else if (k == 0 && X > 1) { // This should not happen if k is calculated correctly.
            // If X is 2, k=1. If X is 1, k=0.
            // If X is 0, loop terminates.
            // So k=0 implies X=1.
        }

        for (long long i = 0; i < num_elements_in_block; ++i) {
            result_array.push_back(current_val);
        }

        X -= ((1LL << num_elements_in_block) - 1);

        // Move to the next block of numbers.
        // The next block's minimum element must be at least `current_val + d`.
        // To ensure `max - min < d` for subsequences within this block,
        // and `max - min >= d` for subsequences spanning across blocks.
        current_val += d;
    }

    if (result_array.size() > 10000) {
        // This case should not be reached given X <= 10^9.
        // Max elements for X=10^9:
        // X=10^9. k=29. Add 29 elements. X -= (2^29-1). X approx 10^9 - 5*10^8 = 5*10^8.
        // k=28. Add 28 elements. X -= (2^28-1). X approx 5*10^8 - 2.5*10^8 = 2.5*10^8.
        // ...
        // This is like a binary representation. The number of elements will be sum of exponents.
        // Max sum of exponents for X=10^9 is roughly 29 + 28 + ... + 1 = 29*30/2 = 435.
        // So, the array size will be well within 10000.
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k is less than the minimum number of moves required to reach (n, m)
        // The minimum moves is max(n, m) because each move can change at most one coordinate by 1
        // or both by 1. To cover a distance of N in one coordinate and M in another,
        // we need at least max(N, M) moves.
        if (k < n) { // Since n >= m, this is equivalent to k < max(n, m)
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k and (n+m) have different parities.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // (x_new + y_new) - (x_old + y_old) = (dx + dy).
        // dx, dy are in {-1, 0, 1}.
        // If dx=0, dy=0, not a move.
        // If dx=0, dy!=0 (straight vertical), sum changes by +/-1.
        // If dx!=0, dy=0 (straight horizontal), sum changes by +/-1.
        // If dx!=0, dy!=0 (diagonal), sum changes by +/-2 or 0.
        // In all cases, (x_new + y_new) and (x_old + y_old) have different parities if it's a straight move,
        // and same parities if it's a diagonal move.
        //
        // Alternatively, consider the parity of (x+y) after k moves.
        // Start at (0,0), so initial (x+y) is 0 (even).
        // After 1 move, (x+y) can be -2, -1, 0, 1, 2.
        //   - If diagonal, (x+y) changes by 0, +/-2 (even change), so (x+y) remains even.
        //   - If straight, (x+y) changes by +/-1 (odd change), so (x+y) becomes odd.
        //
        // Let d be diagonal moves, s be straight moves. k = d + s.
        // Parity of (final_x + final_y) is (initial_x + initial_y) + s * (odd_change) + d * (even_change)
        // Parity of (n+m) is (0+0) + s * (odd_change) mod 2
        // Parity of (n+m) is s mod 2.
        //
        // Also, k = d + s. So s = k - d.
        // Parity of (n+m) is (k - d) mod 2.
        //
        // This means (n+m) and (k-d) must have the same parity.
        // If (n+m) and k have different parities, then (k-d) must have different parity than k,
        // which means d must be odd.
        // If (n+m) and k have the same parity, then (k-d) must have same parity as k,
        // which means d must be even.
        //
        // A simpler way:
        // Each move changes the parity of x or y or both.
        // A diagonal move changes both x and y, so (x_new - x_old) and (y_new - y_old) are both odd.
        // A straight move changes one coordinate, so one of (x_new - x_old) or (y_new - y_old) is odd, the other is even.
        //
        // Consider the parity of (n+m) and k.
        // If (n+m) is even:
        //   If k is even, it's possible.
        //   If k is odd, it's impossible.
        // If (n+m) is odd:
        //   If k is even, it's impossible.
        //   If k is odd, it's possible.
        //
        // This can be summarized as: (n+m) and k must have the same parity.
        // (n+m) % 2 == k % 2
        // If (n+m) % 2 != k % 2, it's impossible.
        //
        // Exception: If n == m, and k has different parity than n+m, it's still possible if k >= n+2.
        // Example: (2,2) in 3 moves. n+m=4 (even), k=3 (odd). Parity mismatch.
        // But (0,0)->(1,0)->(1,1)->(2,2) is 1 diagonal, 2 straight. Total 3 moves.
        // (n+m) = 4 (even), k = 3 (odd).
        // The rule (n+m)%2 == k%2 is for the case where we only use diagonal moves and straight moves that move towards the target.
        // We can always make two extra moves (e.g., (x,y) -> (x+1,y) -> (x,y)) to change the parity of k without changing (n,m).
        // This costs 2 moves and changes the parity of k.
        // So if (n+m)%2 != k%2, we need at least 2 extra moves.
        // This means k must be at least n+2.
        //
        // Let's re-evaluate the parity condition.
        // The minimum number of moves to reach (n,m) is `n` (since n >= m).
        // This path can be constructed by `m` diagonal moves and `n-m` straight moves.
        // Total moves = `m + (n-m) = n`.
        // The parity of (n+m) for this path is `(n+m)`.
        // The parity of `n` (total moves) is `n`.
        //
        // If `n` and `n+m` have different parities, it means `m` is odd.
        // If `n` and `n+m` have same parity, it means `m` is even.
        //
        // The parity of the sum of coordinates (x+y) changes by 1 for each straight move, and by 0 for each diagonal move.
        // So, (n+m) % 2 == (number of straight moves) % 2.
        // Let `s` be the number of straight moves.
        // We have `k = d + s`.
        // So `s = k - d`.
        // Thus, `(n+m) % 2 == (k - d) % 2`.
        // This means `(n+m)` and `(k-d)` must have the same parity.
        //
        // If `n` and `k` have different parities, we need to make an even number of moves to change the parity of `k`
        // to match `n`. For example, move (x,y) -> (x+1,y) -> (x,y). This uses 2 moves, changes no net position,
        // and changes the parity of total moves.
        //
        // The target (n,m) has a fixed parity for (n+m).
