    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        // Apply v_i cry effect and initial d_j cry effect
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply total_d_cry_from_leaving first
            children[j].p -= total_d_cry_from_leaving;

            // Apply v_i cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back to the graph

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding vertex k and updating paths, we need to re-check all pairs
        // among currently active vertices. This is because adding k might have
        // created a shorter path between two *already active* vertices i and j
        // that now passes through k.
        // The previous loop (i,j,k) handles paths i->k->j.
        // We also need to handle paths k->i->j and i->j->k.
        // The standard Floyd-Warshall structure is k (outer loop), i, j (inner loops).
        // So, when k is added, it becomes the new intermediate vertex.
        // The loops above correctly update dist[i][j] using k as an intermediate.
        // However, we also need to update paths involving k itself.
        // For example, dist[k][j] might be shortened by k->i->j.
        // And dist[i][k] might be shortened by i->j->k.
        // The standard Floyd-Warshall structure handles this naturally.
        // Let's re-evaluate the loops for clarity.

        // When vertex k is added, it can be an intermediate for any pair (i, j)
        // where i, j are already active or k itself.
        // The standard Floyd-Warshall update is:
        // dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This needs to be applied for all active i, j.
        // The loops above do this.
        // But what if i or j is k?
        // dist[k][j] = min(dist[k][j], dist[k][k] + dist[k][j]) -> no change as dist[k][k]=0
        // dist[i][k] = min(dist[i][k], dist[i][k] + dist[k][k]) -> no change as dist[k][k]=0
        // So the loops above are correct for updating paths *through* k.

        // However, the problem is that when we add k, it might also be that
        // an existing path between i and j (both active) is now shorter
        // because it uses k as an endpoint.
        // Example: i -> k -> j. This is covered.
        // Example: k -> i -> j. This means dist[k][j] might be updated.
        // Example: i -> j -> k. This means dist[i][k] might be updated.
        // The standard Floyd-Warshall algorithm iterates k as the intermediate vertex.
        // So, when we add vertex `k` (in the reverse order), we are essentially
        // performing the `k`-th iteration of Floyd-Warshall.
        // The correct way to do this is:
        // For each `i` (active):
        //   For each `j` (active):
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //     dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k]) // This is wrong, j is not necessarily intermediate for i->k
        //     dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j]) // This is wrong, i is not necessarily intermediate for k->j

        // Let's stick to the standard Floyd-Warshall update logic.
        // When vertex `k` is added, it can serve as an intermediate vertex.
        // So, for all pairs `(i, j)` that are currently active (including `k` itself),
        // we update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // This means `i` and `j` can be any of the currently active vertices.
        // The loops should be:
        // for (int i_node = 0; i_node < n; ++i_node) {
        //     if (!active[i_node]) continue;
        //     for (int j_node = 0; j_node < n; ++j_node) {
        //         if (!active[j_node]) continue;
        //         dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
        //     }
        // }
        // This is what the first set of loops does.
        // However, this only considers `k` as the *last* intermediate vertex.
        // Floyd-Warshall's `k` loop means "consider paths that can use vertices up to `k` as intermediates".
        // So, when `k` is added, it means we can now use `k` as an intermediate.
        // The correct update for Floyd-Warshall when adding a vertex `k` is:
        // 1. For all `i, j` (including `k`): `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])` for all `p` active.
        // 2. For all `i, j` (including `k`): `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])` for all `p` active.
        // 3. For all `i, j` (including `k`): `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.

        // Let's refine the update logic for adding vertex `k`.
        // When `k` becomes active, it can potentially shorten paths in three ways:
        // 1. Path `i -> j` now goes `i -> k -> j`. (This is `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`)
        // 2. Path `i -> k` now goes `i -> p -> k` for some active `p`. (This is `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])`)
        // 3. Path `k -> j` now goes `k -> p -> j` for some active `p`. (This is `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])`)

        // The standard Floyd-Warshall algorithm structure is:
        // for k from 0 to n-1:
        //   for i from 0 to n-1:
        //     for j from 0 to n-1:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // When we add vertices in reverse order, `x_n, x_{n-1}, ..., x_1`,
        // the `k` in Floyd-Warshall corresponds to the vertex being added.
        // So, the `k` loop should be the outermost.
        // The `i` and `j` loops should iterate over all *currently active* vertices.

        // Corrected update for adding vertex `k`:
        // The `k` vertex is now available as an intermediate.
        // We need to update all `dist[i][j]` for active `i, j` (including `k`).
        // This means `i` and `j` can be any of the vertices that are currently active.
        // The `k` in Floyd-Warshall is the *newest* vertex allowed as an intermediate.
        // So, for every pair `(i, j)` where `i` and `j` are currently active (including `k` itself),
        // we check if `dist[i][k] + dist[k][j]` is shorter than `dist[i][j]`.
        // This is exactly what the first set of loops does.
        // However, this is not enough. The `k` in Floyd-Warshall means "all paths using intermediate vertices `0...k`".
        // When we add `k`, it means `k` can be an intermediate.
        // But `k` itself can also be an endpoint.
        // So, we need to update `dist[i][k]` and `dist[k][j]` using other active vertices as intermediates.
        // This implies a full Floyd-Warshall step for the current set of active vertices.

        // Let's use the standard Floyd-Warshall structure, but only for active vertices.
        // When `k` is added, it means `k` can now be an intermediate.
        // So, for all `i` and `j` that are currently active (including `k`):
        // `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // This is the standard Floyd-Warshall update.
        // The loops should be:
        // for (int i_node = 0; i_node < n; ++i_node) {
        //     for (int j_node = 0; j_node < n; ++j_node) {
        //         if (active[i_node] && active[j_node]) { // Only update if both i_node and j_node are active
        //             dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
        //         }
        //     }
        // }
        // This is still not quite right. The `k` in Floyd-Warshall is the *highest indexed* vertex allowed as an intermediate.
        // Here, `k` is just *one specific* vertex being added.
        // The correct approach for adding a vertex `k` to an existing graph `G'` (with active vertices `V'`)
        // and computing all-pairs shortest paths in `G' U {k}` is:
        // 1. Initialize `dist[k][v]` and `dist[v][k]` for all `v` in `V'` from original graph.
        // 2. For each `v` in `V'`:
        //    `dist[k][v] = min(dist[k][v], dist[k][u] + dist[u][v])` for all `u` in `V'`.
        //    `dist[v][k] = min(dist[v][k], dist[v][u] + dist[u][k])` for all `u` in `V'`.
        // 3. For each `i, j` in `V'`:
        //    `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.

        // Let's re-evaluate the loops.
        // When `k` is added, it can be an intermediate for any pair `(i, j)` where `i, j` are currently active.
        // It can also be an endpoint `(i, k)` or `(k, j)`.
        // The standard Floyd-Warshall `k` loop means "consider paths that can use vertex `k` as an intermediate".
        // So, for all `i` and `j` that are currently active (including `k` itself), we update `dist[i][j]`.
        // This means `i` and `j` can be any of the vertices that are currently active.
        // The loops should be:
        // for (int i_node = 0; i_node < n; ++i_node) {
        //     if (!active[i_node]) continue;
        //     for (int j_node = 0; j_node < n; ++j_node) {
        //         if (!active[j_node]) continue;
        //         dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
        //     }
        // }
        // This is the correct update for `k` as an intermediate.
        // But we also need to update paths like `k -> i -> j` and `i -> j -> k`.
        // This means `k` itself can be an endpoint, and other active vertices `p` can be intermediates.
        // So, for the newly added vertex `k`:
        // For all `p` that are active (including `k`):
        //   For all `i` that are active (including `k`):
        //     `dist[k][i] = min(dist[k][i], dist[k][p] + dist[p][i])`
        //     `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])`
        // This is essentially running Floyd-Warshall on the current set of active vertices,
        // where `k` is the *newest* vertex that can be used as an intermediate.

        // The standard Floyd-Warshall algorithm is:
        // for k_fw from 0 to n-1:
        //   for i_fw from 0 to n-1:
        //     for j_fw from 0 to n-1:
        //       dist[i_fw][j_fw] = min(dist[i_fw][j_fw], dist[i_fw][k_fw] + dist[k_fw][j_fw])
        //
        // In our reverse approach, `k` is the vertex being added.
        // So, the `k` in the Floyd-Warshall loop is our `k` (the vertex `x[k_idx]`).
        // The `i` and `j` loops should iterate over all vertices that are currently active.
        // This means `i` and `j` can be any of the vertices that are currently active.
        // The loops should be:
        for (int i_node = 0; i_node < n; ++i_node) {
            if (!active[i_node]) continue;
            for (int j_node = 0; j_node < n; ++j_node) {
                if (!active[j_node]) continue;
                // Update paths using k as an intermediate
                dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
                // Update paths where k is an endpoint, using i_node as intermediate
                dist[k][j_node] = std::min(dist[k][j_node], dist[k][i_node] + dist[i_node][j_node]);
                dist[i_node][k] = std::min(dist[i_node][k], dist[i_node][j_node] + dist[j_node][k]);
            }
        }
        // The above three lines are redundant and incorrect.
        // The standard Floyd-Warshall update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // when `k` is the outermost loop variable, correctly updates all paths.
        // The `i` and `j` loops should iterate over *all* vertices, and the `active` check should be inside.
        // Let's rewrite the update logic to be exactly like Floyd-Warshall, but only considering active vertices.

        // When vertex `k` is added, it becomes the new "highest index" vertex allowed as an intermediate.
        // So, we run the Floyd-Warshall update for this `k`.
        // The `i` and `j` loops should iterate over all currently active vertices.
        // This means `i` and `j` can be any of the vertices that are currently active.
        // The loops should be:
        for (int i_node = 0; i_node < n; ++i_node) {
            if (!active[i_node]) continue;
            for (int j_node = 0; j_node < n; ++j_node) {
                if (!active[j_node]) continue;
                // Update paths using k as an intermediate
                dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
            }
        }
        // This is still not enough. The problem is that `dist[i_node][k]` and `dist[k][j_node]`
        // themselves might need to be updated using other active vertices as intermediates.
        // For example, if `k` is added, and `i_node` and `p_node` are already active,
        // then `dist[i_node][k]` might be `dist[i_node][p_node] + dist[p_node][k]`.
        // This means we need to run the Floyd-Warshall update for `k` as an intermediate,
        // but also for all *other* active vertices as intermediates for paths involving `k`.

        // The correct way to integrate a new vertex `k` into an existing APSP solution:
        // 1. For all `i` that are active (including `k`):
        //    For all `j` that are active (including `k`):
        //       `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // This is the standard Floyd-Warshall update.
        // The key is that `dist[i][k]` and `dist[k][j]` must already reflect shortest paths
        // using only vertices *other than k* as intermediates.
        // But in our setup, `dist` matrix always stores paths using *all* vertices up to `k_idx` (in reverse).
        // So, when `k` is added, `dist[i][k]` and `dist[k][j]` are the original edge weights.
        // We need to update `dist[i][k]` and `dist[k][j]` using other active vertices as intermediates first.

        // Let's use the standard Floyd-Warshall structure, but with `k` as the outermost loop.
        // The `k` in Floyd-Warshall is the vertex that is *now allowed* as an intermediate.
        // So, when `x[k_idx]` (let's call it `current_k`) is added:
        // For all `i` that are active (including `current_k`):
        //   For all `j` that are active (including `current_k`):
        //     For all `p` that are active (including `current_k`):
        //       `dist[i][j] = min(dist[i][j], dist[i][p] + dist[p][j])`
        // This is running full Floyd-Warshall on the current active set. This is `O(N_active^3)`.
        // `N_active` goes from 1 to `n`. Total `O(N^4)`. Still too slow.

        // The standard reverse Floyd-Warshall trick is:
        // The `k` in Floyd-Warshall is the *highest-indexed* vertex allowed as an intermediate.
        // So, when we add `x[k_idx]` (let's call it `v_add`), it means `v_add` is now allowed as an intermediate.
        // The `dist` matrix already contains shortest paths using all vertices *before* `v_add` (in the reverse order).
        // So, we just need to apply the `v_add` iteration of Floyd-Warshall.
        // For all `i` that are active (including `v_add`):
        //   For all `j` that are active (including `v_add`):
        //     `dist[i][j] = min(dist[i][j], dist[i][v_add] + dist[v_add][j])`
        // This is the correct update. The `dist[i][v_add]` and `dist[v_add][j]` values
        // are already the shortest paths using only vertices *other than `v_add`* as intermediates.
        // This is because the `dist` matrix is being built up.
        // The `dist` matrix at any point `k_idx` (in reverse) stores shortest paths
        // using only vertices `x[k_idx], x[k_idx+1], ..., x[n-1]` as intermediates.

        // Let's re-verify the loops for the Floyd-Warshall update.
        // `k` is the vertex being added.
        // `i` and `j` are any two vertices that are currently active.
        // The `dist` matrix stores the current shortest paths.
        // When `k` is added, it can be an intermediate.
        // So, for every pair `(i, j)` of currently active vertices, we check if `i -> k -> j` is shorter.
        // This means `i` and `j` must be active.
        // `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // This is the standard Floyd-Warshall update.
        // The `dist[i][k]` and `dist[k][j]` values are the shortest paths between `i` and `k`, and `k` and `j` respectively,
        // using only the vertices that were active *before* `k` was added as intermediates.
        // This is correct.

        // The loops should be:
        for (int i_node = 0; i_node < n; ++i_node) {
            for (int j_node = 0; j_node < n; ++j_node) {
                // Update paths using k as an intermediate
                // This is the standard Floyd-Warshall update.
                // It implicitly handles paths like i->k, k->j, k->k.
                dist[i_node][j_node] = std::min(dist[i_node][j_node], dist[i_node][k] + dist[k][j_node]);
            }
        }
        // After this, `dist` matrix contains shortest paths using `k` and all previously added vertices as intermediates.
        // Now, calculate the sum for all *currently active* pairs.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Problem states v != u
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a with a very large value.
    // This value will be an upper bound for a[i] + current_delta[i]
    // for any type 2 operation that covers index i.
    // Since m_i can be up to 5*10^7, and d_i up to 10^4,
    // and there are 5000 operations, current_delta[i] can be up to 5000 * 10^4 = 5*10^7.
    // So initial_a[i] could be around 5*10^7 - 5*10^7 = 0.
    // Or initial_a[i] could be 5*10^7 - (-5*10^7) = 10^8.
    // A safe upper bound for a[i] + current_delta[i] is 5*10^7.
    // So, a[i] <= 5*10^7 - current_delta[i].
    // We need to find the minimum possible a[i] that satisfies all constraints.
    // Let's initialize initial_a[i] to a large positive value,
    // effectively saying a[i] can be anything up to this point.
    // The maximum possible value for m_i is 5*10^7.
    // The minimum possible value for m_i is -5*10^7.
    // The maximum possible delta is 5000 * 10^4 = 5*10^7.
    // The minimum possible delta is 5000 * (-10^4) = -5*10^7.
    // So a[i] = m_i - delta[i] can range from -5*10^7 - 5*10^7 = -10^8
    // to 5*10^7 - (-5*10^7) = 10^8.
    // The problem states |a_i| <= 10^9.
    // Let's initialize `initial_a[i]` to `m_i - current_delta[i]` for type 2 operations.
    // For indices not covered by any type 2 operation, their initial value can be 0.
    // For indices covered by type 2 operations, `a[i]` must be less than or equal to `m_i - current_delta[i]`.
    // So, we want to find the maximum possible `a[i]` that satisfies all `a[i] <= m_k - delta_k[i]` constraints.
    // This means `a[i]` should be `min(m_k - delta_k[i])` over all relevant `k`.
    // Initialize `initial_a[i]` to a very large value (e.g., 10^9 + 7) to represent no upper bound yet.
    std::vector<long long> initial_a(n, 2000000000LL); // A value larger than 10^9

    // Calculate the delta for each index for each operation.
    // This is effectively a prefix sum array for deltas.
    // `delta_at_op[k][j]` stores the sum of `d` values for index `j`
    // after `k` operations.
    // This is too much memory. Instead, we can calculate `current_delta` on the fly.

    // First pass: Determine upper bounds for initial_a[i]
    // For each type 2 operation (2, l, r, m_i), we know that for all j in [l, r],
    // initial_a[j] + current_delta[j] <= m_i.
    // So, initial_a[j] <= m_i - current_delta[j].
    // We need to find the minimum of these upper bounds for each initial_a[j].

    std::vector<long long> current_delta(n, 0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                initial_a[j] = std::min(initial_a[j], op.val - current_delta[j]);
            }
        }
    }

    // For elements not constrained by any type 2 operation, set them to 0.
    // Or rather, if initial_a[j] is still 2*10^9, it means it was never constrained.
    // We can set it to 0, as 0 satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == 2000000000LL) {
            initial_a[i] = 0;
        }
        // Check if the determined initial_a[i] is within bounds
        if (initial_a[i] > 1000000000LL || initial_a[i] < -1000000000LL) {
            // This case should ideally not happen if a solution exists,
            // as m_i - current_delta[j] should be within reasonable bounds.
            // However, if it does, it implies no valid initial_a[i] exists.
            // For example, if m_i is -5*10^7 and current_delta[j] is 5*10^7,
            // then initial_a[j] could be -10^8, which is fine.
            // If m_i is 5*10^7 and current_delta[j] is -5*10^7,
            // then initial_a[j] could be 10^8, which is fine.
            // The 10^9 limit is for the initial array elements.
            // If initial_a[i] is outside this range, it's an invalid solution.
            // This check is important.
            std::cout << "NO\n";
            return 0;
        }
    }

    // Second pass: Verify the solution
    // Apply all operations to the constructed initial_a and check type 2 constraints.
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x can also become large, but it's an index, so it's bounded by n or termination.
// However, x can become negative or exceed n, so it's fine.

// Memoization table for results of (start_x, start_y_offset)
// dp[x_val][0] stores the final x value
// dp[x_val][1] stores the final y value (relative to initial y)
// dp[x_val][2] stores a flag: 0 for not computed, 1 for terminating, 2 for infinite loop
std::vector<std::vector<long long>> dp;
std::vector<int> visited_states; // To detect cycles in the current path

int N;
std::vector<long long> A_values; // Stores a_2, ..., a_n. A_values[0] corresponds to a_2.

// Recursive function to calculate the final y value and x value
// for a given starting x and an initial a_1 value.
// The 'current_a1' is the value of a_1 for the current simulation.
// The 'start_x' is the initial x value for this subproblem (always 1 for the main calls).
// The 'initial_y_offset' is the y value accumulated before this subproblem starts.
// Returns a pair: {final_x, final_y_total}.
// If infinite loop, returns {0, -1} (or any distinct indicator).
std::pair<long long, long long> solve(long long current_a1, long long start_x) {
    // The actual a_values array for this run.
    // a[0] is current_a1, a[1] is A_values[0] (a_2), etc.
    // So a_k corresponds to A_values[k-2] for k >= 2.
    // And a_1 corresponds to current_a1.

    // If start_x is 1, we are at the beginning of a full simulation.
    // If start_x > 1, we are in a subproblem where a_1 is fixed.
    // The memoization key is based on the current x value.
    // We are interested in the state after the first step (x+a_x, y+a_x).
    // The problem states x=1, y=0. Then step 2, then step 3.
    // The state after step 2 is (1+a_1, a_1).
    // The state after step 3 is (1+a_1-a_1, a_1+a_1) = (1, 2*a_1).
    // This is not quite right. The problem says:
    // "The program increases both x and y by a value equal to a_x simultaneously." (Step 2)
    // "The program now increases y by a_x while decreasing x by a_x." (Step 3)
    // "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly"

    // Let's re-evaluate the state transitions.
    // Initial: x=1, y=0.
    // Loop:
    //   Check termination: if x <= 0 or x > N, break.
    //   Let val_ax = a_x.
    //   Step 2: x = x + val_ax, y = y + val_ax.
    //   Check termination: if x <= 0 or x > N, break.
    //   Step 3: y = y + val_ax, x = x - val_ax.

    // This means the value of a_x used in Step 3 is the *original* a_x from before Step 2.
    // Example: x=1, a_1=1.
    // Initial: x=1, y=0.
    // Loop 1:
    //   x=1 is valid.
    //   val_ax = a_1 = 1.
    //   Step 2: x = 1+1=2, y = 0+1=1.
    //   x=2 is valid.
    //   Step 3: y = 1+1=2, x = 2-1=1.
    // Current state: x=1, y=2.
    // Loop 2:
    //   x=1 is valid.
    //   val_ax = a_1 = 1.
    //   Step 2: x = 1+1=2, y = 2+1=3.
    //   x=2 is valid.
    //   Step 3: y = 3+1=4, x = 2-1=1.
    // Current state: x=1, y=4.
    // This implies that if x returns to 1, it will loop infinitely if a_1 is positive.
    // This is a crucial observation.

    // The problem statement implies that a_x is evaluated *once* per pair of steps (2 and 3).
    // Let's define a function `simulate_from_x(current_x, current_y_offset)`
    // This function will return the final y_offset and x.

    // The state for memoization should be just `current_x`.
    // The `current_y_offset` is accumulated.
    // The `current_a1` is fixed for each top-level call.

    // The `dp` table stores results for `x` values from 1 to N.
    // `dp[x][0]` = final x, `dp[x][1]` = final y_offset, `dp[x][2]` = status (0: uncomputed, 1: computed, 2: in_progress/cycle)

    // The `visited_states` array is used to detect cycles within the current path.
    // `visited_states[x]` stores the `current_a1` value for which this path is being explored.
    // If `visited_states[x] == current_a1`, it means we've encountered this state in the current path.

    // The `dp` table is indexed by `x-1` for `x` from 1 to N.
    // `dp[0]` corresponds to `x=1`.

    if (start_x <= 0 || start_x > N) {
        return {start_x, 0}; // Terminated, no additional y_offset
    }

    // Check memoization table
    if (dp[start_x - 1][2] == 1) { // Already computed
        return {dp[start_x - 1][0], dp[start_x - 1][1]};
    }
    if (dp[start_x - 1][2] == 2) { // Currently in progress, means cycle detected
        return {0, -1}; // Indicate infinite loop
    }

    // Mark as in progress
    dp[start_x - 1][2] = 2;

    long long val_ax;
    if (start_x == 1) {
        val_ax = current_a1;
    } else {
        val_ax = A_values[start_x - 2]; // a_2 is A_values[0], a_k is A_values[k-2]
    }

    // Simulate one full step (Step 2 then Step 3)
    long long next_x_after_step2 = start_x + val_ax;
    long long y_offset_after_step2 = val_ax; // y increases by val_ax

    // Check termination after Step 2
    if (next_x_after_step2 <= 0 || next_x_after_step2 > N) {
        dp[start_x - 1][0] = next_x_after_step2;
        dp[start_x - 1][1] = y_offset_after_step2;
        dp[start_x - 1][2] = 1;
        return {next_x_after_step2, y_offset_after_step2};
    }

    long long next_x_after_step3 = next_x_after_step2 - val_ax;
    long long y_offset_after_step3 = y_offset_after_step2 + val_ax; // y increases by another val_ax

    // Now recursively call for the next state
    std::pair<long long, long long> res = solve(current_a1, next_x_after_step3);

    if (res.second == -1) { // Infinite loop detected
        dp[start_x - 1][0] = 0;
        dp[start_x - 1][1] = -1;
        dp[start_x - 1][2] = 1; // Mark as computed (infinite loop result)
        return {0, -1};
    }

    // Combine results
    long long final_x = res.first;
    long long final_y_total_offset = y_offset_after_step3 + res.second;

    dp[start_x - 1][0] = final_x;
    dp[start_x - 1][1] = final_y_total_offset;
    dp[start_x - 1][2] = 1; // Mark as computed
    return {final_x, final_y_total_offset};
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    A_values.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> A_values[i];
    }

    // Initialize dp table. Size N for x values 1 to N.
    // dp[x-1] stores info for x.
    // dp[x-1][0]: final x
    // dp[x-1][1]: final y_offset
    // dp[x-1][2]: status (0: uncomputed, 1: computed, 2: in_progress/cycle)
    dp.resize(N, std::vector<long long>(3, 0));

    for (long long i = 1; i < N; ++i) { // i is the value for a_1
        // Reset dp table for each new a_1.
        // This is because the value of a_1 changes the entire sequence a.
        // So, memoization for a_x depends on a_1.
        // A more efficient approach would be to realize that for x > 1, a_x is fixed.
        // Only a_1 changes.
        // The state (x, y) is what matters.
        // If x > 1, then a_x is fixed. The path from x onwards is fixed.
        // So, we only need to recompute for x=1.
        // The problem is that the recursive calls `solve(current_a1, next_x_after_step3)`
        // depend on `current_a1` for `val_ax` if `next_x_after_step3 == 1`.
        // This means the `dp` table should be indexed by `(x, a_1)` or cleared.
        // Clearing for each `a_1` is simpler given N constraints.

        // Clear dp table for each new a_1
        for (int k = 0; k < N; ++k) {
            dp[k][0] = 0;
            dp[k][1] = 0;
            dp[k][2] = 0;
        }

        // Initial state for each run: x=1, y=0.
        // The first step is special: a_x is a_1.
        // Let's trace the first step explicitly to avoid issues with `solve`'s `start_x` parameter.
        // Initial: x=1, y=0.
        long long current_x = 1;
        long long current_y_offset = 0;

        long long val_a1 = i; // a_1 is set to i

        // Step 2:
        current_x += val_a1;
        current_y_offset += val_a1;

        // Check termination after Step 2
        if (current_x <= 0 || current_x > N) {
            std::cout << current_y_offset << "\n";
            continue; // Move to next i
        }

        // Step 3:
        current_y_offset += val_a1;
        current_x -= val_a1;

        // Now, current_x and current_y_offset are the state after the first (Step 2, Step 3) pair.
        // We can now call the recursive `solve` function.
        std::pair<long long, long long> result = solve(val_a1, current_x);

        if (result.second == -1) { // Infinite loop
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y_offset + result.second << "\n";
        }
    }

    return 0;
}

