// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (one cut)
    // A single cut divides the string into two pieces: s[0...i-1] and s[i...n-1].
    // These can be rearranged as s[i...n-1] + s[0...i-1].
    // We need to check if this new string is a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < n
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (two cuts)
    // Two cuts divide the string into three pieces: s[0...i-1], s[i...j-1], s[j...n-1].
    // The problem statement guarantees s is a palindrome.
    // If we can make a new palindrome with 2 cuts, it must be possible to do so.
    // Consider the structure of a palindrome. s[x] == s[n-1-x].
    // If all characters in s are the same (e.g., "aaaa"), then any rearrangement
    // will result in the same string "aaaa", which is a palindrome.
    // In this case, it's impossible to form a *different* palindrome.
    // We can check this by seeing if s is composed of only one distinct character.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and n > 1,
    // it's always possible to form a new palindrome with 2 cuts.
    // Example: s = "nolon" (n=5)
    // Cut at 2 and 3: "no" | "l" | "on"
    // Rearrange to "on" | "l" | "no" -> "onlno" (palindrome, != "nolon")
    // This strategy works for any palindrome s that is not composed of all identical characters.
    // The pieces are s[0...i-1], s[i...j-1], s[j...n-1].
    // If we take s[0...n/2-1], s[n/2], s[n/2+1...n-1] (for odd n)
    // or s[0...n/2-1], "", s[n/2...n-1] (for even n, middle piece empty)
    // The key is that if s is a palindrome and not all characters are the same,
    // then s.substr(0, n-1) is not a palindrome (unless n=1).
    // If n=1, s="a", then all_same_char is true, handled above.
    // If n > 1 and not all_same_char, then s.substr(0, n-1) is not a palindrome.
    // Consider s = "abacaba". s.substr(0,6) = "abacab". Not a palindrome.
    // Consider s = "otto". s.substr(0,3) = "ott". Not a palindrome.
    //
    // The problem states that if a solution with 2 cuts exists, we should output 2.
    // The logic here is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // This implies that `s` is not of the form `aaaaa...`.
    // In such a case, it's always possible to find a 2-cut solution.
    // For example, take `s = "abacaba"`.
    // Cut `s` into `s[0...n/2-1]`, `s[n/2]`, `s[n/2+1...n-1]`.
    // For `n=7`, `s[0...2]="aba"`, `s[3]="c"`, `s[4...6]="aba"`.
    // Rearrange to `s[4...6] + s[3] + s[0...2]` -> `"abacaba"`. This is `s`.
    // This specific rearrangement doesn't work.
    //
    // However, consider the string `s_prefix = s.substr(0, n-1)`.
    // If `s` is a palindrome and not all characters are the same, then `s_prefix` is NOT a palindrome.
    // (Unless `n=1`, which is handled by `all_same_char` check).
    // For example, `s = "abacaba"`, `s_prefix = "abacab"`. Not a palindrome.
    // For `s = "otto"`, `s_prefix = "ott"`. Not a palindrome.
    //
    // If `s_prefix` is not a palindrome, then we can make two cuts:
    // 1. Cut `s` into `s[0...n-2]` and `s[n-1]`.
    // 2. Cut `s[0...n-2]` into `s[0...i-1]` and `s[i...n-2]` for some `i`.
    // This is getting complicated.
    //
    // A simpler argument for k=2:
    // If `s` is a palindrome and not all characters are the same, then `s` must have at least two distinct characters.
    // Let `s = P + M + P_rev` where `P` is the first half, `M` is the middle character (if odd length), `P_rev` is the reverse of `P`.
    // Example: `s = "nolon"`. `P="no"`, `M="l"`, `P_rev="on"`.
    // Pieces: `no`, `l`, `on`. Rearrange to `on`, `l`, `no`. Result: `onlno`. This is a palindrome and `!= nolon`.
    // This is achieved by 2 cuts: `no|l|on`.
    // This strategy works for any palindrome `s` that is not `aaaa...`.
    // The cuts are at `n/2` and `n - n/2`.
    // For `s = "kinnikkinnik"` (n=12). `P="kinnik"`, `P_rev="kinnik"`.
    // `kinnik | kinnik`. This is 1 cut.
    // The example `kinnikkinnik` -> `1` is correct.
    //
    // The logic for `k=2` is: if `s` is a palindrome and not all characters are the same,
    // then it's always possible to find a 2-cut solution.
    // The only case where it's impossible is if all characters are the same.
    // We've already handled the `all_same_char` case.
    // So, if we reach this point, it means `k=1` didn't work, but `s` is not `aaaa...`.
    // Therefore, `k=2` must be the answer.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

// Function to check if all tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    int h_idx = 0; // Current index for heads

    while (p_idx < m) {
        if (h_idx >= n) {
            // No more heads available, but there are still tracks to cover
            return false;
        }

        // Find the first target track p[p_idx] that is not yet covered
        // by previous heads.
        // If p[p_idx] is already covered by h[h_idx-1]'s range,
        // we still need to use h[h_idx] for subsequent tracks.
        // The logic below implicitly handles this by advancing p_idx.

        // For the current head h[h_idx], what is the leftmost track it can reach?
        long long head_left_reach = h[h_idx] - T;

        // If the current target track p[p_idx] is to the left of what
        // the current head h[h_idx] can reach, then h[h_idx] cannot cover p[p_idx].
        // This implies that h[h_idx] is too far to the right to cover p[p_idx].
        // Since h is sorted, all subsequent heads h[h_idx+1], ... will also be too far right.
        // This scenario should not happen if we are trying to cover p[p_idx] with h[h_idx].
        // Instead, we should consider if h[h_idx] can cover p[p_idx].
        // If p[p_idx] is too far left for h[h_idx] to reach, then it must be covered by a previous head.
        // But we are processing p_idx sequentially, so p[p_idx] is the *first* uncovered track.
        // This means if h[h_idx] cannot reach p[p_idx], then no head can reach it.
        // This is incorrect. The head h[h_idx] might be able to cover p[p_idx] if p[p_idx] is within [h[h_idx]-T, h[h_idx]+T].

        // Let's re-think the greedy strategy:
        // We need to cover p[p_idx]. We must use some head h[k] for this.
        // Which head h[k] should we use?
        // The most efficient way is to use the leftmost available head h[h_idx]
        // that can cover p[p_idx].
        // If h[h_idx] is too far to the right to cover p[p_idx] (i.e., h[h_idx] - T > p[p_idx]),
        // then h[h_idx] cannot cover p[p_idx]. Since h is sorted, no subsequent head can either.
        // This means p[p_idx] cannot be covered.
        // This is the critical condition: if h[h_idx] is too far right for p[p_idx], it's impossible.
        if (h[h_idx] - T > p[p_idx]) {
            return false; // Current head is too far right to cover p[p_idx]
        }

        // If h[h_idx] can cover p[p_idx] (i.e., h[h_idx] + T >= p[p_idx]),
        // then this head can cover a range starting from max(p[p_idx], h[h_idx] - T)
        // up to h[h_idx] + T.
        // We want to maximize the rightmost reach for the current head.
        long long current_head_right_reach = h[h_idx] + T;

        // Now, advance p_idx as long as tracks are covered by the current head.
        while (p_idx < m && p[p_idx] <= current_head_right_reach) {
            p_idx++;
        }

        // Move to the next head for the remaining tracks.
        h_idx++;
    }

    // All tracks covered
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance between any h_i and p_j is 10^10.
    // So, max time could be 10^10.
    // A tighter upper bound: max(p_m - h_1, h_n - p_1) if n=1, m=1.
    // Or simply max(abs(h_i - p_j)) for all i,j.
    // Since h and p are sorted, max(p_m - h_1, h_n - p_1) is a good estimate.
    // A safe upper bound is 2 * 10^10.
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

