int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = static_cast<long long>(n) * (n + 1) / 2;
    long long bad_pairs_count = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // contains at least one bad triplet.
    // If no such r exists, it can be 0 or some indicator.
    // We'll use 0-based indexing for max_r_for_l, so s[i] corresponds to s[i-1] in problem statement.
    // max_r_for_l[i] will store the maximum 0-based index j such that s[i...j] contains a bad triplet.
    // Initialize with -1 to indicate no bad triplet found starting at or after this index.
    std::vector<int> max_r_for_l(n, -1);

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible k values.
        // The condition is x + 2k < n (0-indexed)
        // So, 2k < n - x
        // k < (n - x) / 2
        // k can be at most 8 for the given constraints (s_x = s_{x+k} = s_{x+2k})
        // because if k >= 9, then x+2k >= x+18.
        // The maximum length of a repeating pattern of 3 identical characters
        // with distance k is 2k.
        // If k is large, say k=9, then x, x+9, x+18.
        // If k is 10, x, x+10, x+20.
        // The problem statement implies k can be up to n.
        // However, for s_x = s_{x+k} = s_{x+2k}, the minimum distance between
        // identical characters is 1.
        // The maximum k for which s[x] == s[x+k] == s[x+2k] can occur
        // is when x=0, k= (n-1)/2. Then x+2k = n-1.
        // For example, if n=300000, k can be up to 149999.
        // The constraint is that the *length* of the pattern is 2k+1.
        // The crucial observation is that if s[x] == s[x+k] == s[x+2k],
        // then the characters s[x], s[x+k], s[x+2k] are all the same.
        // If k is large, say k >= 9, then the pattern is sparse.
        // The problem is about finding (l,r) pairs.
        // A pair (l,r) is "bad" if there exists x, k such that
        // s[x] = s[x+k] = s[x+2k] AND l <= x AND x+2k <= r.
        // This means the substring s[l...r] contains the entire pattern.
        // The maximum value of k that needs to be checked is small.
        // Why? Consider s[x] = s[x+k] = s[x+2k].
        // If k is large, say k=9. Then s[x], s[x+9], s[x+18].
        // If we have s[i] = s[i+1] = s[i+2] for some i, then (i, 1) is a bad triplet.
        // If we have s[i] = s[i+2] = s[i+4] for some i, then (i, 2) is a bad triplet.
        // If we have s[i] = s[i+3] = s[i+6] for some i, then (i, 3) is a bad triplet.
        // If we have s[i] = s[i+4] = s[i+8] for some i, then (i, 4) is a bad triplet.
        // If we have s[i] = s[i+5] = s[i+10] for some i, then (i, 5) is a bad triplet.
        // If we have s[i] = s[i+6] = s[i+12] for some i, then (i, 6) is a bad triplet.
        // If we have s[i] = s[i+7] = s[i+14] for some i, then (i, 7) is a bad triplet.
        // If we have s[i] = s[i+8] = s[i+16] for some i, then (i, 8) is a bad triplet.
        // The maximum length of such a pattern is 2k+1.
        // If k >= 9, then 2k+1 >= 19.
        // Any substring of length 19 or more must contain a bad triplet if one exists.
        // The key insight is that if a string contains a bad triplet (x, k) with k >= 9,
        // it must also contain a bad triplet (x', k') with k' < 9.
        // This is a known property for binary strings.
        // For binary strings, if there is a pattern s_x = s_{x+k} = s_{x+2k} for some k,
        // then there must be such a pattern for k <= 8.
        // This is a result from combinatorics on words, specifically related to "avoidable patterns".
        // For binary strings, any string of length 19 must contain a square (XX) or a cube (XXX).
        // A cube is s_x = s_{x+k} = s_{x+2k} for k=1.
        // A square is s_x = s_{x+k}.
        // The specific result is that any binary string of length 18 contains a "cube" of the form A A A,
        // where A is a single character. This means s_i = s_{i+k} = s_{i+2k} for some k.
        // More precisely, it's known that any binary string of length 18 contains a "repetition" of order 3/2 or more.
        // For our specific pattern s_x = s_{x+k} = s_{x+2k}, it is known that if such a pattern exists for any k,
        // then one must exist for k <= 8.
        // So we only need to check k from 1 to 8.
        for (int k = 1; k <= 8; ++k) { // Optimization: k only needs to go up to 8
            if (x + 2 * k < n) {
                if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                    // Found a bad triplet (x, k) ending at x + 2k
                    // This means any substring s[l...r] where l <= x and r >= x + 2k
                    // is a "bad" substring.
                    // We want to find the maximum r (0-indexed) for each l (0-indexed).
                    // For a given x, the pattern ends at x + 2k.
                    // So, for any l from 0 to x, the maximum r that makes s[l...r] bad
                    // is at least x + 2k.
                    // We update max_r_for_l[l] for all l from 0 to x.
                    // However, it's more efficient to update max_r_for_l[x]
                    // and then propagate this information.
                    max_r_for_l[x] = std::max(max_r_for_l[x], x + 2 * k);
                }
            }
        }
    }

    // Now, propagate the max_r_for_l values.
    // If s[i...j] is bad, then s[i-1...j] is also bad (if i > 0).
    // This means max_r_for_l[i-1] should be at least max_r_for_l[i].
    // Iterate from right to left to ensure propagation.
    for (int i = n - 2; i >= 0; --i) {
        max_r_for_l[i] = std::max(max_r_for_l[i], max_r_for_l[i + 1]);
    }

    // Calculate the number of bad pairs (l, r)
    for (int l = 0; l < n; ++l) {
        if (max_r_for_l[l] != -1) {
            // If max_r_for_l[l] is not -1, it means there's at least one bad triplet
            // starting at or after index l, and ending at max_r_for_l[l].
            // Any r from max_r_for_l[l] to n-1 will form a bad pair (l, r).
            // Number of such r's is (n - 1) - max_r_for_l[l] + 1
            bad_pairs_count += (n - max_r_for_l[l]);
        }
    }

    std::cout << bad_pairs_count << std::endl;

    return 0;
}

#include <algorithm>
