struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s)
    // In this case, all f(a_i, a_j) = a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness_all_same = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    long long min_goodness = goodness_all_same;
    std::vector<int> best_partition(n, 1); // Default to all 1s

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is a_{n-1} + a_n + h.
    // This occurs if a_1 and a_2 are in the same group, and a_{n-1} and a_n are in different groups.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in the same group.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in different groups.
    // Or if a_1 and a_2 are in the same group, and a_{n-1} and a_n are in the same group.

    // Consider the partition where elements[0] is in S1 and elements[1] is in S2.
    // And elements[n-1] is in S2 and elements[n-2] is in S1.
    // This is a specific partition strategy.
    // The smallest sum is a_1 + a_2.
    // The largest sum is a_{n-1} + a_n.
    // The smallest f value could be a_1 + a_2 (if a_1, a_2 same group) or a_1 + a_2 + h (if a_1, a_2 different groups).
    // The largest f value could be a_{n-1} + a_n (if a_{n-1}, a_n same group) or a_{n-1} + a_n + h (if a_{n-1}, a_n different groups).

    // Let's analyze the critical values:
    // min_val_same = a_1 + a_2
    // max_val_same = a_{n-1} + a_n
    // min_val_diff = a_1 + a_2 + h
    // max_val_diff = a_{n-1} + a_n + h

    // The overall minimum f value will be at least a_1 + a_2.
    // The overall maximum f value will be at most a_{n-1} + a_n + h.

    // Consider a partition where elements[0] is in group 1, and all other elements are in group 2.
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    // f values:
    //   - elements[0] with elements[j] (j > 0): elements[0].value + elements[j].value + h
    //   - elements[i] with elements[j] (i, j > 0): elements[i].value + elements[j].value
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[n-1].value + elements[n-2].value
    // This is only valid if elements[0].value + elements[1].value + h <= elements[n-1].value + elements[n-2].value.
    // If not, then max_f is elements[n-1].value + elements[n-2].value, and min_f is elements[0].value + elements[1].value + h.
    // The range would be (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h).
    // This is not right. The min_f is min(all f values), max_f is max(all f values).

    // Let's consider the partition where elements[0] is in group 1, and all other elements are in group 2.
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    // The values of f are:
    //   - elements[0].value + elements[j].value + h for j = 1, ..., n-1
    //   - elements[i].value + elements[j].value for i, j = 1, ..., n-1, i != j
    // min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    // This is a specific partition.

    // The key insight is that the minimum possible value of f is always a_1 + a_2.
    // The maximum possible value of f is always a_{n-1} + a_n + h.
    // The goodness is (a_{n-1} + a_n + h) - (a_1 + a_2).
    // This is the goodness if a_1 and a_2 are in the same group, and a_{n-1} and a_n are in different groups.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in the same group.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in different groups.

    // Let's consider two main partition strategies:
    // Strategy A: All elements in one group (already covered by goodness_all_same).
    // Strategy B: elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    //   min_f = elements[0].value + elements[1].value + h
    //   max_f = elements[n-1].value + elements[n-2].value
    //   If elements[0].value + elements[1].value + h > elements[n-1].value + elements[n-2].value,
    //     then the minimum f value is elements[n-1].value + elements[n-2].value.
    //     This means all f values are of the form X + Y + h.
    //     No, this is wrong. If elements[0].value + elements[1].value + h is the smallest possible f value,
    //     and elements[n-1].value + elements[n-2].value is the largest possible f value,
    //     then the goodness is (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h).
    //     This is only if elements[0].value + elements[1].value + h <= elements[n-1].value + elements[n-2].value.
    //     Otherwise, all f values are of the form X+Y+h, or all f values are of the form X+Y.
    //     This is getting complicated.

    // Let's simplify.
    // The minimum possible sum of two elements is `elements[0].value + elements[1].value`.
    // The maximum possible sum of two elements is `elements[n-1].value + elements[n-2].value`.

    // Option 1: All elements in the same group.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)

    // Option 2: Partition such that elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    // This means elements[0] is always different from any other element.
    // All pairs (elements[0], elements[j]) for j > 0 will have f = elements[0].value + elements[j].value + h.
    // All pairs (elements[i], elements[j]) for i,j > 0 will have f = elements[i].value + elements[j].value.
    // The minimum f value will be min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value).
    // The maximum f value will be max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value).
    // Let's call this partition P1.
    // min_f_P1 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    // max_f_P1 = std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value);
    // goodness_P1 = max_f_P1 - min_f_P1;

    // If elements[0].value + elements[1].value + h <= elements[n-1].value + elements[n-2].value:
    //   min_f_P1 = elements[0].value + elements[1].value + h
    //   max_f_P1 = elements[n-1].value + elements[n-2].value
    //   goodness_P1 = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h)
    // Else (elements[0].value + elements[1].value + h > elements[n-1].value + elements[n-2].value):
    //   This means all f values of type X+Y+h are greater than all f values of type X+Y.
    //   So, min_f_P1 = elements[1].value + elements[2].value
    //   max_f_P1 = elements[0].value + elements[n-1].value + h
    //   goodness_P1 = (elements[0].value + elements[n-1].value + h) - (elements[1].value + elements[2].value)

    // This is the crucial part.
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-1].value + elements[n-2].value + h`.
    // The goodness is `(elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value)`.
    // This is the goodness if we can achieve both `elements[0].value + elements[1].value` (by putting them in the same group)
    // AND `elements[n-1].value + elements[n-2].value + h` (by putting them in different groups).
    // This is possible if we put elements[0] and elements[1] in group 1, and elements[n-1] in group 2, elements[n-2] in group 1.
    // This is a general upper bound on goodness.

    // Let's consider the two main candidates for optimal partition:
    // 1. All elements in the same group (e.g., all 1s).
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //    This is `goodness_all_same`.

    // 2. Partition where elements[0] is in group 1, and all other elements are in group 2.
    //    S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    //    Pairs within S1: None (if n > 1)
    //    Pairs within S2: (elements[i], elements[j]) for i,j in [1, n-1]
    //    Pairs across S1, S2: (elements[0], elements[j]) for j in [1, n-1]
    //    min_f_in_S2 = elements[1].value + elements[2].value (if n >= 3)
    //    max_f_in_S2 = elements[n-1].value + elements[n-2].value (if n >= 3)
    //    min_f_across = elements[0].value + elements[1].value + h
    //    max_f_across = elements[0].value + elements[n-1].value + h

    //    If n=2: S1={elements[0]}, S2={elements[1]}. Only one pair (elements[0], elements[1]).
    //    f = elements[0].value + elements[1].value + h. min_f = max_f = f. Goodness = 0.
    //    This is handled by the general logic.
    //    If n=2, goodness_all_same = (elements[1].value + elements[0].value) - (elements[0].value + elements[1].value) = 0.
    //    So for n=2, goodness is always 0.

    //    For n >= 3:
    //    min_f_candidate_2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    //    max_f_candidate_2 = std::max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value);
    //    goodness_candidate_2 = max_f_candidate_2 - min_f_candidate_2;

    //    Let's re-evaluate the second strategy.
    //    Partition: elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    //    The values of f are:
    //    - `elements[0].value + elements[j].value + h` for `j = 1, ..., n-1`
    //    - `elements[i].value + elements[j].value` for `i, j = 1, ..., n-1`, `i != j` (only if n >= 3)
    //    The minimum of these values is `min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)` (if n >= 3).
    //    The maximum of these values is `max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)` (if n >= 3).

    //    If n=2, elements[0] in group 1, elements[1] in group 2.
    //    Only one pair: (elements[0], elements[1]). f = elements[0].value + elements[1].value + h.
    //    min_f = max_f = f. Goodness = 0.
    //    This is consistent with goodness_all_same.

    //    For n >= 3:
    long long current_min_f_val;
    long long current_max_f_val;

    // Partition 1: All elements in group 1.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = max_f - min_f
    // This is `goodness_all_same`.

    // Partition 2: elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    // goodness = max_f - min_f
    // This is `goodness_candidate_2`.

    // Let's consider the values:
    // A = elements[0].value
    // B = elements[1].value
    // C = elements[2].value
    // X = elements[n-2].value
    // Y = elements[n-1].value

    // Case 1: All in one group.
    // min_f = A + B
    // max_f = X + Y
    // goodness = (X + Y) - (A + B)

    // Case 2: elements[0] in group 1, others in group 2. (n >= 3)
    // Values of f:
    //   - A + B + h
    //   - A + C + h
    //   ...
    //   - A + Y + h
    //   - B + C
    //   ...
    //   - X + Y
    // min_f = min(A + B + h, B + C)
    // max_f = max(A + Y + h, X + Y)
    // goodness = max_f - min_f

    // The problem states that one of the subsequences can be empty.
    // If one subsequence is empty, it's the "all in one group" case.

    // The optimal partition must involve either:
    // 1. All elements in one group.
    // 2. The smallest element `a_1` is separated from the rest.
    // 3. The largest element `a_n` is separated from the rest.
    // 4. The smallest two elements `a_1, a_2` are separated from the rest.
    // 5. The largest two elements `a_{n-1}, a_n` are separated from the rest.

    // Let's consider the two main candidates for the minimum goodness:
    // Candidate 1: All elements in the same group.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-1].value + elements[n-2].value
    //   goodness_1 = max_f - min_f
    //   Partition: all 1s.

    // Candidate 2: elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    //   min_f_val = elements[0].value + elements[1].value + h
    //   max_f_val = elements[n-1].value + elements[n-2].value
    //   If min_f_val > max_f_val, it means all pairs (a_i, a_j) where a_i is in S1 and a_j is in S2
    //   produce values greater than all pairs (a_i, a_j) where both are in S2.
    //   In this case, the minimum f is `elements[1].value + elements[2].value` (from S2)
    //   and the maximum f is `elements[0].value + elements[n-1].value + h` (from S1-S2).
    //   goodness_2 = (elements[0].value + elements[n-1].value + h) - (elements[1].value + elements[2].value)
    //   This is the case where `h` is large enough to push all `a_i+a_j+h` values above all `a_i+a_j` values.

    //   If min_f_val <= max_f_val, it means the smallest `a_i+a_j+h` value is less than or equal to the largest `a_i+a_j` value.
    //   In this case, the minimum f is `elements[0].value + elements[1].value + h` (from S1-S2)
    //   and the maximum f is `elements[n-1].value + elements[n-2].value` (from S2).
    //   goodness_2 = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h)

    // Let's use the values from the sorted array directly.
    long long a1 = elements[0].value;
    long long a2 = elements[1].value;
    long long an_1 = elements[n - 2].value;
    long long an = elements[n - 1].value;

    // Option 1: All elements in one group.
    // min_f = a1 + a2
    // max_f = an_1 + an
    // goodness = (an_1 + an) - (a1 + a2)
    long long current_goodness = (an_1 + an) - (a1 + a2);
    std::vector<int> current_partition(n, 1);

    // Option 2: elements[0] in group 1, others in group 2. (Only relevant if n >= 3)
    if (n >= 3) {
        long long min_f_val_P2;
        long long max_f_val_P2;

        // Smallest sum from S1-S2: a1 + a2 + h
        // Smallest sum from S2-S2: a2 + elements[2].value (which is a3)
        // So, min_f_val_P2 = std::min(a1 + a2 + h, a2 + elements[2].value);
        // Largest sum from S1-S2: a1 + an + h
        // Largest sum from S2-S2: an_1 + an
        // So, max_f_val_P2 = std::max(a1 + an + h, an_1 + an);

        // The problem is that elements[2].value is not necessarily a3. It's elements[2].value.
        // Let's use the sorted values directly.
        long long min_f_across_P2 = elements[0].value + elements[1].value + h;
        long long max_f_across_P2 = elements[0].value + elements[n-1].value + h;
        long long min_f_within_S2_P2 = elements[1].value + elements[2].value;
        long long max_f_within_S2_P2 = elements[n-1].value + elements[n-2].value;

        min_f_val_P2 = std::min(min_f_across_P2, min_f_within_S2_P2);
        max_f_val_P2 = std::max(max_f_across_P2, max_f_within_S2_P2);

        long long goodness_P2 = max_f_val_P2 - min_f_val_P2;

        if (goodness_P2 < current_goodness) {
            current_goodness = goodness_P2;
            current_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                current_partition[elements[i].original_index] = 2;
            }
        }
    }

    // The case where n=2 is special.
    // If n=2, elements[0] and elements[1].
    // Option 1: Both in group 1. f = elements[0].value + elements[1].value. min_f = max_f = f. Goodness = 0.
    // Option 2: elements[0] in group 1, elements[1] in group 2. f = elements[0].value + elements[1].value + h. min_f = max_f = f. Goodness = 0.
    // So for n=2, goodness is always 0. The initial `goodness_all_same` correctly calculates 0.
    // The `if (n >= 3)` condition correctly skips the second option for n=2.

    std::cout << current_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << current_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::abs

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            counts[j][i + 1] = counts[j][i];
        }
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Adjust to 0-based indexing for prefix sums
        // Substring is s[l-1 ... r-1]
        // Counts for this substring:
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The condition for termination is that the counts of 'x', 'y', 'z'
        // in any 3-character window are "balanced" enough.
        // Specifically, the difference between the max and min count among x, y, z
        // must be at most 1.
        // This is equivalent to checking if |count_x - count_y| <= 1,
        // |count_y - count_z| <= 1, and |count_x - count_z| <= 1.
        // Or, more simply, max(count_x, count_y, count_z) - min(count_x, count_y, count_z) <= 1.

        int max_count = std::max({count_x, count_y, count_z});
        int min_count = std::min({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}
